INSERT INTO `dc_report` VALUES (12855, 69, 1, 37, 52, 'เลี้ยงสัตว์ในบ้านพัก', '2025-12-30', '09:01:00', '2025-12-30', '09:00:10', 'Non_Clinic', 'เกิดขึ้นที่บ้านพักครอบครัวข้างๆสสง.สาธารณสุขอำเภอ\r\nมีจนท.เลี้ยงแมวหลายตัวมาก เลี้ยงแบบปล่อย ไม่ดูแล  \r\nรอบๆบ้านข้าพเจ้ามีแต่ขี้แมวเต็มไปหมด ทำให้ทุกวันนี้ข้าพเจ้าและครอบครัว และบ้านพักอื่นๆ ลำบากในการอยู่อาศัยในแต่ละวัน ส่งกลิ่นเหม็นไปทั่ว บางบ้านมีผลกระทบในเรื่องทรัพย์สิน (หลังคาบ้านเสีย เกิดจากแมวตีกัน จนกระเบื้องแตก ) จึงขอความช่วยเหลือกับทางกรรมการบ้านพักในการจัดการเหตุการเหล่านี้ให้เร็วที่สุด ', 'มีจนท.แจ้งให้ทราบกับเจ้าของสัตว์เลี้ยงแล้ว แต่ไม่ได้ดำเนินการใดๆ', '2', '12-2025', 'P', 1, 0, 0, 0, 1, NULL, 'ENV', NULL, 32, 1, NULL, NULL, NULL, '2', '2026-01-02', NULL, NULL, 'Y', NULL, '1900500042896', 'admin1', NULL, NULL, NULL, '17926-', 'N');
