INSERT INTO `dc_report` VALUES (12863, 69, 2, 6, 48, 'ใบพัดของพัดลมเพดาน', '2026-01-04', '12:14:00', '2026-01-04', '17:12:30', 'Non_Clinic', '4/1/69 เวลา 12.14 น ตำแหน่งระหว่าง เตียง 2 กับ เตียง 1 หอผู้ป่วยใน 1 มีพัดลมติดเพดาน  ใบพัดลมแตก ปลิวลงมาตกกลางเตียง 2 (เตียง 2 เด็กชายอายุ 10เดือน HN 180514 DX Pneumonia  CHF c PDA F/U  HYH  on o2caluna 2 LPM)ขณะนั้นมีผู้ป่วยกับแม่ นอนอยู่บนเตียง  แม่กระโจนขว้าบุตรไว้ทัน หลบทัน  ไม่มีใครได้รับความเสียหายทางร่างกาย  แต่ตกใจเล็กน้อยไม่ได้โวยวาย ไม่ได้จะฟ้องร้่อง  และพ่อวิ่งไปปิดพัดลม พยาบาลรีบวิ่งไปดูอาการ check ใบพัดไม่ได้กระแทกกับสิง่ใด ดูเสื่อมสภาพ\r\n', 'ประเมินอาการเด็กและมารดา ทั้งร่างกายและจิดใจ  \r\nพูดปลอบใจ ให้ความมั่นใจ ว่าไม่ตกใส่อีก\r\nปิดพัดลม แจ้งบุคคลากรและญาติผู้ป่วยทุกคน งดใช้พัดลมตัวนี้\r\nแจ้งซ่อมและเปลียนพัดลมเป็นตั้งโต๊ะ\r\nแจังหัวหน้างาน\r\nเขียน IR \r\n', '3', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'ENV', NULL, 33, 1, NULL, NULL, NULL, '2', '2026-01-15', NULL, NULL, 'Y', NULL, '1900500021082', 'admin1', NULL, NULL, NULL, '72272-', 'IPD');
INSERT INTO `dc_report` VALUES (12864, 69, 2, 7, 7, 'เสียชีวิตอย่างสงบ (NR)', '2025-12-22', '12:20:00', '2026-01-06', '18:23:41', 'Clinic-Dx', 'ผู้ป่วยเพศหญิง อายุ 75 ปี (HN 61733) U/D DM, Chondrosarcoma of pelvis  . Admit at 8/12/68  > Dx. Infected Bedsore  at cocyx (Debridement bedsore 9/12/68) c UTI ขณะ admit มีอาการไข้ หายใจเหนื่อย > ญาติ NR ขอรักษาแบบประคอง  on HFNc ตั้งแต่วันที่ 18/12/68.  at 22/12/68 12.05น. มีหายใจเหนื่อยมากขึ้น เริ่มมี Air hunger RR= 16-22/min  มี Chest retraction Osat 70-75%  BP 89/54 mmHg  PR 76/min. at 12.20น. คลำชีพจรไม่ได้ วัดBPไม่ได้ EKG >Asystole \r\n', 'notify แพทย์เวร \r\nให้ข้อมูลญาติ > Accept\r\nCare Dead\r\n', 'I', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 62, 5, NULL, NULL, NULL, 'I', '2026-01-15', NULL, NULL, 'Y', NULL, '1940500129860', 'admin1', NULL, NULL, NULL, '93799-', 'IPD');
INSERT INTO `dc_report` VALUES (12865, 69, 2, 7, 7, 'ผู้ป่วยเสียชีวิตอย่างสงบ(NR)', '2025-11-24', '12:26:00', '2026-01-07', '08:12:04', 'Clinic-Dx', 'ผู้ป่วยเพศหญิง อายุ71ปี HN. 17544 ผู้ป่วย admit วันที่ 21/11/2568 case trumor necrosis\r\nผู้ป่วย NR. รักษาแบบประคับประคอง เวลา 11.00น. ผู้ป่วยเริ่มมีอาการหายใจเหนื่อย RR 30 bpm. มี chest retraction o2sat 89%  on o2 mask with bag 15 lpm เวลา 12.00น.0 เริ่มมีอาการหายใจเฮือก Air hunger O2 sat 50% on o2 mask with bag 15 lpm เวลา 12.26น.ผู้ป่วยไม่รู้สึกตัว ปลุกไม่ตื่น คลำชีพจรไม่ได้ ผู้ป่วยเสียชีวิตอย่างสงบเวลา 12.26น.', 'รายงานแพทย์เวรรับทราบ\r\nให้ข้อมูลญาติ ญาติ Accept\r\nCare dead', '0', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 63, 5, NULL, NULL, NULL, 'I', '2026-01-15', NULL, NULL, 'Y', NULL, '1960600168085', 'admin1', NULL, NULL, NULL, '45380-', 'IPD');
INSERT INTO `dc_report` VALUES (12866, 69, 2, 37, 51, 'ส่งยาไปรษณีย์ผิดคน', '2026-01-02', '09:48:00', '2026-01-07', '09:23:34', 'Clinic', 'จัดส่งยาไปรษณีย์ชื่อหน้ากล่องกับชื่อหน้าซองยาข้างในกล่อง ชื่อไม่ตรงกัน หน้ากล่อง ชื่อ ฮาบีเบ๊าะ ย๊ะ ยาข้างในเป็นของ ดวงเพ็ญ อินน้ำหอม  HN 154167 \r\n วันที่ 2/1/69 ฮาบีเบ๊าะ ย๊ะ ได้นำยากลับมาที่ห้องยา แจ้งว่า ได้รับยาไม่ตรงกับชื่อของตัวเอง', 'เบื้องต้นเมื่อรับทราบถึงอุบัติการณ์ ได้โทรประสานแจ้งกลับไปยังคุณ ดวงเพ็ญ อินน้ำหอมแล้ว ว่ายาสลับกับของ คุณฮาบีเบ๊าะ ย๊ะ\r\nการแก้ไขเพื่อไม่ให้เกิดอุบัติการณ์ซ้ำ\r\n -ก่อนจะแพ็คยาลงกล่องพัสดุ ให้ทำการ ตรวจเช็คซ้ำว่า ใบปะหน้า กับ ยาชื่อตรงกันไหม\r\n -ให้ทำการแพ็คยาลงกล่อง ให้เสร็จเป็นคนๆ ไป เพื่อป้องกัน ไม่ให้ ยาสลับกันอีก\r\n- ระมัดระวัง ตอนจับคู่ใบปะหน้า กับยาว่าตรงกันไหม ', 'C', '01-2026', 'P', 1, 1, 0, 0, 1, 'U4', 'PTC', 'U4', 71, 6, 46, 176, 335, 'C', '2026-01-15', '2026-01-21', '', 'Y', 'PTC', '1900300115750', 'PTC', '', '', 'open', '41789-', 'OPD');
