INSERT INTO `dc_report` VALUES (12871, 69, 2, 6, 3, 'ย้ายผู้ป่วยไม่ปลอดภัย ', '2026-01-09', '16:00:00', '2026-01-09', '15:56:09', 'Clinic', 'วันที่ 9/1/2569  เวลา  15.50 น.รับย้ายผู้ป่วยจาก ER ผู้ป่วยเด็กผู้หญิง อายุ  1 ปี 5 เดือน HN:000177028 AN:69000123 Dx.Pneumonia with RLL Aytelectasis มาด้วยหายใจเหนื่อย ระยะเวลา 5  ชม.ก่อนมารพ. ย้าย IPD 1 ผู้ป่วยหายใจเหนื่อยเยอะ หายใจมี Subcostal retraction  RR=62/min PR =170/min BT=37.2 C On O2 mask 10 LPM =97%  พยาบาล IPD1 รายงานแพทย์ER ทราบ ', '1.รายงานแพทย์เวร ER ทราบ \r\n2.ให้ loading IVF 0.9 ml 90 ml \r\n3. ให้ On HFNC 12 LPM ,FiO2 40 \r\n4.ให้พ่นยา Ventolin 1.2 ml +3%Nacl up to 4 ml *2 ml ทุก 1 ชั่วโมง*dose then ventolin 1.2 ml+nss up to 4 ml ทุก 4 hr. ', 'D', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 66, 5, NULL, NULL, NULL, 'D', '2026-01-15', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '72457-', 'IPD');
