INSERT INTO `dc_report` VALUES (12873, 69, 2, 37, 51, 'ยา pt หายจากการส่งยาทางไปรษณีย์', '2026-01-07', '10:00:00', '2026-01-09', '23:01:16', 'Clinic', 'pt HN 94320  จัดยาส่งทางไปรษณีย์ เช็ครหัสส่งไปรษณีย์ระบุยายาส่งถึง pt เเล้ว pt ยืนยันว่ายาที่ส่งไม่ได้รับ เเละไม่มีการเซ็นรับของ ไปรษณีย์มีรูปถ่ายวางยาไว้บนโต๊ะบริเวณบ้าน \r\nสรุปให้ตามยาเเถวบ้านญาติใกล้เคียงก็ไม่เจอ  ยาที่ส่งให้ pt ได้หายไป มูลค่า 458 บาท ', 'จัดยาใหม่ให้ pt ถึงวันนัด เเจ้งว่ารอบหน้าหากเเพทย์นัดเข้าสู่คลินิกเติมยาให้มารับยาที่ รพ เเทนเพื่อป้องการสูญหาย', 'C', '01-2026', 'P', 1, 1, 0, 0, 1, 'U4', 'PTC', 'U4', 75, 6, 114, 1095, 804, 'C', '2026-01-15', '2026-01-21', '', 'Y', 'PTC', '1909800480374', 'PTC', '', '', 'open', '98961-', 'OPD');
INSERT INTO `dc_report` VALUES (12874, 69, 1, 37, 38, 'ลงวันนัดผิดพลาด', '2026-01-07', '00:00:00', '2026-01-09', '23:09:13', 'Clinic', 'pt HN 161251 เเพทย์นัดเข้าสู่คลินิกเติมยาวันที่ 8 เมษายน 68 เเละนัด pt วันที่ 8 เมษายน 68 เป็นวันเดียวกัน \r\n', 'เเจ้งเเพทย์เเก้ไข สรุปไม่เข้าสู่คลินิกเติมยานัดวันเดียว 8 เมษา 68 ', 'B', '01-2026', 'P', 1, 1, 0, 0, 1, 'U5', 'PTC', 'U5', 76, 6, 114, 615, 598, 'B', '2026-01-15', '2026-01-16', '', 'Y', 'PTC', '1909800480374', 'PTC', '', '', 'open', '90120-', 'OPD');
