INSERT INTO `dc_report` VALUES (12876, 69, 2, 3, 11, 'ขับรถมอเตอร์ไซคฺ์ชนที่กั้นทาง ', '2026-01-11', '09:07:00', '2026-01-11', '09:06:07', 'Non_Clinic', '-  เวลา 08.50 น \r\nเจ้าหน้าฝึกงาน  ขับ MC เข้ามาฝึกงาน  \r\nใส่หมวกกันน้อค  ชนที่กั้นทางเข้าบ้านพัก  \r\n มีถลอกบวมโน ( โดยระบุว่ามองไม่เห็น ) ', '-แจ้งรายงานอุบัติการณ์\r\n-แจ้งยาม \r\n- รับการรักษาที่ห้องอุบัติเหตุฉุกเฉิน ', '3', '01-2026', 'P', 1, 1, 0, 0, 1, 'U1', 'ENV', 'U1', 34, 1, 3, 910, 0, '3', '2026-01-15', '2026-02-24', '', 'Y', 'env', '1909900124090', 'env', '', '', '', '54254-', 'OPD');
INSERT INTO `dc_report` VALUES (12877, 69, 2, 6, 44, 'ญาติไม่พอใจเรื่องไม่ได้เข้าห้องพิเศษ', '2026-01-10', '02:00:00', '2026-01-11', '20:38:34', 'Non_Clinic', 'ชายไทย อายุ24 ปี HN 5397 Dx Malaise and fatique \r\nvisit วันที่ 9/1/69 เวลา 19.34 น \r\nมาด้วย10 วัน PTA  กินไม่ได้ ไม่ค่อยมีแรง  ไม่ไข้  ไม่ไอ ไม่มีน้ำมูก  ไม่เหนื่อย  5 วัน กินข้าวไม่ได้เลย กินแค่วันละ 1 มื้อ   2-3 วัน  มีถ่ายเหลววันละ 2-3 ครั้ง ไม่มีอาเจียน ไม่ปวดท้อง ถ่ายอุจจาระสีเหลือง ไม่มีอาเจียนเป็นเลือด น้ำหนักลดลงไม่ทราบกี่กิโล\r\nPE : BP 107/70 mmHg\r\nHEENT: not pale, no jaundice \r\nHeart  :  normal S1S2 no murmur\r\nLung : normal breath sound equal lung\r\nAbd : Soft , not tender , no guarding \r\nExt : no pitting edema \r\nCBC WBC 4550 Hct 26 no baseline Plt 147000\r\nB24 positive\r\nlactate 1.5 electrolyte normal\r\nIMP anemia with 1st Diag B24\r\nPlan \r\n- admit supportive tx\r\nญาติต้องการห้องพิเศษ และได้แจ้งตั้งแต่ห้องฉุกเฉิน  แต่ห้องฉุุกเฉินไม่ได้ขอห้อง พิเศษ  ให้ผู้ป่วย จึงย้ายมา ward 1 เตียง  ส 4 \r\nadmit  ถุึง  ward1  10/1/69 เวลา 1.00 น  ผู้ป่วยย้ายลงเตียง  มีญาติมาด้วย 3 คน  สีหน้าไม่พอใจ แจ้งขอห้องพิเศษกับ ward1อีกครั้ง\r\nเวลา 1.30 น จึงโทรประสาน ward 2 อีกครั้ง สรุปมีเตียงว่าง   แต่อ้างว่าเป็นยามวิกาล จะปฏิเสธรับผู้ป่วย เลยต่อรองว่าไม่มีในแนวทาง ว่าไม่รับใหม่คนไข้ยามวิกาล  และได้ให้เหตุผลว่า \r\nญาติมีความตัองการห้องพิเศษ มาก ๆ   ward 2 จึงรับคนไข้ไว้ และได้ย้ายคนไข้ไปWard 2 เวลา 2.00 น ทำเอกสารรับใหม่เรียบร้อย มีพยาบาลนำส่ง\r\n ญาติจึงพอใจ', '\r\n-ประสาน ward2 แสดงความประสงค์ อีกครั้ง ชี้แจงความจำเป็น\r\n-แสดงท่าทีเป็นมิตรกับญาติ\r\n***ข้อเสนอแนะ\r\n-เจ้าหน้าที่ด้านหน้าควรใส่ใจ คำพูดญาติ ความประส่งค์ ญาติ สีหน้า ท่าทางญาติ มากกว่านี้ \r\n-เคส ที่ admit  ห้องพิเศษได้ เช้น สิทธิเบิกได้ อสม หรือ อื่น ๆ และ ที่แพทย์อนุญาต ควรได้รับการสอบถาม  ตั้งแต่ด้านหน้า \r\nและประสานงานให้เรียบร้อย \r\n-ห้องพิเศษ ถ้าว่าง หาก มีเคสที่จองไว้   ward 2 ต้องเคลียร์ และรันคิว ทันที  ที่ว่าง ก่อน 21.00 น\r\n', '2', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 67, 5, NULL, NULL, NULL, '2', '2026-01-15', NULL, NULL, 'Y', NULL, '1900500021082', 'admin1', NULL, NULL, NULL, '38361-', 'IPD');
INSERT INTO `dc_report` VALUES (12878, 69, 1, 7, 3, 'ON IV ผู้ป่วยมียา ATB ไม่ต่อ Treeway แล้วเสียบในสาย IV ', '2026-01-11', '21:30:00', '2026-01-11', '22:57:25', 'Non_Clinic', 'รับเคสจาก ER at 21.30 น ผู้ป่วยชาย case AGE  มี on IV + มี ATB แต่ไม่ต่อ Treeway ให้  ให้ยา ATB ต่อกับสาย IV  ', '*** หลายเคสแล้วค่ะ ประสาน ER แล้ว บอกว่า รับทราบ', '1', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 68, 5, NULL, NULL, NULL, 'C', '2026-01-15', NULL, NULL, 'Y', NULL, '1960300122373', 'admin1', NULL, NULL, NULL, '30176-1111111.jpg', 'IPD');
INSERT INTO `dc_report` VALUES (12879, 69, 1, 51, 36, 'พฤติกรรมบริการ', '2026-01-08', '16:35:00', '2026-01-12', '08:33:23', 'Non_Clinic', '8 มค69 13.30น ลูกสาวรับบริการห้องฟันแจ้งว่า จนท ให้ชั่งน้ำหนัก จึงไปชั่ง และเดินมาที่เคาน์เตอร์เพื่อแจ้งนน แต่เจ้าหน้าที่ มองด้วยสายตา จิก ค้อนแล้วไม่ทันได้บอก นน ก็พูดห้วนๆใส่ว่าไปวัดความดันด้วย ลูกสาวก็ไปทำตาม แล้วกลับมาเล่า ว่า จนท หน้าเคาน์เตอร์ พูดห้วน มองสายตาที่ลูกเหมือนจิก พูดห้วนมาก สายตา คำพูด ไม่เหมาะอยู่หน้าเคาน์เตอร์ \r\nส่วนอีกวัน 9มค68ดิฉันในฐานะเป็นแม่และเป็นจนท รพ เข้าไปสอบถาม  จนท อีกคน เพื่อสอบถามเรื่องการรักษาครั้งต่อไปของลูก ที่ต้องชำระเงิน และสอบถามเรื่องการจ่ายเงิน ต้องบอกว่าถามหลายครั้งมาก ซึ่งจนท ที่เราสอบถาม ก็พยายามอธิบาย ในขณะเดียวกัน จนท ทีมีประเด็นพูดห้วยใส่ลูก นั่งข้างๆ ทุกคำถามของเรา นางจะหันมามองและใช้สายตาจิก เหมือนคิดว่า ไม่รู้เรื่อง และทุกครั้งที่ถาม นางจะหันมามองด้วยสายตาแบบนั้นทุกครั้ง ซึ่งมองว่า คนจะอยู่่หน้าเคาน์เตอร์ ควรมี service mind ทัศนคติที่ดี ทั้ง กายจิตวาจา ที่ีแสดงออกมา ซึ่งบอกเลยไม่โอเค ปล เจอ อยากให้ปรับปรุง โดยเฉพาะจุดบริการ ระดับ premium ', 'ไมได้ได้แก่ไข้ คะ เดินกลับ\r\nโมโหอย่างเดียว', '1', '01-2026', 'P', 1, 0, 0, 0, 4, NULL, 'HUM', NULL, 5, 4, NULL, NULL, NULL, '1', '2026-01-15', NULL, NULL, 'Y', NULL, '3909700025621', 'admin1', NULL, NULL, NULL, '33147-', 'OPD');
INSERT INTO `dc_report` VALUES (12880, 69, 2, 1, 7, 'ปฏิเสธรับ case เข้าห้องพิเศษ', '2026-01-11', '20:00:00', '2026-01-12', '17:19:51', 'Non_Clinic', '11/1/69 เวลา 20.00 น.  \r\nผู้ป่วยชาย อายุ 61 ปี  HN 91711 \r\ncase AGE admit แพทย์ให้เข้าห้องพิเศษได้\r\nERโทร IPD 2  ห้องพิเศษพยาบาลรับ case แจ้งว่าห้องเต็ม มี 8 คิว แจ้งญาติคนที่ 1รับทราบ **ญาติคนที่ 1กลับบ้าน / accept \r\nER โทร  admit IPD 1  ห้องสามัญ /และERแจ้งว่า เคสนี้หมอให้เข้าห้องพิเศษได้แต่IPD 2แจ้งห้องพิเศษเต็ม\r\n*** ประเด็นIPD 1 แจ้ง ER ว่าพึ่งคุยกันเรื่องเตียง กับIPD 2 ว่าห้องพิเศษว่าง 1 เตียงค่ะ ****\r\nER จึงโทรกลับ IPD 2 รอบที่ 2 -->  wardแจ้ง ER ว่า ว่าง 1 เตียงสุดท้าย และให้ห้องพิเศษ  ERจึงแจ้งคนญาติ<คนที่ 2 รับทราบ>+คนไข้ accept ', 'เขียนรายงานอุบัติกาณ์\r\nแจ้งหัวหน้ารับทราบ เพื่อขอความชัดเจนข้อมูลเรื่องห้องพิเศษ ก่อนแจ้งว่าเตียงเต็ม ', '0', '01-2026', 'P', 1, 0, 0, 0, 4, NULL, 'PCT', NULL, 69, 5, NULL, NULL, NULL, 'C', '2026-01-15', NULL, NULL, 'Y', NULL, '1900500023051', 'admin1', NULL, NULL, NULL, '61588-', 'IPD');
INSERT INTO `dc_report` VALUES (12881, 69, 2, 6, 2, 'คัดกรองส่งผู้ป่วยมา IPD1 ไม่ปลอดภัย  ', '2026-01-13', '12:10:00', '2026-01-13', '12:43:33', 'Clinic', 'วันที่ 13/1/2569  เวลา 12.10 น. รับย้ายผู้ป่วยจาก OPD  โดยเปลนอน  Dx.CHF with  Pleural effusion U/D DM,HT,DLP   ขาบวมสองข้าง มา 3  วัน  Case Oedema มาตามนัดเพื่อติดตาม แพทย์ OPD ประเมินอาการ lung wheezing BL ,ขาบวมกดบุ๋ม 3+ แรกรับที่ IPD1 ผู้ป่วยมีอาการหายใจเหนื่อย  มี mild retraction RR=24/min PR=78/min BP =108/70 mmHg. OsatRA99%  ขาบวมกดบุ๋ม 3+', '1.ประเมิน V/S ,Osat  ฟังปอดและตรวจร่างกสยผู้ป่วย \r\n2.ดูแล On H/L และฉีดยา Lasix  80  mgV q12 hr.\r\n3.แจ้งแพทย์เวรประเมินอาการซ้ำอีกครั้ง ', 'C', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 70, 5, NULL, NULL, NULL, 'C', '2026-01-15', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '15422-', 'IPD');
