INSERT INTO `dc_report` VALUES (12883, 69, 1, 35, 35, 'รายงานผลผิดพลาด ', '2026-01-13', '14:00:00', '2026-01-13', '14:27:14', 'Clinic', 'เวลา 12.15 น. เจ้าหน้าที่ห้องฉุกเฉิน โทรมาขอเพิ่ม Lab Urine pregnancy test คนไข้ ชื่อ นางขอดิเย๊าะ นิสัน เจ้าหน้าที่แลปเดินมาดูปัสสาวะของคนไข้ เพื่อตรวจสอบว่ามีปัสสาวะอยู่ไหม และได้เห็นปัสสาวะเคสล่าสุดที่วางอยู่ชื่อ ขอลิเย๊าะ ซึ่งชื่อมีลักษณะคล้ายกัน แต่ไม่ได้ดูนามสกุลคนไข้ และสิ่งส่งตรวจที่วางอยู่นั้นมีจำนวนมาก เจ้าหน้าที่เวรเที่ยง เข้าใจว่าเคสที่โทรมาแจ้งคือเคสล่าสุดที่ส่งปัสสาวะ จึงได้ตอบ er ว่าสามารถตรวจได้ ได้ทำการจุ่ม Strip UPT ไป สรุปว่าเคสนี้ Positive ไม่มั่นใจในอายุของคนไข้ จึงได้ตรวจซ้ำอีกครั้ง และคอนเฟิร์มด้วยการดูผลการตรวจ 2 คน ', 'คนไข้ส่งปัสสาวะมาตรวจใหม่อีกครั้ง  และได้ทำการออกผลที่ถูกต้อง พร้อมกับรายงานความเสี่ยง ในหน่วยงานหาแนวทาง เพื่อทบทวนความเสี่ยง', 'C', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 71, 5, NULL, NULL, NULL, 'C', '2026-01-15', NULL, NULL, 'Y', NULL, '1900501126082', 'admin1', NULL, NULL, NULL, '7160-', 'OPD');
