INSERT INTO `dc_report` VALUES (12885, 69, 2, 2, 35, 'ห้องปฏิบัติการลงผลผิดคน ', '2026-01-13', '14:23:00', '2026-01-13', '15:37:02', 'Clinic', '000003417 case  Asthma, Chronic rhinitis , DLP  มาตามนัด  3 เดือน ไม่ขาดยา    ไม่มีหายใจเหนื่อยหอบกำเริบ ไม่ไอ    ประมาณ 1 เดือน  ก่อนมารพ.  มีอาการมึนศีรษะ   ปวดตื้อๆ   กำลังแขนขาปกติ ไม่มีอ่อนแรง   ไม่เพลีย  / O2  sat= 100%  RA \r\n - พบเเพทย์  เเพทย์ให้ฉีด  dimen 50 mg V  และ ส่งตรวจ  UPT    ผู้ป่วยไปฉีดยาที่ ER   ส่ง กลับมาพบแพทย์ ช่วงบ่าย    \r\n-หลังจากพบแทย์ ผล  การตรวจ  UPT     Positive      เเพทย ์ให้ ตรวจซ้ำ    + ให้คุยเรื่องครรภ์ เสี่ยง      หากผลการตั้งครรภ์  positive \r\n-     หลังจากส่งปัสสาวะ รอบสอง  ห้องฏิบัติการ โทรมาเเจ้งว่า  ผลการตั้งครรภ์   Negative   \r\n  (ผลรายงานที่ส่งตรวจไป  ครั้งเเรก    เป็นผลของคนไข้ที่ชื่อเหมือนกัน   ที่ตรวจ ไปรอบ เเรก   )  ', '1.  รายงานเเพทย์  เจ้าของcase รับทราบ \r\n2.  เเพทย์  พูดคุยกับญาติ    และนัด มาพบแพทย์    อีก3 วัน  ตรวจการตั้งครรภ์ ซ้ำ  \r\n3.  อธิบายหากอาการไม่ทุเลา  ให้มาพบแพทย์    เช่น มึนศรีษะ  ', 'C', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 72, 5, NULL, NULL, NULL, 'C', '2026-01-15', NULL, NULL, 'Y', NULL, '3900500022671', 'admin1', NULL, NULL, NULL, '16522-', 'OPD');
INSERT INTO `dc_report` VALUES (12886, 69, 2, 2, 2, 'ไม่ได้เปลี่ยน cystostomy ตามเวลา ', '2026-01-13', '16:10:00', '2026-01-13', '16:32:29', 'Clinic', 'HN 180687 มา เปลี่ยนสายสวนปัสสาวะ  cystostomy ตามนัด พบแพทย์แล้ว รอแพทย์ไปเปลี่ยนให้ ก่อนหน้านี้แพทย์ได้มาถามหลังพบแพทย์แล้ว แต่ทางห้องทำแผล ยังไม่ได้โทรมาตาม\r\nเวลา 16.10 น .ทางห้องทำแผล ได้มาถามเรื่องเปลี่ยนสายสวน cystostomy  แต่แพทย์ได้กลับไปแล้ว จึงโทรติดต่อแพทย์เดิม แพทย์ได้ออกไปข้างนอกรพ.แล้ว บอกว่าทำไมช้าจัง', 'โทรประสานแพทย์เจ้าของ case อีกครั้ง เพื่อตัดสินว่าจะ แosult หมอคนอื่นหรือไม่ ', 'C', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 73, 5, NULL, NULL, NULL, 'C', '2026-01-15', NULL, NULL, 'Y', NULL, '3940700136351', 'admin1', NULL, NULL, NULL, '40807-', 'OPD');
INSERT INTO `dc_report` VALUES (12887, 69, 2, 7, 37, 'จ่ายยาที่ผสมแล้ว และ exp แล้ว', '2026-01-13', '16:30:00', '2026-01-13', '16:41:56', 'Clinic', 'ผู้ป่วยชาย HN17528 อายุ 85 ปี่ Dx CA Lung c pneumonia แพทย็มี Order เปลี่ย ATB จาก Ceftrazidime เป็น Tazocin 4.5 g v g 8 hr ห้องยาจ่ายยามาทั้งหมด 4 vial พยาบาลเวรเช้า stat ยาไปให้เวลา 11.10 น. พยาบาลเวรบ่ายนำยา Tazocin มลมาเพื่อเตรียมผสมเมื่อแกะกล่องยาพบว่า ยามีการเปิดใช้ยาแล้ว และเขียนวันผสมใว้ข้างขวดวันที่ 29/12/68 เวลา 11.00 น. ', '-ประสานเจ้าหน้าที่ห้องยา เพื่อส่งยาคืนและเบิกยาเพิ่ม\r\n-ลงรายงานอุบัติการณ์\r\n-รายงานหัวหน้าหอผู้ป่วยรับทราบ/เวรตรวจการรับทราบ ', 'B', '01-2026', 'P', 1, 1, 0, 0, 1, 'U4', 'PTC', 'U4', 80, 6, 46, 176, 341, 'C', '2026-01-15', '2026-01-21', '', 'Y', 'PTC', '1969500002728', 'PTC', '', '', 'open', '42397-', 'IPD');
INSERT INTO `dc_report` VALUES (12888, 69, 2, 36, 17, 'ขอรถแต่ไม่มีรถมารับ เนื่องจากพนักงานขับรถลาป่วย', '2026-01-13', '08:15:00', '2026-01-14', '10:25:47', 'Non_Clinic', 'เมื่อวันที่ 13/1/69 เวลา 08.10 เจ้าหน้าที่ทันตกรรม นั่งรอรถตามปกติ แต่เมื่อถึงเวลานัดแล้ว รถยังไม่มารับ จึงโทรสอบถามพนักงานขับรถตามที่ระบุใน telegram พนักงานคนดังกล่าวแจ้งว่าตนลาป่วย จะประสานกับผู้จัดรถให้ เวลาผ่านไป 20 นาที จึงมีรถมารับ และได้ให้ข้อมูลว่า ได้แจ้งเปลี่ยนคนขับและรถในระบบแล้วแต่แจ้งผิดเป็นพนักงานขับรถคนเดิมที่ลาป่วย รวมทั้งรถก็ยังเป็นคันเดิม จึงทำให้เกิดเหตุการณ์ดังกล่าวในครั้งนี้', 'ทางหน่วยงานดังกล่าว ได้มีการประสานให้พนักงานขับรถท่านอื่นมารับ-ส่งแทน', '1', '01-2026', 'P', 1, 1, 0, 0, 1, 'U1', 'RM', 'U1', 19, 8, 92, 680, 0, '2', '2026-01-15', '2026-01-15', '', 'Y', 'rm', '1900501138137', 'rm', '', '', '', '70142-', 'N');
