INSERT INTO `dc_report` VALUES (12892, 69, 2, 2, 51, 'ผู้ป่วยกรีดร้อง ตะโกน ดิ้น ไม่ยอมให้ จนท. เจาะ lab ', '2026-01-14', '19:30:00', '2026-01-15', '08:37:05', 'Clinic-Dx', 'ผู้ป่วย HN 63675 U/D  DM, HT,meningitis  (เปลอน)   คัดกรอง จาก ER  มารอซักประวัติและตรวจที่ OPD ( แรกรับ OPD  อาการสงบ นิ่ง  นอนบนเตียง ถามตอบได้ ปกติ  ) ญาติให้ข้อมูลว่า 3 ชั่วโมงก่อนมารพ.  มีอาการหูแว่ว เห็นภาพหลอนถี่ขึ้น   หลังส่งพบแพทย์ OPD รอบที่ 1    มี order  สั่งเจาะ lab   จึงประสาน  จนท. ห้อง lab ให้มาเจาะเลือดข้างเตียง  แต่ยังไม่ทันได้ลงมือเจาะอยู่ๆ  ผู้ป่วยก็มีอาการกรีดร้องลั่น  โวยวาย   ดิ้นไปมา  ลงจากเตียง  ( ขณะนั้น ญาติมายืนรุมเต็มข้างเตียง )  ลูกๆ ญาติผู้ชาย จึงช่วยกันจับ แต่ผู้ป่วยยังไม่นิ่ง  ได้โทรแจ้งยาม  และ จนท. ศูนย์เปลมาช่วย  restained +นำส่ง ER   และแจ้งแพทย์เวรทราบด่วน มี order  เพิ่ม และได้ประสาน   พยบ.  ER เพื่อ ส่งไปฉีดยา  Diazepam 1  amp  IV    at   ER    ทันที', '- รายงานแพทย์เวรทราบทันที \r\n- โทรแจ้งยาม และพนง. ศุนย์เปลมาช่วย restained + นำส่ง ER เพื่อดูแลต่อ\r\n', 'C', '01-2026', 'P', 1, 0, 0, 0, 4, NULL, 'PCT', NULL, 74, 5, NULL, NULL, NULL, 'C', '2026-01-15', NULL, NULL, 'Y', NULL, '1959900110234', 'admin1', NULL, NULL, NULL, '67010-', 'OPD');
INSERT INTO `dc_report` VALUES (12893, 69, 2, 37, 37, 'ใบ MR ไม่ใช่ข้อมูลล่าสุด', '2026-01-15', '10:25:00', '2026-01-15', '10:16:06', 'Clinic', 'HN 83277 Ward 2 โทรแจ้งว่าผป.แพ้ simvastatin ยังไม่มีประวัติในระบบ \r\nในสมุดประจำตัวผป.เปลี่ยนเป็น Atorvastatin แล้ว แต่ในใบ MR ยังเป็น Simvas \r\nตอนนอนรพ.แพทย์สั่ง simvas ตามใบ MR +/- ผื่นขึ้น then เปลี่ยนเป็น Atorvas', 'รับทราบตอน D/C จึงเขียนบัตรแพ้ยาและลงประวัติในคอม + เขียนใบ MR ใหม่ให้เป็นประวัติล่าสุด', '4', '01-2026', 'P', 1, 1, 0, 0, 1, 'U4', 'PTC', 'U4', 84, 6, 114, 1041, 754, 'C', '2026-01-15', '2026-01-16', '', 'Y', 'PTC', '1969900313984', 'PTC', '', '', '', '32511-', 'IPD');
