INSERT INTO `dc_report` VALUES (12896, 69, 2, 42, 3, 'เลือดออกทางสาย Heplock', '2026-01-15', '09:00:00', '2026-01-15', '11:18:59', 'Clinic', 'วันที่ 15/1/69 เวลาประมาณ 09.00 น.ห้องอุบัติเหตุส่งผู้ป่วย  HN 000063079 มาเอกซเรย์ พบว่าที่แขนด้านขวาบริเวณที่ On Heplock มีเลือดออกเต็มสายและมีเลือดติดที่เสื้อผู้ป่วยด้วย (ดังภาพแนบ)', '- แจ้งหน่วยงานที่เกี่ยวข้อง\r\n- รายงานความเสี่ยงในระบบ', 'B', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 75, 5, NULL, NULL, NULL, 'B', '2026-01-15', NULL, NULL, 'Y', NULL, '3909700096820', 'admin1', NULL, NULL, NULL, '76581-ir.jpg', 'OPD');
INSERT INTO `dc_report` VALUES (12897, 69, 2, 43, 3, 'ผู้รับบริการโพสเฟส เรื่องระยะเวลารอคอย', '2026-01-12', '13:52:00', '2026-01-15', '11:29:26', 'Non_Clinic', 'รับแจ้งจากเจ้าหน้าที่ว่า วันที่ 11 มกราคม 2569 ว่ามีผู้ป่วย ชื่อในเฟสว่า \"Amita  Botoei\" มารับบริการที่ห้องอุบัติเหตุเวลา 2 ทุ่มโพสเฟส ข้อความดังนี้ \" น่าเบื่อมากกกก เป็นอะไรที่ช้ามากกกกกก มาถึง 2 ทุ่มกว่าๆ นี้จะ5 ทุ่มแล้วยังไม่เรียกอีก นี่ถ้าคนใกล้ตาย ป่านี้ไปฝั่งกุโบร์แล้ว\"', '- แจ้งคกก.ข้อร้องเรียนรับทราบและดำเนินการ\r\n- รายงานความเสี่ยงในระบบ', '1', '01-2026', 'P', 1, 1, 0, 0, 1, 'U9', 'RM', 'U9', 20, 8, 115, 559, 0, '1', '2026-01-15', '2026-01-15', '', 'Y', 'rm', '3909700096820', 'rm', '', '', '', '51147-ir.jpg', 'OPD');
INSERT INTO `dc_report` VALUES (12898, 69, 2, 43, 43, 'ผู้รับบริการไม่พึงพอใจการให้การดูแลรักษาพยาบาล', '2026-01-13', '15:00:00', '2026-01-15', '13:39:42', 'Clinic-Dx', 'รักษาการหัวหน้างานห้องคลอด ได้รับแจ้งจาก จนท.รพ.สต สะกอมว่า ผู้ป่วยชื่อ วาสนา จินะ ไม่พึงพอใจการรักษาพยาบาล จนทำให้แท้งลูก โดยได้ส่งข้อความมีรายละเอียดดังนี้ \r\n\" ฉ๊ะนิยังเรืองอยากถามมันค่าใจอยู่เรืองเดิมนั้นและอยากถามฉ๊ะว่าถ้าเป็นหมอตรวจตรวจอาการนิวันนั้นฉ๊ะจะวินิฉัยว่าพรือวันที6เวลาบ่ายสองนินามีมูกเลือกออกแต่ไม่มากพอไปโรงบาลหมอผู้ชายอันตาซาวว่าเด็กยังอยู่เเต่เด็กไม่ได้อยู่ในมดลูกมันในถุงนินาคิดในใจหรือว่าเราท้องนอกมดลูกแต่หมอไม่ได้บอกว่าเราท้องนอกมดลูกเขาเจาะเลือดตรวจเยี่ยวแล้วมีหมอผู้หญิงมาเปลียนเวรหมอผู้หญิงมาตรวจอีกทีก็บอกว่าเด็กยังอยู่ให้ตรวจภายในอีกทีพอหลังจากตรวจภายในเลือดออกมากหว่าเดิมถึงเขาบอกว่าเด็กยังอยู่สามารถไปต่อได้ให้หลบบ้านไปนอนอย่าเดินเยอะอย่ายกของหนักไม่ให้นอนเเลอาการนั่งรถเครืองหลบมหว่างจีถึงบ้านแล้วทีเขาบอกว่าเด็กในถุงแล้วมันไม่เสียงหลุดน่อพอกลางคืนนินาเจ็บพุงแล้วเลือดก็ออกทุกทีไปเยี่ยวพอเช้ามาทีนินาโทรหาฉ๊ะพอวางสายเจ็บเยี่ยวแล้วมันหลุออกมาโทรฉุกเฉินหว่างจีมาหลุดออกมาล่าวสองรอบพอไปถึงโรงบาลหมอบอกน้องไม่อยู่ถึงเห็นนินานอนไม่เจ็บเท่าให้หลบบอกให้หลบไปแลอาการทีบ้านลูกไปทำเรืองออกสักพักนินาเจ็บเเล้วเลือดออกมาล่าวนินาวิ่งเข้าห้องนำ้สามรอบทั้งเจ็บพุงแล้วเวียนหัวในห้องฉุกเฉินใครมัยมาแลหมอกะนั้งทีโต๊ะนินาให้ลูกไปบอกหมอว่านินาเวียนหัวกับเจ็บพุงแรงหมอตอบมาว่าครับรับทราครับพอสักพักถึงมาบอกว่าเสียเลือดเยอะให้นอนโรงบาลได้ตอ้งถ้ามห้ตายก่อนและถึงจีให้นอนโรงบาลเราอุสาไปพึงหมอแต่สิ่งทีได้กลับให้เสียความรู้สึกได้ทีโรงบาลเทพาเดียวนี้ถึงเป็นแบบนี้แล้วแต่ก่อนไม่เป็นแบบนี้ทีนินาคิดว่าอัลเลาะให้มันมาอยู่กับเราเท่านั้นพอนึกถึงโรงบาลทำแบบนั้นมันเสียความรู้สึกถ้าฉ๊ะเป็นหมออยู่ตอนนั้นฉ๊ะจะทำแบบนั้นม้ายนินาแค่อยากจีเล่าให้ฟังเรืองทีนินาพบแต่ก่อนเขาย่อกันว่าโรงบาลเทพาดีพอพบแบบนี้หมดหวังเลยขอบใจน่อทีรับฟังบางทีพอนึกไปมันทำให้คิด\" ซึ่งผู้รับเรื่องไม่แน่ใจประเด็นว่าจะมีการฟ้อง รพ.หรือไม่', '- แจ้งคกก.ข้อร้องเรียน\r\n- แจ้งเลขา PCT \r\n- รายงานความเสี่ยงในระบบ', 'D', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 76, 5, NULL, NULL, NULL, 'D', '2026-01-15', NULL, NULL, 'Y', NULL, '3909700096820', 'admin1', NULL, NULL, NULL, '95692-', 'OPD');
