INSERT INTO `dc_report` VALUES (12900, 69, 2, 42, 47, 'เปิดน้ำทิ้งไว้', '2026-01-15', '10:25:00', '2026-01-15', '13:50:21', 'Non_Clinic', 'เวลาประมาณ 10.25 น.เข้าไปห้องรับประทานอาหารเจ้าหน้าที่ (ข้างห้อง OR) พบว่ามีการเปิดน้ำใส่กระบอกน้ำทิ้งไว้ ทำให้น้ำนองในพื้นเป็นบริเวณกว้าง เสี่ยงต่อการลื่นล้ม', '- แจ้งพนักงานทำความสะอาดเช็ดนำ้\r\n- แจ้งผู้เกี่ยวข้องทราบ\r\n- รายงานความเสี่ยงในระบบ', '1', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'ENV', NULL, 35, 1, NULL, NULL, NULL, '1', '2026-01-15', NULL, NULL, 'Y', NULL, '3909700096820', 'admin1', NULL, NULL, NULL, '33073-', 'OPD');
INSERT INTO `dc_report` VALUES (12901, 69, 2, 6, 3, '๊Unplan Refer ', '2026-01-15', '21:41:00', '2026-01-15', '17:07:12', 'Clinic', 'วันที่ 15/1/2568  เวลา 09.40 น. รับย้ายผู้ป่วยจาก ER เวลา 09.40  น.  ผู้ป่วยชายไทยอายุ 72 ปี HN:000063079 An:690000220 Dx.R/O acute appendicitis  มาด้วยอาการ  ปวดท้องบริเวณสี่ข้างด้านขวาทะลุหลัง  ก่อนมารพ.1 วัน  ER แพทย์ FilM AAS :impact feces แผนการรักษา เจาะ lab CBC,BUN,cratinine ,Eletrolyte ,UA  Admit  ให้ nss 1000 ml v rate 60 cc/hr.( ER ไม่ได้ OnIV) ย้ายมาที่ IPD1 ผู้ป่วยปวดท้องด้านขวาล่าง PS 10/10 คะแนน มี Rebound tender แพทย์เวร IPD1 consult refer รพ.สงขลา Dx.R/O Diverticulitis (ย้ายผู้ป่วยลงเตียงแพทย์ไปประเมินอาการผู้ป่วยทันที)', '1.ประเมิน V/S ประเมิน Avorado score \r\n2.ประเมินอาการปวดท้อง อาเจียน \r\n3.รายงานแพทย์เวร IPD4 ทราบ \r\n4.Ultrasound consult แพทย์รพ.สงขลา Sx.อ.กรินทร์รับ case refer ', 'E', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 77, 5, NULL, NULL, NULL, 'E', '2026-01-25', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '52729-', 'IPD');
