INSERT INTO `dc_report` VALUES (12903, 69, 2, 6, 3, 'ไม่่ทำหัถตการก่อนเข้า ward ', '2026-01-14', '16:30:00', '2026-01-16', '08:20:26', 'Clinic', 'วันที่ 14/1/2568  เวลา 16.30  น.  รับย้ายผู้ป่วยจาก OPD ส่ง ER  ผู้ป่วยเด็กหญิงพม่า อายุ 12  ปี Dx.Infection AGE with sepsis ,(Hypo K =3) 2 วันถ่ายเหลว 8-9 ครั้ง/วัน อาเจียน  5 ครั้ง วันนี้ถ่ายเหลว 5 ครั้ง อาเจียน 2  ครั้ง  OPD BT=38.9 C PR =128/min RR=20/min PR=128/min  แพทย์ order เจาะ LabCBC,H/C*1 ,lactate ,CXR  OPD ส่งไปทำหัตถการที่ ER On IVF 5%D/Nss 1000 ml +KCL 20 meq. V rate 70 cc/hr ----> ER โทรแจ้งย้ายผู้ป่วยโดยไม่ทำหัถตการก่อนเข้า Ward ', '1ประเมิน V/S Osat \r\n2 ประเมินอาการถ่ายเหลว อาการปวดท้อง ไข้ อาการอาเจียน\r\n3 ประเมิน SIRs  \r\n4 ดูแล On IVF ตามแผนการรักษาของแพทย์ ', 'C', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 78, 5, NULL, NULL, NULL, 'C', '2026-01-25', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '97946-', 'IPD');
