INSERT INTO `dc_report` VALUES (12921, 69, 2, 4, 37, 'ห้องยาจ่ายยาผิด', '2026-01-15', '16:00:00', '2026-01-20', '15:37:27', 'Clinic-Dx', 'วันที่15/1/69 ช่วงเวลา16.00น. ห้องคลอดมีเคสมารดาติเชื้อ ซิฟิลิส คลอดแล้ว แพทย์มี orderให้ฉีด Benzathine penicillin G  ทั้งมารดาและทารก แต่ห้องยาผิดตัว โดยให้ยา Penicillin G  มาแทน ทั้งของมารดาและทารก พยาบาลห้องคลอดจึงโทรไปแจ้งให้ทราบและนำ order แพทย์พร้อมยาคืนห้องยา  และให้จัดยาใหม่ให้ถูกต้อง \r\n\r\n', ' พยาบาลห้องคลอดจึงโทรไปแจ้งให้ทราบและนำ order แพทย์พร้อมยาคืนห้องยา  และให้จัดยาใหม่ให้ถูกต้อง ', 'B', '01-2026', 'P', 1, 1, 0, 0, 1, 'U4', 'PTC', 'U4', 96, 6, 46, 176, 334, 'B', '2026-02-04', '2026-02-25', '', 'Y', 'ptc', '3900500222254', 'ptc', 'Penicillin G', 'Benzathine penicillin G ', 'open', '82837-', 'IPD');
INSERT INTO `dc_report` VALUES (12922, 69, 2, 2, 2, 'ผู้ป่วยปฏิเสธการรักษาadmit', '2026-01-20', '15:35:00', '2026-01-20', '16:42:16', 'Clinic', 'HN66938    9 วันก่อนมารพ. (วันที่  11/1/69  เวลา  17.00  น )  นั่งซ้อนท้ายรถจักรยานยนต์ ชน กับรถเก๋ง    ถไลไปกับ รถจักรยานยนต์    มีเผลที่ข้อด้านขวา  มีเเผลที่ข้อศอก     ไม่มีปวด   ปฏิเสธศรีษะ กระเเทกพื้น    เดินได้ปกติ   ไม่ได้รักษาที่ไหน    \r\n4 วัน ก่อนมารพ.  บวมที่เข่าขวา    ตึงที่เข่า ไม่วด  ย์ดขาไม่สุด  จึงมารพ. ---->พบแพทย์เเพทย์ให้เอกซเรย์  เเละadmit  ผุ้ป่วยปฎิเสธ', '1.advice   อาการที่ผิดปกติ\r\n2.นัดมาดูอาการ 27/1/69 ', 'C', '01-2026', 'P', 1, 0, 0, 0, 10, NULL, 'PCT', NULL, 82, 5, NULL, NULL, NULL, 'C', '2026-02-04', NULL, NULL, 'Y', NULL, '3900500022671', 'admin1', NULL, NULL, NULL, '18873-', 'OPD');
INSERT INTO `dc_report` VALUES (12923, 69, 2, 8, 21, 'ผ้าห่อเชต', '2026-01-21', '09:02:00', '2026-01-21', '10:48:31', 'Clinic', 'ขอผ้าห่อเซต ที่เจ้าหน้าที่ซักฟอก เวลา 09.02น.  ยังไม่มี พอถึวเลา 10.52น ไปเก็บผ้า แต่ไม่มีผ้าคะ  เจ้าหน้าที่ นั่งเล่นโทรศัพท์ อยู่คะ   ทั้งๆที่มีผ้า 2ถังทีอบแร้วคะ ในห้อง', ' แจ้งหัวหน้า', 'A', '01-2026', 'P', 1, 1, 0, 0, 1, 'U1', 'RM', 'U1', 27, 8, 92, 472, 799, '1', '2026-02-04', '2026-02-04', '', 'Y', 'rm', '1900500064563', 'rm', '', '', '', '34154-', 'N');
INSERT INTO `dc_report` VALUES (12924, 69, 2, 7, 37, 'พูดจาคุกคาม', '2026-01-14', '23:50:00', '2026-01-21', '14:33:20', 'Non_Clinic', 'วันที่ 14/1/69 เวลา 23.45 น. หอผู้ป่วยใน 2 มีผู้ป่วย case complete abortion แพทย์ทำคลอดทารกที่เสียเชียวิตแล้ว และต้องการส่งตรวจชิ้นเนื้อรกโดยต้องแช่น้ำยาฟอร์มาลิน  ผู้ช่วยเหลือคนไข้ จึงนำนำ้ยาฟอร์มาลินไปให้เจ้าหน้าที่ห้องยาผสมให้  เมื่อไปถึงห้องยาถูกตำหนิ ว่าทำไมเพิ่งมาตอนนี้ พุดด้วยน้ำเสียงไม่พอใจ ทำไมถึงไม่ผสมตั้งไว้ ถ้าเกิดห้องยาไม่ผสมให้จะเอาจากไหน', '-รายงานหัวหน้างาน\r\n-ลงอุบัติการณ์', '1', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'HUM', NULL, 6, 4, NULL, NULL, NULL, '1', '2026-02-04', NULL, NULL, 'Y', NULL, '1910300006284', 'admin1', NULL, NULL, NULL, '27138-', 'N');
INSERT INTO `dc_report` VALUES (12925, 69, 2, 7, 2, 'ไม่ได้ทำหัตการ แต่ติ๊กใน order ว่าทำแล้ว', '2026-01-21', '15:30:00', '2026-01-21', '17:05:13', 'Clinic', 'ผู้ป่วยหญิง อายุ 99 ปี HN 13815 case infected bedsore แพทย์มีแผนการรักษาให้ส่ง pus c/s จากแผล พยาบาล OPD ทำสัญลักษ์ติ๊กหน้าหัตการดังกล่าว เมื่อผู้ป่วยมาถึงวอร์ด มีอุปกรณ์สำหรับเก็บ lab ดังกล่าวใส่มาในถุงยาผู้ป่วย พยาบาลวอร์ด โทรไปสอบถามปรากำว่ายังไม่ได้ทำหัตถการดังกล่าวเลย', '- พยาบาลวอด เก็บ lab ดังกล่าวเพื่อส่งให้\r\n-อยากให้พยาบาล OPD เพิ่มความละเอียดในการอ่าน order ว่าได้ทำอะไรไปแล้วบ้างตามที่แพทยื order เพราะเจอบ่อยที่ไม่ได้ทำหัตการแล้วติ๊ก  ส่วนหัตการที่ทำแล้วกลับไม่ติ๊กว่าทำแล้ว เพราะอาจจะทำให้มีผลต่อการรักษาผู้ป่วย', 'B', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 83, 5, NULL, NULL, NULL, 'B', '2026-02-04', NULL, NULL, 'Y', NULL, '1910300006284', 'admin1', NULL, NULL, NULL, '72026-', 'IPD');
INSERT INTO `dc_report` VALUES (12926, 69, 2, 35, 3, 'เจาะ Hemoculture ซ้ำ ', '2026-01-23', '22:23:00', '2026-01-23', '22:17:11', 'Clinic', '23/1/2026 เวลา 17.40 Pt มาจาก OPd โดยมี order cbc , Hemo 2 ขวด โดยทางห้องแลปได้ทำการเจาะเลือดเสร็จกระบวนการทั้งสองอย่าง และให้ผู้ป่วยกลับไปนั่งรอพบแพทย์ ที่ OPD หลังจากนั้นเวลา 21.00 มีการนำส่งขวด Hemoculture ซ้ำจากจุด ER โดยเป็นคนไข้เดิม', 'เนื่องจากขวด Hemo มีต้นทุนค่าใช้จ่าย เจ้าหน้าที่ที่ปฏิบัติงานต้องตรวจสอบให้ครบถ้วนก่อนที่จะทำการเก็บตัวอย่าง', 'B', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 84, 5, NULL, NULL, NULL, 'B', '2026-02-04', NULL, NULL, 'Y', NULL, '3900500033443', 'admin1', NULL, NULL, NULL, '44235-', 'OPD');
INSERT INTO `dc_report` VALUES (12927, 69, 1, 35, 3, 'สิ่งส่งตรวจไม่มีสติ๊กเกอร์ ชื่อ-สกุล', '2026-01-21', '08:20:00', '2026-01-25', '09:51:01', 'Clinic', 'จุดบริการอื่นๆ ได้ส่งตัวอย่างคนไข้มาเป็น Tube Heparin (สีเขียว) แต่ไม่มีการติดสติ๊กเกอร์ชื่อ-สกุลคนไข้มา จึงไปดูในระบบว่ามีจุดไหนKey แลปมาบ้าง พบว่า เป็นจุดบริการ ER จึงโทรไปสอบถาม และให้นำสติ๊กเกอร์มาติกพร้อมเขียนใบบันทึกยืนยันการใช้สิ่งส่งตรวจเดิม โดยยืนยันเป็นของคนไข้ชื่อนายหะแว เจ๊ะมิง ส่งตรวจ Trop-I', 'ให้นำสติ๊กเกอร์มาติกพร้อมเขียนใบบันทึกยืนยันการใช้สิ่งส่งตรวจเดิม', 'B', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 85, 5, NULL, NULL, NULL, 'B', '2026-02-04', NULL, NULL, 'Y', NULL, '1900501126082', 'admin1', NULL, NULL, NULL, '23679-', 'OPD');
INSERT INTO `dc_report` VALUES (12928, 69, 1, 35, 3, 'สิ่งส่งตรวจไม่มีสติ๊กเกอร์ ชื่อ-สกุล', '2026-01-21', '14:50:00', '2026-01-25', '09:57:30', 'Clinic', 'ER ส่ง Hemoculture เด็ก (ขวดสีเหลือง) แต่สิ่งส่งตรวจนั้นไม่มีสติ๊กเกอร์ ชื่อ-สกุล จึงได้โทรไปแจ้งและให้นำสติ๊กเกอร์มาติดพร้อมเขียนใบบันทึกยืนยันการขอใช้สิ่งส่งตรวจเดิม ยืนยันโดยเจ้าหน้าที่ผู้เจาะ ตัวอย่างนั้น ชื่อ ด.ญ.ซัลซาบีล สูหลง', 'ให้นำสติ๊กเกอร์มาติดพร้อมเขียนใบบันทึกยืนยันการขอใช้สิ่งส่งตรวจเดิม', 'B', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 86, 5, NULL, NULL, NULL, 'B', '2026-02-04', NULL, NULL, 'Y', NULL, '1900501126082', 'admin1', NULL, NULL, NULL, '41365-', 'OPD');
INSERT INTO `dc_report` VALUES (12929, 69, 1, 35, 24, 'วันเดือนปีไม่ตรงกัน', '2026-01-22', '15:20:00', '2026-01-25', '10:02:45', 'Clinic', 'คนไข้มาเจาะเลือดที่ห้องเจาะเลือด เจ้าหน้าที่ได้สอบถามชื่อ-สกุลคนไข้ พร้อมกับสอบถามวันเดือนปีเกิดของคนไข้ คนไข้ตอบมาซึ่งไม่ตรงกับข้อมูลในระบบ Hosxp จึงขอบัตรประชาชนคนไข้มาตรวจสอบ จึงพบว่าในระบบ Hosxp ลงข้อมูลผิด จึงโทรไปแจ้งห้องบัตรให้แก้ไข้ให้ถุกต้อง ในระบบ Hosxp ลงวันเดือนปีเกิดคนไข้ เป็น 12 พ.ย. 2533 แต่ตามบัตรประชาชนคนไข้ เป็น 13 พ.ย. 2532 ซึ่งวันเดือนปีเกิด มีผลกับค่าเลือดบางตัว จำเป็นต้องใช้ข้อมูลตรงนี้มาคำนวณหาค่า เช่น eGFR ', 'ขออนุญาตคนไข้ถ่ายรูปบัตรประชาชน และโทรไปแจ้งให้ห้องบัตรแก้ไขข้อมูลในระบบ Hosxp ให้ถูกต้อง', 'B', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 13, 3, NULL, NULL, NULL, 'B', '2026-02-04', NULL, NULL, 'Y', NULL, '1900501126082', 'admin1', NULL, NULL, NULL, '1293-วดป-ไม่ตรง.jpg', 'OPD');
