INSERT INTO `dc_report` VALUES (12935, 69, 2, 2, 37, 'ฉีกใบ copy order admit ที่แพทย์ยังไม่ order ออกหมด', '2026-01-25', '00:00:00', '2026-01-25', '12:16:06', 'Clinic', 'HN 81451 แพทย์รับไว้รักษาในโรงพยาบาล ในใบ order แพทย์เขียน order แค่ครึ่งหน้า หลังจากให้ญาติไปยื่นรับยาที่ห้องยา พบว่า order ได้ถูกฉีกไปทั้งแผ่นโดยที่ยังเหลือใช้อีกครึ่งหน้า ทำให้เวลาแพทย์จะ order เพิ่ม ต้องใช้แผ่นใหม่ ', '-', 'B', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 87, 5, NULL, NULL, NULL, 'B', '2026-02-04', NULL, NULL, 'Y', NULL, '1900500049611', 'admin1', NULL, NULL, NULL, '79051-s__127123471.jpg', 'OPD');
INSERT INTO `dc_report` VALUES (12936, 69, 2, 3, 2, 'แจ้งประวัติผู้ป่วยไม่ครอบคลุม ', '2026-01-25', '14:30:00', '2026-01-25', '15:00:57', 'Clinic-Dx', 'case pneumonia ส่งมา on IV +รอ lab พยาบาล OPD  โทรประสาน ER มาแจ้งประวัติผู้ป่วยไม่ครอบคลุม Hx  TB  lung ขาดยาด้วย พนักงานเปลเข็นผู้ป่วยมาจอดที่ zone สังเกตอาการ ที่ไม่ใช่ห้องแยก\r\n', 'เคลื่อนย้ายผู้ป่วยเข้าห้องแยกER', 'D', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 88, 5, NULL, NULL, NULL, 'D', '2026-02-04', NULL, NULL, 'Y', NULL, '3900100411394', 'admin1', NULL, NULL, NULL, '33533-', 'OPD');
INSERT INTO `dc_report` VALUES (12937, 69, 1, 2, 2, 'ปฏิเสธ Admit ', '2026-01-26', '11:30:00', '2026-01-26', '11:38:40', 'Clinic', 'ผู้ป่วย HN  180809 แพทย์วินิจฉัยเป็น Wheezing breathing,Pneumonia ต้องการรับไว้รักษาในโรงพยาบาล แต่ผู้ป่วยปฏิเสธ เนื่องจากต้องการพักที่ที่ค่าย ', '- แนะนำสังเกตอาการผิดปกติ \r\n- เขียนเซ็นต์ใบปฏิเสธ', 'D', '01-2026', 'P', 1, 0, 0, 0, 10, NULL, 'PCT', NULL, 89, 5, NULL, NULL, NULL, 'D', '2026-02-04', NULL, NULL, 'Y', NULL, '1900500049611', 'admin1', NULL, NULL, NULL, '11628-', 'OPD');
INSERT INTO `dc_report` VALUES (12938, 69, 2, 3, 50, 'เครื่องพ่นยาไม่พอใช้', '2026-01-27', '10:01:00', '2026-01-27', '10:00:47', 'Clinic-Dx', 'ER มีCase เหนื่อยมาพร้อมกัน 6 case มีเครื่องพ่นยาอยู่2 เครื่อง ,ถังออกซิเจน 1 เครื่อง (ห้องแยกมี Case )เครื่องพ่นยาหมดไม่พอใช้ ---->ไปดูที่ห้องเครื่องมือ ไม่มีเครื่องพ่นยา มีแต่เครื่องชำรุด ', 'ให้ผู้ป่วยพ่นยาใน ER (ไม่ใช่ห้องแยก) ผ่านไปท์ไลออกซิเจน 2 case ,พ่นผ่านเครื่องพ่นยา 2case ,พ่นยาผ่านถังออกซิเจนอีก 1 case ,อีก 1 case เหนื่อยไม่เยอะให้รอสลับเครื่องพ่น ', 'C', '01-2026', 'P', 1, 1, 0, 0, 1, 'EM', 'EM', 'EM', 2, 2, 13, 1077, 0, 'C', '2026-02-04', '2026-02-25', 'แจ้งศูนย์เครื่องมือสำรวจเครื่องพ่นยา', 'Y', 'EM', '1900400008041', 'EM', '', '', '', '28737-', 'OPD');
INSERT INTO `dc_report` VALUES (12939, 69, 2, 2, 2, 'ให้ยา filadec เกินขนาด', '2026-01-27', '10:00:00', '2026-01-27', '10:04:51', 'Clinic', 'มีพม่ามาตรวจสุขภาพต่างด้าว 5 ราย เจ้าหน้าที่ได้จัดยาให้กิน มียา ถ่ายพยาธฺิ 2 เม็ด ยาป้องกันเท้าช้าง 1 เม็ด (filadec) HN 182724 จนท.ได้ให้ ยา filadec 2 เม็ด ยาถ่ายพยาธิ 1 เม็ด ', '-ประสานเภสัชกร เรื่องอันตรายที่อาจเกิดขึ้น  เภสัช แนะนำให้ทานยาถ่ายพยาธิเพิ่ม 1 เม็ด\r\nยาที่กินไม่อันตรายมาก \r\n-อธิบายผู้ป่วยให้ทราบ \r\n', 'D', '01-2026', 'P', 1, 1, 0, 0, 1, 'OPD', 'PTC', 'OPD', 97, 6, 46, 174, 748, 'D', '2026-02-04', '2026-02-25', 'นำเข้าที่ประชุม PTC ', 'Y', 'PTC', '3940700136351', 'PTC', '', '', 'open', '25736-', 'OPD');
INSERT INTO `dc_report` VALUES (12940, 69, 2, 4, 4, 'ตกเลือดหลังคลอด', '2026-01-28', '11:00:00', '2026-01-28', '16:05:46', 'Clinic-Dx', 'มารดา อายุ 18 ปี HN 134248 P1-0-0-1 NL c Rt epi c tear labia minora Rt c mild PIH c obesity คลอดปกติเวลา 06.20 น. วันที่ 28/01/2569 รกคลอด complete เวลา 06.25 น. หลังคลอดได้รับยา 0.9%NSS 1000 cc + oxytocin 40 unit IV drip rate 120 cc/hr. มดลูกหดรัดตัวดี          2 ชม.หลังคลอดเวลา 08.45 น. flush perinium + เค้นล้วง blood clot BL = 400 cc. รวม TBL = 520 cc. no active bleed มดลูกหดรัดตัวดี เวลา 10.40 น. pad เปื้อน 1 ชิ้นชุ่ม BL = 70 cc. TBL = 590 cc. ย้ายผู้ป่วยเข้าห้องคลอดขึ้นขาหยั่งเพื่อประเมินการฉีกขาดของช่องทางคลอด ช่องทางคลอดปกติ ล้วง blood clot ออกอีกเล็กน้อย no active bleed มดลูกหดรัดตัวดี รายงานแพทย์เวรทราบเวลา 10.46 น. มาดูอาการ USG มีเศษรกค้างในโพรงมดลูก แพทย์ order D/C stat เริ่ม D/C เวลา 11.15 น. under valium + pethidine เวลา 11.35 น. ตามแพทย์พรทิพย์มาช่วยขูดมดลูก ผู้ป่วยตื่น แพทย์จึง order under propofol D/C เสร็จเวลา 12.10 น. TBL = 1400 cc. มดลูกหดรัดตัวดี \r\nการรักษาที่ได้รับ \r\n-	Load RLS total 2000 cc. \r\n-	Transmic acid 1000 mg + 0.9%NSS 100 cc IV drip in 15 min at 11.33 น. \r\n-	Cytotec 4 tab rectal suppo at 11.56 น. \r\n-	Gelofusin 500 ml IV load at 12.10 น. \r\n-	Retain foley’s cath at 12.15 น. \r\n-	LPRC 2 unit IV drip at 14.05 น. \r\n-	Ceftri 2 gm IV drip OD at 14.30 น. \r\n', '- รายงานแพทย์เวรทราบ \r\n- รายงานอุบัติการณ์\r\n- รายงานหัวหน้างาน', 'E', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 90, 5, NULL, NULL, NULL, 'E', '2026-02-04', NULL, NULL, 'Y', NULL, '1900500006873', 'admin1', NULL, NULL, NULL, '36941-', 'IPD');
INSERT INTO `dc_report` VALUES (12941, 69, 2, 3, 11, 'ไม่มีรถ refer', '2026-01-29', '11:15:00', '2026-01-29', '11:40:03', 'Clinic', '11.00 น. er มี  plan  refer 2  case  พร้อมกัน  1. เด็ก  1 ปี  seizure 1st. episode refer HYH.\r\n2. drug induce psychosis refer SHPH. ประสานขอรถ refer จากบริหาร เคสแรก HYH. รถออกเวลา 11.08 น.  เคสที่ 2  refer SKPH. เวลา 11.20 น. โทรขอรถบริหาร  แจ้งว่าไม่มีคนขับรถ ให้รอรถคันแรกกลับตอนนี้ประสาน พขร.แล้ว รถคันแรกระหว่างเดินทางไป SKH. ถึงจะนะแล้ว ', 'แจ้งพยาบาล refer ให้กลับก่อน \r\nแจ้งญาติว่าต้องรอรถประมาณ  2 ชม.  ญาติรับทราบ ', 'C', '01-2026', 'P', 1, 1, 0, 0, 1, 'U1', 'ENV', 'U1', 36, 1, 157, 1096, 0, 'C', '2026-02-04', '2026-02-24', '', 'Y', 'env', '3900500052758', 'env', '', '', '', '51340-', 'OPD');
INSERT INTO `dc_report` VALUES (12942, 69, 2, 3, 43, 'กล่าวหาว่า er ฉีกผ้าขวางเพื่อมัดคนไข้ ', '2026-01-26', '10:11:00', '2026-01-29', '11:51:41', 'Non_Clinic', '10.11 น. รับโทรศัพท์จากบริหารแจ้งว่ามีอุบัติการณ์ จากห้องผ้า ว่า er ฉีกผ้าขวางเตียงเพื่อมัดคนไข้ 2 ผืน คาดการณ์ว่าน่าจะเกิดเหตุช่วงวันหยุดที่ผ่านมา  er ประสาน ห้องผ้า ยืนยันว่าเป็นถุงผ้าจาก er / สอบถาม จนท.เวร er ทุกคน ที่ปฏิบัติงานระหว่างวันที่ 23-25 มค.69 ไม่มีใครฉีกผ้าขวาง  สอบถามงานยานพาหนะแล้วไม่มี พขร. คนไหนฉีกผ้าขวาง /ตรวจสอบรายชื่อผู้ป่วย refer ทั้ง รพ. พบว่ามีเคส จิตเวช refer จาก ward 1 อีก  1 เคส จึงสอบถามไปที่ ward 1 แจ้งว่าไม่มีใครฉีกผ้าขวางเช่นกัน    ', 'สอบถาม จนท. ที่อาจเกี่ยวข้องกับเหตุการณ์นี้ \r\nรายงานความเสี่ยง \r\nแจ้งย้ำ จนท. er เรื่องมาตรการการจำกัดพฤติกรรมคนไข้ด้วยผ้ารัด \r\n', '2', '01-2026', 'P', 1, 1, 0, 0, 1, 'U1', 'RM', 'U1', 28, 8, 92, 472, 0, '2', '2026-02-04', '2026-02-14', '', 'Y', 'rm', '3900500052758', 'rm', '', '', '', '25858-', 'OPD');
INSERT INTO `dc_report` VALUES (12943, 69, 2, 2, 37, 'ปริ้นสติกเกอร์ยาผิดคน ', '2026-01-27', '08:00:00', '2026-01-29', '19:33:13', 'Clinic', 'ผู้ป่วย HN 162320 และ HN 32706 แพทย์นัดมาคัดกรองเบาหวานกินน้ำตาล 75 กรัม หลังเจาะเลือดพยาบาล OPD ได้ให้ไปเบิกน้ำตาลที่ห้องยาซึ่งเป็นเวลาไล่เลี่ยกัน หลังจากนั้นมายื่นเพื่อกินน้ำตาลที่ OPD พยาบาล OPD พบว่าห้องยาปริ้นสติกเกอร์ยามาเป็นของ HN 162320 ทั่ง 2 ชุด ', '- เช็คความถูกต้องให้ผู้ป่วยก่อนให้ผู้ป่วยกินน้ำตาล ', 'C', '01-2026', 'P', 1, 1, 0, 0, 1, 'U4', 'PTC', 'U4', 98, 6, 46, 176, 444, 'C', '2026-02-04', '2026-03-19', '', 'Y', 'PTC', '1900500049611', 'PTC', '', '', 'open', '96749-s__127295490.jpg', 'OPD');
INSERT INTO `dc_report` VALUES (12944, 69, 2, 24, 2, 'มายื่นบัตรทำแผล 15.46 น.', '2026-01-29', '15:46:00', '2026-01-30', '08:59:48', 'Clinic', 'วันที่30/1/69 เวลา 15.46 ญาตินายมะเย็ง เขตเทพาติดต่อยื่นบัตรกับเจ้าหน้าที่ห้องบัตรที่ห้องฉุกเฉิน เนื่องจากไปยื่นทำแผลที่ห้องทำแผลแล้ว เจ้าหน้าที่แจ้งปิดบัตรแล้ว ให้มาติดต่อทำแผลที่ห้องฉุกเฉิน เจ้าหน้าที่ห้องบัตรแจ้งญาติไป แนะนำรอทำแผลหลังสี่โมง และมีค่าทำเนียมนอกเวลา100 บ. ญาติเลยไม่พอใจ ทำไมต้องรอ ในเมื่อมาก่อนสี่โมงเย็น ไปทางโน้นแล้วก็ไม่รับ มาทางอีอาก็ให้รอหลังสี่โมงอีก มาครั้งก่อนก็รอหลังสี่โมงด้วย เจ้าหน้าที่ห้องบัตรเลยแจ้งไปว่า พยาบาลขณะนี้กำลังเคลียร์คนไข้ฉุกเฉินอยู่ค่ะ เดี่ยวให้ญาตินั่งรอก่อนน่ะค่ะ ญาติไม่พอใจ เลยขอบัตรประชาชนกลับ และพาคนไข้ขึ้นรถกลับบ้าน ', 'อธิบายด้วยน้ำเสียงนุ่มนวล เพื่อให้ญาติไม่มีอารมณื รุนแรงมากเกินไป และรายงานเหตุการณ์ที่เกิดขึ้นให้หัวหน้าทราบ', 'B', '01-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 91, 5, NULL, NULL, NULL, 'B', '2026-02-04', NULL, NULL, 'Y', NULL, '1900500108471', 'admin1', NULL, NULL, NULL, '60139-', 'OPD');
