INSERT INTO `dc_report` VALUES (12953, 69, 2, 12, 50, 'จำนวนเงินค่ารักษาพยาบาลไม่ตรงกับใบแสดงรายการค่าใช้จ่าย', '2026-02-02', '15:00:00', '2026-02-05', '09:23:09', 'Non_Clinic', 'วันที่ 2 ก.พ.69 เวลาประมาณ 15.00 น.  คนไข้ AN680006216 มาจ่ายเงินค่าค้างชำระ ของวันที่ 4/11/2568  ค่ารักษา 15,107 บาท  วันที่ 4/11/68 คนไข้จ่ายไแล้ว 400 บาท  วันนี้ (2/2/69) มาจ่ายส่วนที่เหลือ  คนไข้จ่ายเรียบร้อยแล้วและได้กลับบ้านไป  แต่เวลาประมาณ 18.00 น.  กลับมาเพื่อขอใบแสดงรายการค่าใช้จ่ายที่ได้จ่ายเงินไป  จนท.ได้ตรวจสอบพบใบเสร็จ 1 ใบ จำนวนเงินที่ออกใบเสร็จ กับใบแสดงรายการค่าใช้จ่ายไม่ตรงกัน', 'แจ้งงาน IT ตรวจสอบจำนวนเงินค่ารักษาพยาบาล', '3', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 19, 3, NULL, NULL, NULL, '3', '2026-02-14', NULL, NULL, 'Y', NULL, '5600290010204', 'admin1', NULL, NULL, NULL, '70740-', 'IPD');
INSERT INTO `dc_report` VALUES (12954, 69, 2, 30, 24, 'ตรวจHIVในคนไทยมีเลข13หลักสิทธิ์ประกันสังคม', '2026-02-05', '10:49:00', '2026-02-05', '10:30:57', 'Clinic-Dx', 'ทางคลินิกARV ได้รับการประสานจากOPDเรื่องส่งผู้รับบริการมารับการปรึกษาเรื่องการบอกผลการการติดเชื้อแก่คู่ และการรับยาต้านต่อเนื่อง ทางคลินิกได้ให้สามีของผู้รับบริการไปส่งชื่อที่ห้องบัตรเพื่อรับบริการเจาะตรวจหาการติดเชื้อHIV แต่ห้องบัตรแจ้งกับผู้รับบริการว่าส่งตรวจไม่ได้ ถ้าจะตรวจต้องสำรองจ่าย จึงไม่ได้รับบริการ ซึ่งสิทธิคนไทยที่มีเลข13หลักสามารถตรวจฟรีปีละ2ครั้งทุกสิทธิ', 'ให้คำแนะนำผู้รับบริการ ให้ไปรับการตรวจพร้อมคู่ที่รพ.สงขลาตามสิทธิ รายงานรองหัวหน้างาน ', 'D', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 20, 3, NULL, NULL, NULL, 'C', '2026-02-14', NULL, NULL, 'Y', NULL, '3900500222149', 'admin1', NULL, NULL, NULL, '36604-', 'OPD');
