INSERT INTO `dc_report` VALUES (12967, 69, 2, 6, 47, 'ได้กลื่นควันเผาขยะ บริเวณฝั่งชายหอผู้่ปวยใน1', '2026-02-07', '22:50:00', '2026-02-07', '22:52:43', 'Non_Clinic', 'เวลา 22.50 น \r\nขณะเดินปฏฺิบัติงานในหอผู้ป่วยฝั่งชาย ได้กลิ่นเผาขยะ  ขณะที่ในหอผู้ป่วย 1  มีผู้ปวย admit ด้วยโรค  COPD Pneumonia  ผู้ป่วยและญาติแจ้งได้กลิ่นเผาขยะด้วย บางคนมีรู้สึกมึนศรีษะ  หายใจไม่สะดวก \r\nสำรวจในตึกและบริเวณรอบๆ ตึก ไม่มีแหล่งกำเนิดควัน\r\nสอบถามหอผู้ป่วยใน 2 ได้กลิ่นควันด้วย แต่ยังไม่รู้ที่มา  และได้แจ้งสอบถามป้อมยามให้ตรวจสอบ', 'จากก่ารสอบถาม คิดว่า ควันน่าจะมาจากนอก รพ  ที่บริเวณข้างทิศใต้โรงพยาบาล มีโรงงานไม้  \r\nและบ้านประชาชน \r\n', '3', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'ENV', NULL, 37, 1, NULL, NULL, NULL, '3', '2026-02-14', NULL, NULL, 'Y', NULL, '1900500021082', 'admin1', NULL, NULL, NULL, '99825-', 'IPD');
INSERT INTO `dc_report` VALUES (12968, 69, 2, 3, 35, 'เจาะเลือดผู้ป่วยซ้ำ', '2026-02-08', '20:05:00', '2026-02-08', '21:08:48', 'Clinic-Dx', 'case dizzeness  HN 131345  แพทย์order lab  CBC cr elyte  พยาบาลเจาะ lab tube เขียวเล็กเนื่องจากเลือดออกน้อย แต่ได้ถึงขีดที่กำหนด  แต่ห้องlab แจ้ง มาว่าให้เจาะ lab ใหม่ เนื่องจากเลือดไม่พอ  ทำให้ต้องเจาะเลือดผู้ป่วยซ้ำ ', 'แจ้งผู้ป่วยทราบเจาะเลือดซ้ำ \r\n', 'C', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 94, 5, NULL, NULL, NULL, 'C', '2026-02-14', NULL, NULL, 'Y', NULL, '1900500041156', 'admin1', NULL, NULL, NULL, '49303-', 'OPD');
INSERT INTO `dc_report` VALUES (12969, 69, 2, 42, 2, 'ผู้ป่วยเป็นลมขณะเปลี่ยนเสื้อก่อนเอกซเรย์', '2026-02-09', '10:45:00', '2026-02-09', '10:41:23', 'Clinic', 'ขณะให้ผู้ป่วยเปลี่ยนเสื้อก่อนเอกซเรย์ ผู้ป่วยหน้ามืด เป็นลม', 'เรียกพยาบาล OPD  เปลพร้อมรถนอน ปฐมพยาบาลที่ห้องเอกซเรย์ ก่อนส่งสังเกตุอาการที่ OPD', '0', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 95, 5, NULL, NULL, NULL, 'C', '2026-02-14', NULL, NULL, 'Y', NULL, '3900500019866', 'admin1', NULL, NULL, NULL, '99964-', 'OPD');
INSERT INTO `dc_report` VALUES (12970, 69, 2, 15, 40, 'ส่งทำอนุมัติเดินทางไปราชการ', '2026-02-09', '16:00:00', '2026-02-09', '16:29:19', 'Non_Clinic', 'วันที่ 9 กุมภาพันธ์  2569  เวลา16.00น.  งานแผนงานนและยุทธ์ได้รับหนังสือบันทึกข้อความขออนุมัติเดินทางไปราชการ ของกลุ่มงานเวชกรรมฟื้นฟู จำนวน 2 คน คือ นางสาวนูรอาซีย๊ะห์ อับดุลเลาะห์ และนางสาวเนตรนภา ได้ส่งหนังสือขออนุมัติเดินทางไปราชการ ผ่านงานแผนงานและยุทธ์ ในเวลา16.00น. ซึ่งในเนื้อความระบุวันที่ประชุม วันที่10  กุมภาพันธ์ 2569 ณ อำเภอหาดใหญ่ จ.สงขลา งานแผนฯต้องดำเนินการอย่างเร่งด่วน โดยประสานกับงานธุรการ งานบริหาร เพื่อดำเนินการทำหนังสืออนุมัติเดินทางไปราชการ เพื่อเสนอผู้บริหารในลำดับต่อ ตามแนวทางปฏิบัติและได้มีการแจ้งให้ทราบโดยทั่วกันว่าการเดินทางไปราชการควรดำเนินการอนัมติล่วงหน้าอย่างน้อย 7 วันหรือ กรณีเร่งด่วนอย่างน้อย 3 วัน ', 'ประสานกับงานธุรการ งานบริหาร เพื่อดำเนินการทำหนังสืออนุมัติเดินทางไปราชการ เพื่อเสนอผู้บริหารในลำดับต่อ (ในเวลา16.07น.)', '1', '02-2026', 'P', 1, 1, 0, 0, 4, 'U1', 'RM', 'U1', 30, 8, 92, 955, 0, '2', '2026-02-14', '2026-02-14', '', 'Y', 'rm', '3900500219130', 'rm', '', '', '', '82384-1.jpg', 'N');
INSERT INTO `dc_report` VALUES (12971, 69, 2, 15, 40, 'ส่งทำอนุมัติเดินทางไปราชการ', '2026-02-09', '16:00:00', '2026-02-09', '16:32:57', 'Clinic', 'วันที่ 9 กุมภาพันธ์  2569  เวลา16.00น.  งานแผนงานนและยุทธ์ได้รับหนังสือบันทึกข้อความขออนุมัติเดินทางไปราชการ ของกลุ่มงานเวชกรรมฟื้นฟู จำนวน 2 คน คือ นางสาวนูรอาซีย๊ะห์ อับดุลเลาะห์ และนางสาวเนตรนภา ชุมประมาณ ได้ส่งหนังสือขออนุมัติเดินทางไปราชการ ผ่านงานแผนงานและยุทธ์ ในเวลา16.00น. ซึ่งในเนื้อความระบุวันที่ประชุม วันที่10  กุมภาพันธ์ 2569 ณ อำเภอหาดใหญ่ จ.สงขลา หนังสือแจ้งเข้าร่วมประชุม ผ่านระบบ ลงรับ ในวันที่29 มกราคม 2569  แต่ได้รับการส่งทำขออนุมัติก่อนทางไปราชการ 1 วัน และเป็นช่วงเวลาเลิกงาน 16.00น. งานแผนฯต้องดำเนินการอย่างเร่งด่วน โดยประสานกับงานธุรการ งานบริหาร เพื่อดำเนินการทำหนังสืออนุมัติเดินทางไปราชการ เพื่อเสนอผู้บริหารในลำดับต่อ ตามแนวทางปฏิบัติและได้มีการแจ้งให้ทราบโดยทั่วกันว่าการเดินทางไปราชการควรดำเนินการอนัมติล่วงหน้าอย่างน้อย 7 วันหรือ กรณีเร่งด่วนอย่างน้อย 3 วัน ', 'ประสานกับงานธุรการ งานบริหาร เพื่อดำเนินการทำหนังสืออนุมัติเดินทางไปราชการ เพื่อเสนอผู้บริหารในลำดับต่อ (ในเวลา16.07น.)', '0', '02-2026', 'P', 1, 1, 0, 0, 4, 'U1', 'RM', 'U1', 31, 8, 92, 955, 0, '2', '2026-02-14', '2026-02-14', '', 'Y', 'rm', '3900500219130', 'rm', '', '', '', '35180-เอกสารแนบ.pdf', 'N');
INSERT INTO `dc_report` VALUES (12972, 69, 2, 24, 36, 'คนไข้มารับบริการห้องทันตกรรมโวยวาย', '2026-02-10', '06:09:00', '2026-02-10', '08:30:54', 'Non_Clinic', 'วันที่10/2/69 เวลา 06.09 น.คนไข้ HN3168 นางทัศนีย์ สามะ เบอร์โทร0896565420มารอรับคิวฟันซึ่งวันนี่คิวฟันรับจำนวน15คิว แต่วันนี่มีผู้มาบริการจำนวนมากคิวฟันได้หมดแล้วจึงทำให้คนไข้ไม่พอใจ ด่าโวยวายว่ามาตั้งนานแล้วยังไม่ได้คิวฟันและถ่ายรูปเจ้าหน้าที่ที่อยู่เวรดึก', 'เจ้าหน้าที่ห้องบัตรได้อธิบายว่าไม่สามารถรับคิวเพิ่มได้และแนะนำคนให้คนไข้ไปรอติดต่อห้องฟันหลังเวลา08.00น.แต่คนไข้ก็ยังไม่พอใจ', '1', '02-2026', 'P', 1, 1, 0, 0, 1, 'U9', 'RM', 'U9', 32, 8, 115, 559, 0, '1', '2026-02-14', '2026-02-14', '', 'Y', 'rm', '1900500009112', 'rm', '', '', '', '5667-', 'OPD');
INSERT INTO `dc_report` VALUES (12973, 69, 2, 38, 38, 'deley treatment', '2026-02-09', '16:36:00', '2026-02-11', '08:41:58', 'Clinic-Dx', 'หญิงไทยอายุ 85 ปี 000007727 นางพิมพ์ คงทอง refer back for rehab เรื่อง Closed intertrochanteric  fracture of  femur   stable  type 30/1/69 ระหว่าง admit มีไข้ ตัวเหลือง และ BP drop ประมาณ 7/1/69 >> ควร Diag toxic cholangitis และ refer รพ.สงขลา 7/2/69 เพื่อ drainage ใน 24-48 hr แต่ไม่ได้ refer >> วันที่ 9/2/69 ผู้ป่วยเหลืองมากขึ้น และหายใจเหนื่อยมากขึ้น ต้องใส่ ETT +refer รพ.สงขลา ญาติผู้ป่วยเป็นพยาบาลรู้จักแพทย์ข้าวขวัญเป็นการส่วนตัว แจ้งว่าจะฟ้องรพ.     ', 'รักษาตามแผนการรักษา ให้ยาฆ๋าเชื้อและใส่ท่อช่วยหายใจ เนื่องจากผู้ป่วยหายใจเหนื่อย', 'F', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 96, 5, NULL, NULL, NULL, 'F', '2026-02-14', NULL, NULL, 'Y', NULL, '1959900394356', 'admin1', NULL, NULL, NULL, '49810-', 'IPD');
INSERT INTO `dc_report` VALUES (12974, 69, 1, 37, 37, 'จัดยาผิด', '2026-02-11', '09:25:00', '2026-02-11', '09:26:19', 'Clinic', 'HN 64392 kalimate จัด montelukast', 'จัดใหม่', 'B', '02-2026', 'P', 1, 1, 0, 0, 1, 'U4', 'PTC', 'U4', 114, 6, 46, 175, 323, 'B', '2026-02-14', '2026-03-20', '', 'Y', 'PTC ', '1909800514627', 'PTC ', '', '', 'open', '36516-', 'OPD');
INSERT INTO `dc_report` VALUES (12975, 69, 1, 35, 4, 'ติดสติกเกอร์ ผิดคน', '2026-02-11', '17:00:00', '2026-02-11', '17:53:24', 'Clinic', 'ห้องคลอดส่ง Urine ติดสติกเกอร์ชื่อ นส.นาปีซะห์ ยามิง HN 148674 สั่งรายการแลป UPCR ห้องแลปทำการรับและตรวจวิเคราะห์รายงานผลเรียบร้อยแล้ว  ทางห้องคลอดได้โทรมาสอบถามเคสผู้ป่วย ชื่อ น.ส.ซูไรณี มามะ HN 163714Urine analysis ว่าห้องแลปยังไม่ได้รับแลปเคสนี้ ห้องแลปได้ตรวจสอบแล้วไม่มี Specimen ของผู้ป่วยรายนี้  ห้องคลอดได้โทรมาแจ้งอีกครั้งว่า ได้ติดสติกเกอร์ผู้ป่วยผิดคน', 'แจ้งให้ห้องคลอดเก็บตัวอย่างใหม่  แต่ทางห้องคลอดว่าจะใช้ตัวอย่างเดิมมาแก้ไขสติกเกอร์ให้ถูกคน และได้ทำการบันทึกข้อมูลการแก้ไขที่ใช้ตัวอย่างเดิมในระบบแลปและทำการตรวจวิเคราะห์', 'B', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 97, 5, NULL, NULL, NULL, 'B', '2026-02-14', NULL, NULL, 'Y', NULL, '3960800027708', 'admin1', NULL, NULL, NULL, '94142-', 'IPD');
INSERT INTO `dc_report` VALUES (12976, 69, 1, 35, 4, 'ติดสติกเกอร์ ผิดคน', '2026-02-11', '17:00:00', '2026-02-11', '18:05:31', 'Clinic', 'ห้องคลอดส่ง Urine  ของน.ส.นาปีซะห์  ยามิง HN 148674 สั่งรายการแลป UPCR แลปได้ทำการตรวจวิเคราะห์และรายงานผลเรียบร้อย ได้โทรมาแจ้งว่าติดสติกเกอร์ผิดคน ให้มีการยกเลิกรายการแลปดังกล่าว ซึ่งตรวจไปแล้วมีการเสียค่าใช้จ่ายของเทสนั้นๆ \r\n', 'ทำการยกเลิกรายการแลปดังกล่าว เนื่องจากเป็นตัวอย่างผิดคน ', 'B', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 21, 3, NULL, NULL, NULL, 'B', '2026-02-14', NULL, NULL, 'Y', NULL, '3960800027708', 'admin1', NULL, NULL, NULL, '88025-', 'IPD');
INSERT INTO `dc_report` VALUES (12977, 69, 2, 43, 50, 'ผู้ป่วยโพสเฟสบุ๊ค วัน เดือน ปีเกิดผิด', '2026-02-08', '20:00:00', '2026-02-14', '14:04:07', 'Clinic', 'วันที่ 8 ก.พ.69 เวลา ประมาณ 20.00 น.ผู้รับบริการโพสบุ๊ค ว่า \" แมลงสาบ(ลูกมันดีที่ไม่ใช่ตัวใหญ๋555) เข้าหู...สุดๆไม่เคยพยเคนเจอ ต้องมารพ.ให้หมอเอาออกให้ถึงจะได้รู้ว่าเป็นอะไร..อัลฮัมดูลินละห์ดีที่สาบว่าเป็นอะไร...ขอบคุณน้องอ้วนที่เอาแมลงสาบออกมาได้ นามสกุลเดิมอีก วันเดือนปีเกิดผิด\"\r\nรายละเอียดตามไฟล์แนบ', '- แจ้งผู้เกี่ยวข้องทราบ\r\n- รายงานความเสี่ยง', 'B', '02-2026', 'P', 1, 1, 0, 0, 1, 'U9', 'RM', 'U9', 33, 8, 69, 239, 806, 'B', '2026-02-14', '2026-02-14', '', 'Y', 'rm', '3909700096820', 'rm', '', '', '', '13652-การระบุตัว.png', 'OPD');
INSERT INTO `dc_report` VALUES (12978, 69, 2, 43, 2, 'ผู้ป่วยโพสเฟสบุ๊ค การเรียกผู้ป่วยในการเข้ารับบริการห้องฉีดยาทำแผล', '2026-02-10', '10:57:00', '2026-02-14', '14:11:25', 'Non_Clinic', 'ผู้รับบริการโพสเฟสบุ๊คว่า \" ขนาดฉันหูดี พยาบาลเรียกสามครั้งยังไม่ได้ยิน ไปไหนมาเรียกตั้งนานแล้ว  ฉันยืนอยู่ตรงนี้ไม่ได้ไปไหนเลยค่ะ นึกในใจกูหูหนวกใช่ม่าย ก่อนโทษคนอื่น ต้องตรวจสอบตัวเองก่อน \" รายละเอียดตามไฟล์แนบ', '- แจ้งผู้เกี่ยวข้อง\r\n- รายงานความเสี่ยง', '1', '02-2026', 'P', 1, 1, 0, 0, 1, 'U9', 'RM', 'U9', 34, 8, 69, 721, 807, '1', '2026-02-14', '2026-02-14', '', 'Y', 'rm', '3909700096820', 'rm', '', '', '', '31241-ระบบการให้บริการ.jpg', 'OPD');
INSERT INTO `dc_report` VALUES (12979, 69, 2, 24, 36, 'คนไข้ทะเลาะกันเรื่องคิวฟัน', '2026-02-16', '05:50:00', '2026-02-16', '08:43:40', 'Non_Clinic', 'วันนี้ 16 กุมภาพันธ์  2569  เวลาประมาณ  05.40 น.มีคนไข้ 1 คนไปเก็บบัตรประชาชนของคนไข้เพื่อไปเรียงลำดับคิวฟัน และมีคนไข้อีก 1 คน ไม่ยอมเพราะเค้ามาเวลาตี 4 เลยเกิดการทกเถียง ด่ากัน (คนที่เก็บบัตรใช้คำพูดแรง ด่า คนอื่น แต่ไม่มีใครตอบโต้กลับ) คนที่มาตอนตี 4 เลยพูดว่านั้นเราไปเข้าแถวต่อคิว ทุกคนพร้อมใจกันไปต่อคิว ส่วนคนที่เก็บบัตรประชาชนยังโวยวายเหมือนเดิม แล้วก้ไปแทรกคิวคนอื่นจนได้คิว หลังจากนั้นถามเจ้าหน้าห้องบัตรว่า เก็บบัตรประชาชนไหม เจ้าหน้าที่ตอบว่า ไม่มีการเก็บบัตรประชาชนค่ะ', 'เจ้าหน้าที่ห้องบัตรชี้แจ้งเรื่องบัตรคิวว่าวันนี้รับได้กี่คิวตามที่หมอแจ้งไว้ และแจ้งคนไข้ที่มายื่นคิวฟันว่าตอนนี้เหลืออีกกี่คิว รับแล้วกี่คิว ส่วนคนที่ไม่ได้ให้ติดต่อห้องฟันเวลา 08.00 น.และแจ้งว่าสามารถจองคิวได้จากหมอพร้อมค่ะ', '1', '02-2026', 'S', 1, 1, 0, 0, 1, 'OK', 'RM', 'OK', 35, 8, 69, 842, 0, '1', '2026-02-18', '2026-02-21', 'ประชุมทบทวนร่วมกัน เมื่อวันที่ 19 ก.พ.68 ที่ประชุมมีมติดังนี้\r\n1. ให้ห้องทันตกรรมเปิดรับคิวให้บริการเอง โดยให้กลุ่มงานทันตะฯไปกำหนดรูปแบบในการใหบริการที่ไม่ส่งผลกระทบกับหน่วยงานอื่น\r\n2. ผู้ป่วยที่ได้บัตรคิวแล้วให้นำบัตรคิวมา visit และยืนยันตัวตนที่ห้องบัตรก่อนเข้ารับบริการ\r\n3. มอบกลุ่มงานทันตะฯและกลุ่มงานบริหารงานทั่วไปประชาสัมพันธ์การเปลี่ยนแปลงระบบดังกล่าว\r\n4. เริ่มให้บริการวันที่ 1 มีนาคม 2569 เป็นต้นไป', 'Y', 'rm', '1940300181671', '', '', '', '', '49204-', 'OPD');
INSERT INTO `dc_report` VALUES (12980, 69, 1, 24, 12, 'ยอดเงินในใบเสร็จรับเงิน ไม่ตรงกับยอดในระบบ hosxp', '2026-02-18', '02:30:00', '2026-02-18', '08:14:13', 'Non_Clinic', 'คนไข้มารับบริการด้วยอาการ มีผื่นขึ้นตามร่างกาย  ระยะเวลา 40 นาที    ก่อนมาโรงพยาบาล คนไข้ต้องสำรองจ่ายเงิน 462.75 บาท แต่ใบเสร็จรับเงินออกยอดเงิน 463 บาท ', 'ได้อธิบายคนไข้ เบื้องต้นแล้ว ว่า ใบเสร็จรับเงิน กับรายการรักษา ยอดไม่ตรงกัน ซึ่งเกิด ระบบHosxp', '4', '02-2026', 'P', 1, 0, 0, 0, 4, NULL, 'IM', NULL, 22, 3, NULL, NULL, NULL, '2', '2026-02-18', NULL, NULL, 'Y', NULL, '1900500080798', 'admin1', NULL, NULL, NULL, '51451-', 'OPD');
