INSERT INTO `dc_report` VALUES (12987, 69, 2, 6, 3, 'ไม่เปลี่ยนเสื้อผ้าผู้ป่วย Admin ก่อนเข้ามาใน ward', '2026-02-19', '11:14:00', '2026-02-19', '23:10:19', 'Non_Clinic', 'ERไม่เปลี่ยนเสื้อผ้าผู้ป่วย Admin ก่อนเข้ามาใน ward  จำนวน 4 ราย\r\nซึ่งในเวรบ่ายมีผูป่วยAdmin เข้ามาจำนวน 4 ราย ไม่ได้เปลี่ยนเสื้อผ้าทุกรายที่เข้ามา\r\nAdmin ในเวรบ่าย', '- ได้เปลี่ยนเสื้อผ้าให้ผู้ป่วยทุกรายที่เข้ามา Admin ทุกราย', '1', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 99, 5, NULL, NULL, NULL, 'B', '2026-03-07', NULL, NULL, 'Y', NULL, '1900500046492', 'admin1', NULL, NULL, NULL, '18446-', 'IPD');
