INSERT INTO `dc_report` VALUES (12989, 69, 2, 42, 44, 'ผู้ป่วยฉีด contrast media เกิดผลข้งเคียง (แขนบวม)', '2026-02-19', '10:00:00', '2026-02-20', '10:08:02', 'Clinic', 'วันที่ 19 ก.พ.69 ผู้ป่วย admit   000004922  อายุ 58 ปี case CA breast  มาตามนัดเพื่อ ทำ CT  Chest + whole abdomen  with contrast ขอใบส่งตัวไป รพ.หาดใหญ่ ขณะทำการฉีด โดยเปิดเส้นใช้เข็มเบอร์18ข้างซ้าย และมีการทดสอบเส้น โดยการดันน้ำเกลือด้วยความเร็ว10 cc ไหลปกติ และได้มีการฉีด contrast เข้าเส้นประมาณ 60 cc พบว่าแขนข้างที่ฉีดบริเวณใต้ข้อพับผู้ป่วยบวม  จึงทำการหยุดฉีดและรายงานแพทย์เจ้าของไข้ \r\n', 'การแก้ไขเบื้องต้น \r\n1.แพทย์พิจารณาให้เปลี่ยนเส้นเพื่อฉีดอีกครั้ง\r\n2.ก่อนฉีดให้มีการทดสอบเส้นโดยการดันน้ำเกลือด้วยความเร็ว 10 cc ต่อ 2วินาที \r\n3.ประคบเย็นตรงบริเวณที่บวมและติดตามอาการบวม', 'D', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 101, 5, NULL, NULL, NULL, 'D', '2026-03-07', NULL, NULL, 'Y', NULL, '3909700096820', 'admin1', NULL, NULL, NULL, '70643-', 'IPD');
INSERT INTO `dc_report` VALUES (12990, 69, 1, 8, 7, 'ไซริ่งพร้อมเข็มพร้อมใช้งาน', '2026-02-17', '13:30:00', '2026-02-20', '14:34:44', 'Clinic', 'ขณะเอาเครื่่องเครื่องมือติดเชื้อของวอดมาล้างปรากฎว่าได้มีไซริ่งพร้อมเข็มติดมากับเทรจำนวน 3 อัน', 'แจ้งหัวหน้าทราบ', '0', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IC', NULL, 8, 7, NULL, NULL, NULL, '1', '2026-03-07', NULL, NULL, 'Y', NULL, '5900500001319', 'admin1', NULL, NULL, NULL, '1953-', 'IPD');
INSERT INTO `dc_report` VALUES (12991, 69, 2, 6, 44, 'ผู้ป่วยมีภาวะ Hypoglycemia', '2026-02-20', '11:30:00', '2026-02-20', '17:14:33', 'Clinic-Dx', 'วันที่ 20/2/69 เวลา 11.15  น. case ผู้ป่วยชายไทย อายุ  42 ปี HN:000069141 AN:690001016  Dx.Cellulitis Lt.hand ,U/D DM   เวลา  11.15  น. เจาะ DTX premeal ac เที่ยง =61 mg/dl ผู้ป่วยไม่มีอาการเหงื่ออกตัวชื้น ไม่มีอาการใจสั่น รายงานแพทย์เวรทราบ ให้ 15 g glucose  ตาม DTX อีก 1 hr. เวลา 12.30 น. DTX=165 mg% \r\n(order continuation แพทย์เดิม มี Mixtard 16-0-12 u sc ac ,MFM 500 1*2 Opc )', '1. ประเมินระดับความรู้สึกตัว และวัด V/S \r\n2.รายงานแพทย์เวรทราบ\r\n3. แพทย์ hold Mixtard 16-0-12 u sc ', 'E', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 102, 5, NULL, NULL, NULL, 'E', '2026-03-07', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '55428-', 'IPD');
INSERT INTO `dc_report` VALUES (12992, 69, 2, 6, 44, 'hypoglycemia', '2026-02-20', '01:30:00', '2026-02-20', '19:45:42', 'Clinic-Dx', 'ผู้ป่วยชาย อายุ74 ปี HN 72870 DX.simple hyperglycemia ,hypoglycemia, AKI, old lacunar intarction ,myoclonus \r\n เรื่องDm วันที่19/2/69 order   มีฉีด mixtard 24-0-16 u +notify RI scaleทุกรอบ\r\nวันที่19/2/69 DTX hs 226 mg% พยาบาลให้ NPH 4 u hs ไม่ได้รายงานแพทย์ วันที่20/2/69 เวลา 1.30 น มีhypoglycemia DTX 70 mg% ', 'รายงานแพทย์ทราบ ให้Glucose 15 gm O DTX ซ้ำ93 mg%', 'E', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 103, 5, NULL, NULL, NULL, 'E', '2026-03-07', NULL, NULL, 'Y', NULL, '1900500039607', 'admin1', NULL, NULL, NULL, '14950-', 'IPD');
INSERT INTO `dc_report` VALUES (12993, 69, 2, 37, 44, 'ยา visit OPD หายไป เนื่องจากผู้ป่วย Admit ', '2026-02-20', '17:30:00', '2026-02-20', '21:05:08', 'Clinic', 'HN 30713 วันที่ 20/2/69 ผป.มี visit OPD รับยา Morphine และยาอื่นๆ โดยรับยาไปแล้ว หลังจากนั้นมี Visit admit แต่เมื่อดูประวัติยา พบว่า ประวัติยา visit OPD หายไป โดยรวมไปอยู่ใน visit IPD (ยาของ OPD กลับไปถึงบ้านผู้ป่วยแล้ว) \r\nเมื่อสอบถามพยาบาล ER พยาบาลแจ้งว่าทำตามขั้นตอนปกติ ระบบดึงแบบ Auto จึงไม่แน่ใจว่าปัญหาอยู่ที่ระบบหรือไม่', '-', 'B', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 104, 5, NULL, NULL, NULL, 'B', '2026-03-07', NULL, NULL, 'Y', NULL, '1969900313984', 'admin1', NULL, NULL, NULL, '41774-', 'IPD');
INSERT INTO `dc_report` VALUES (12994, 69, 2, 6, 44, 'ผู้ป่วยมีภาวะ  hypoglycemia', '2026-02-18', '22:30:00', '2026-02-21', '04:21:55', 'Clinic-Dx', 'ชายไทย อายุ 74 ปี HN 72870  admit ด้วย \r\nDX Simple hyperglycemia AKI old lacuna infartion  \r\nติดตาม order  DTX premeal  hs  มี mixtard 30-0-20 u sc  + RI scale\r\nเกิดเหตุ วันที่18/2/68  \r\n7.00 น  DTX 469  mg% ได้รับ  mixtard 22 u  กินข้าวต้มได้ \r\n11.00 DTX  396    mg% ได้รับ  RI 8 usc กินข้าวได้\r\n15.00  DTX 360 mg mixtard 20 u + RI 8 U sc กินข้่าวได้\r\n20.00  DTX 133 \r\n22.30 น ญาติแจ้ง   มีอาการเหงื่อออกตัวชื้น  ไม่ใจสั่น มีภาวะน้ำตาลต่ำ DTX 60 mg% \r\n', 'ติดตาม DTX \r\nรายงานแพทย์ทราบ ให้ 15 g glucose O ติดตาม น้ำตาลซ้ำ\r\nและ hold mixtard', 'D', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 105, 5, NULL, NULL, NULL, 'D', '2026-03-07', NULL, NULL, 'Y', NULL, '1900500021082', 'admin1', NULL, NULL, NULL, '75041-', 'IPD');
