INSERT INTO `dc_report` VALUES (12997, 69, 2, 37, 7, 'ใส่ใบ Med reconcile ผิดคน ', '2026-02-22', '18:13:00', '2026-02-22', '18:33:04', 'Clinic', 'วันนี้ ไปเปิด chart ของผู้ป่วย เกศินี ็HN 785 ชื่อ  แต่ ไปเจอ ใบ Med reconcile ของ อรุณี  HN 16354 เสียบใน chart แทน ***  ซึ่งผู้ป่วย HN  16354  นี้ ก่อนเกิดเหตุ 30 นาที ห้องยาได้โทรไป ฝากพยาบาลว่า ช่วยแจ้งเวรเช้า เตือนแพทย์ สั่งยาเดิม ตาม ใบMed Recocnile ที่ส่งเข้าไป ตอนเที่ยง ให้หน่อย พยาบาลรับทราบ แต่มาทราบภายหลังว่า ใส่ ใบ Med reconcile ผิดคน ', ' เมื่อพบความคลาดเคลื่อน ได้แจ้งพยาบาล ใน เวร ทันที  แต่พบว่า น้องพยาบาล ไม่ได้มีท่าที แสดงความสนใจ  เรื่องความผิดพลาดนี้ บอกเพียงว่า ไม่รู้ใครทำ และทำงานต่อ ( อาจจะยุ่ง)   ', 'B', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 107, 5, NULL, NULL, NULL, 'B', '2026-03-07', NULL, NULL, 'Y', NULL, '3959900044394', 'admin1', NULL, NULL, NULL, '1723-', 'IPD');
INSERT INTO `dc_report` VALUES (12998, 69, 2, 37, 52, 'คัดลอกวิธีใช้ยาผิด และ คัดลอกไม่ครบ ', '2026-02-22', '15:00:00', '2026-02-22', '18:48:11', 'Clinic', 'ผู้ป่วยฟอกไต แพทย์สั่ง Vit D 20,000 IU 2 cap ทุกเสาร์ แต่ พยาบาล คัดลอกเป็น Manidipine 2 cap ทุกเสาร์ // ส่วน Vit D ไม่ได้คัดลอก ', 'แจ้ง พยาบาล พยาบาลแก้ไข พิมพ์วิธีใช้ Manidipine เป็น 1*1 pc/30 cap และ Vit D 20,000 IU 2 cap ทุกเสาร์ ', 'B', '02-2026', 'P', 1, 1, 0, 0, 1, 'PTC', 'PTC', 'PTC', 119, 6, 46, 171, 313, 'B', '2026-03-07', '2026-03-20', '', 'Y', 'PTC ', '3959900044394', 'PTC ', '', '', 'open', '99857-', 'OPD');
INSERT INTO `dc_report` VALUES (12999, 69, 2, 6, 44, 'ีื๊ีunplan refer ', '2026-02-22', '16:30:00', '2026-02-23', '11:33:28', 'Clinic', 'ชายไทย อายุ 67 ปี HN 28393 AN690001040\r\n visit 19/2/69 เวลา 21.33 น \r\ncc:ปวดหลังบริเวณเอวข้างซ้ายมาก  1 วันก่อน\r\n PI 7วันก่อนมา มีปวดบั้นเอว ปัสสาวะปกติ ไม่มี แสบขัด ออกกระปริดกระปรอย **ประวัติเป็นเคยสลายนิ่วรพ.มอ.ประมาณ 10 ปี -- \r\n1 วันก่อนมา มีอการปวดหลังบริเวณเอวข้างซ้ายมากขึ้นจึงมารพ.   วันนี้จึงมา รพ.เทพา\r\n03 ประวัติโรคประจำตัว ( ) ไม่มี  ( /) มีระบุ...DM , DLP , CKD stage 3   รับการรักษาที่.เทพา .. รับประทานยาสม่ำเสมอ\r\n04 ประวัติการเจ็บป่วยในอดีต/การผ่าตัด (/ ) ไม่มี ( ) มีระบุ... DTX 126 mg% \r\n\r\nDX. RC r/o renal mass \r\nadmit ward 1 วันที่19/2/69 เวลา 23.48 น  ให้  IVF control pain  ตาม   CT   KUB  20/2/69 ผล เป็น Enlarge contour  Lt kidney c multiple stone DDx xanthogranulomatous pyelonephritis or renal tumor  \r\nระหว่าง admit  ปวดบั้วเอว ซ้าย 19/2/69 7.00 น ได้รับ Hyosine 1 amp v   \r\n ได้ tramol 1 amp v รู้สึกตัวดี ไม่ปวดหัว เดินไม่ค่อยไหว   ทำกิจวัตรบนเตียงส่วนใหญ่\r\n วันที่ 22/2/69  13.20 น  บอกมีอาการปวดลดลงแล้ว  มีอาการอ่อนแรงด้านขวา ชา มากขึ้น \r\nแต่บอกว่ามีอาการมา  3 วันแล้ว แพทย์ดูอาการ NIHSS 3 คะแนน  DDx stroke non fast     E4V5M6 pupil 2.5 mmRTBE  moter power   LT V all   RT III * all นั่งตรงได้ \r\nBT 36.8 c PR 70 /min RR 20 /min BP 169/93 mmHg  \r\nส่ง   CT brain non contact   \r\nผลออก 16.00 น ผล CT >> Multiple hyperrndense lesion c surrounding vasogenic brain edema at rt frontal and bilateral parietal  \r\nแพทย์ดูผลแพทย์  advice ญาติ  accept  ประสานส่งต่อ รพ สงขลา \r\nIMP Hemorrhagic brain metastasis  c RC R/O CA lt kidney  \r\n\r\nส่งต่อ เวลา  16.30 น\r\n', 'ประเมิน V/S BEfast  รายงานแพทย์   และแนะนำญาติ  accept', 'E', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 108, 5, NULL, NULL, NULL, 'E', '2026-03-07', NULL, NULL, 'Y', NULL, '1900500021082', 'admin1', NULL, NULL, NULL, '60046-', 'IPD');
INSERT INTO `dc_report` VALUES (13000, 69, 2, 3, 11, 'ผู้ป่วยไม่พอใจ เมื่อให้ร่วมจ่ายค่ารถแอมบูแลนซ์', '2026-02-25', '04:00:00', '2026-02-25', '10:09:55', 'Non_Clinic', 'เวลา 00.50 น. HN 10769 ผู้ป่วยหญิงอายุ 53 ปี สิทธิ์เบิกได้ เข้ารับบริการ ที่ห้องฉุกเฉินด้วยอาการ 7 hr ก่อนมา รพ. ตอนนอนแน่นหน้าอกตรงกลางไม่มีร้าวไปที่อื่น หายใจไม่สะดวก  ไม่ไข้ ไม่ไอ ประวัติโรคหัวใจ รักษา รพ.มอ.ตลอดมีนัดรักษาต่อเนื่อง อาการผู้ป่วยหายใจเหนื่อย 28 ครั้ง/นาที lung crepitation both lungs EKG AF rate 141 bpm CXR แardiomegaly +cephalization advice synchronize cardioversion  ผู้ป่วย denied ขอให้ยา cordarone แทน และ on HFNC   advice หากหายใจเหนื่อยมากขึ้น ยินยอม ETT/CPR ** ญาติและผู้ป่วยต้องการให้ส่งตัวไป มอ. consult รพ.มอ. เตียงเต็มมาก ไม่สามารถรับผู้ป่วยได้ แต่ให้ต่อคิวรอเรียกหากเตียงว่าง  คุยกับผู้ป่วย สามีและลูกชาย ยืนยันจะไปรพ.มอ.ไม่ยินยอมไปรพ.สงขลา และจะไปเอง หาก รพ.ไม่ส่งตัว แพทย์เวร advice แล้วว่ามีปัญหาเรื่องหัวใจเต้นผิดจังหวะและน้ำท่วมปอด หากไปเองมีโอกาสหายใจเหนื่อยมากขึ้นหรือเสียชีวิต >> ลูกชายและสามีรับทราบ แพทย์เวรโทรแจ้งศูนย์รีเฟอร์รพ.มอ.อีกรอบแล้ว ตอนนี้ไม่มีเตียงจริงๆ  ญาติผู้ป่วยก็ยังยืนยันจะไป ม.อ. พยาบาลได้ติดต่อรถกู้ชีพของ อบต.เทพา ติดต่อนายกเพื่อขอเอารถออกไม่ได้ พยาบาลคำนึงความปลอดภัยของผู้ป่วยหาก จะไป มอ. โดยเดินทางไปเอง **จึงเสนอแนวทาง ให้รถ แอมบูแลนซ์ ของรพ. มีพยาบาลนำส่ง และเปลี่ยนถ่ายเป็นรถส่วนตัว ที่ไกล้ รพ.มอ.มากที่สุด โดยขอให้ร่วมจ่ายค่ารถ **สามีผู้ป่วยไม่พอใจ อ้างว่า รอบที่แล้ว ส่งต่อมอ.รับและมีรถไปส่งไม่ต้องจ่ายเงิน รอบนี้ทำไมต้องจ่าย และไม่ยินยอมจ่าย และยืนยันจะเดินทางโดยรถส่วนตัวไปเอง  จึงให้เซ็นต์ปฏิเสธการรักษา+พิมพ์ประวัติจากรพ.เทพาให้ไป', '...ไม่มีระเบียบปฏิบัติที่เป็นลายลักษณ์อักษร ที่ให้ผู้ปฏิบัติใช้เป็นแนวทางที่ชัดเจนและอ้างถึงได้ ในการให้คำแนะนำผู้ป่วยและญาติ ในการร่วมจ่ายค่ารถแอมบูแล้น์ ในกรณีใดบ้าง', '1', '02-2026', 'P', 1, 1, 0, 0, 4, 'U9', 'RM', 'U9', 37, 8, 69, 494, 810, '1', '2026-03-07', '2026-03-17', '', 'Y', 'rm', '3900900184376', 'rm', '', '', '', '17368-', 'OPD');
