INSERT INTO `dc_report` VALUES (13003, 69, 2, 36, 36, 'เลือดไหลไม่หยุด หลังถอนฟัน ในผู้ป่วยได้รับยา warfarin', '2026-02-09', '14:00:00', '2026-02-26', '14:52:27', 'Clinic', 'ผู้ป่วยเพศหญิง HN 000088966 อายุ 59 visit วันที่ 9/2/2569 เวลา 8:33:25น.\r\nCC: มาตามนัดถอนฟันบน ฟันแตกมา 10 เดือน \r\nPI: ฟันกรามบนด้านขวาซี่ที่ 2 โยกมาก มีเลือดซึมที่เหงือก เป็นๆหายๆ ปัจจุบันไม่มีอาการปวดใดๆ มีโรคประจำตัวเป็น ลิ้นหัวใจรั่ว เคยได้รับการผ่าตัดใส่ลิ้นหัวใจเทียมมาแล้ว 2 ครั้ง ครั้งล่าสุดเมื่อ 3 ปีที่แล้ว รักษาอยู่ที่ รพ.จุฬา ทานยา Warfarin วันละ 5 mg\r\nAt OPD 07.30น. ส่งตรวจ PT INR และ premed amoxicillin 500 mg 4 tabs ก่่อนทำหัตถการ 30 นาที \r\nAt. ทันตกรรม 08.40 ผลตรวจ INR: 1.2, PT 14.7วินาที \r\nGA: Good conscious\r\nE/O : WNL\r\nI/O :17 Sound tooth W/ 3 mobility\r\n(....NA....ve to exploration, ...NA.....ve to air blow, ....+..... ve to percussion, etc........)\r\nDx : 17 Chronic periodontitis\r\nTx: 17 = LA 2% Lidocaine with epi. 1:100,000 ,1.8 ml, Ext, Curette, bite gauze, hemostasis, POIG \r\nAt. ทันตกรรม 14.00น. ผู้ป่วยกลับมา มีเลือดซึมที่แผลตลอดเวลา\r\nTx: 17 = LA 2% Lidocaine with epi. 1:100,000 ,1.8 ml, Curette, IRR W/ NSS, Applied surgicel, suture W/ BS 1 stitch, Bite gauze, Observe 1 ชม. เลือดหยุดไหลดี\r\n', 'ทำแผลใหม่ ใส่วัสดุห้ามเลือด และเย็บแผล\r\nTx: 17 = LA 2% Lidocaine with epi. 1:100,000 ,1.8 ml, Curette, IRR W/ NSS, Applied surgicel, suture W/ BS 1 stitch, Bite gauze, Observe 1 ชม. เลือดหยุดไหลดี\r\n', 'E', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 109, 5, NULL, NULL, NULL, 'E', '2026-03-07', NULL, NULL, 'Y', NULL, '1900400056925', 'admin1', NULL, NULL, NULL, '27937-', 'OPD');
INSERT INTO `dc_report` VALUES (13004, 69, 1, 2, 2, 'ปฏิเสธ Admit ', '2026-02-26', '12:05:00', '2026-02-26', '15:40:48', 'Clinic', ' HN 49952  ประวัติ  3 วัน  ก่อนมารพ.  ปวดบวมแดงเข่าซ้าย  ร้อนๆ   ไม่มีตุ่มน้ำใส  มีไข้  << Dx. Cellulitis   เเพทย์plan admit ผู้ป่วยdenied  จึงให้ฉีดยา Cef-3 * 3 วัน +f/u  เนื่องจากมารดาติดอบรม ทำให้ไม่มีญาติมาเฝ้า', '-เขียนใบปฏิเสธการรักษา \r\n- เเนะนำ หากมีอาการผิดปกติให้มารพ.', 'A', '02-2026', 'P', 1, 0, 0, 0, 10, NULL, 'PCT', NULL, 110, 5, NULL, NULL, NULL, 'A', '2026-03-07', NULL, NULL, 'Y', NULL, '1940700117083', 'admin1', NULL, NULL, NULL, '91192-', 'OPD');
INSERT INTO `dc_report` VALUES (13005, 69, 1, 2, 54, 'ปฏิเสธ Admit ', '2026-02-26', '08:48:00', '2026-02-26', '15:46:25', 'Clinic-Dx', 'HN 118347 case Sever depressive episode without psychotic symptoms มาติดตามอาการหลังจำหน่าย ไม่มีหูแว่ว ไม่มีภาพหลอน เบื่ออาหาร นอนหลับไม่สนิท  << เเพทย์ plan \r\nadmit ผู้ป่วยปฏิเสธ   เนื่องจากต้องดูเเลคนที่บ้าน  ไม่มีคนเฝ้า --> f/u 2 wk  + refer opd psychi SKH  ', '-ให้ผู้ป่วยเซ็นใบปฏิเสธการรักษา\r\n', 'A', '02-2026', 'P', 1, 0, 0, 0, 10, NULL, 'PCT', NULL, 111, 5, NULL, NULL, NULL, 'A', '2026-03-07', NULL, NULL, 'Y', NULL, '1940700117083', 'admin1', NULL, NULL, NULL, '89584-', 'OPD');
INSERT INTO `dc_report` VALUES (13006, 69, 1, 2, 38, 'order  ยาฉีด Epokine ไม่ตรงกับ dose ยาที่รพ. สงขลาสั่ง', '2026-02-26', '14:40:00', '2026-02-26', '16:32:49', 'Clinic', 'ผู้ป่วย HN 68841 (CKD stage 4 ) มาพบแพทย์ตามใบนัดฉีดยา รพ.  สงขลา \r\nแพทย์ รพ. เทพา มี order สั่งยาฉีด ดังไฟล์แนบ \r\nซึ่งผ่านพยบ. หลังพบแพทย์ OPD  > เภสัชกร > และสุดท้ายมาเจอ พยบ. ห้องฉีดยา/ ทำแผล  check  order  ทวนสอบ ยา Epokine พบว่า  order  dose ยาไม่ตรงกับใบนัด รพ. สงขลา \r\n', 'รายงาน\r\n1.แพทย์เจ้าของเคสทราบ แก้ไข  order ยา \r\n2.แจ้งพยบ. หลังพบแพทย์เพื่อตรวจสอบความถูกต้อง order ก่อนส่งไปยังจุดบริการต่อไป \r\n3.แจ้งเภสัชกร เพื่อขอ sticker ยาใหม่ \r\n4. ทวนสอบความถูกต้องซ้ำอีกครั้งก่อนฉีดยาให้ผุ้ป่วย ', 'B', '02-2026', 'P', 1, 1, 0, 0, 8, 'U5', 'PTC', 'U5', 122, 6, 46, 172, 298, 'B', '2026-03-07', '2026-03-20', '', 'Y', 'PTC ', '1959900110234', 'PTC ', '', '', 'open', '43746-ไฟล์แนบความเสี่ยงวันที่-26-2-69.jpg', 'OPD');
INSERT INTO `dc_report` VALUES (13007, 69, 2, 3, 26, 'ติดต่อจนท.ไม่ได้  ', '2026-02-28', '01:28:00', '2026-02-28', '01:53:06', 'Clinic', ' at  00.33 มีผู้ป่วยโดนหนูกัด มา แพทย์ order ยากิน+.ใบนัด กลับบ้าน  เครื่องปริ้น สติ้กเกอร์ยา ปริ้นท์ ไม่ออก  at  01.28 โทรหาจนท. IC  5  ครั้ง ไม่รับสาย ', 'พยบ.แจ้งผู้ป่วยรับทราบ ให้มารับยาพรุ่งนี้ และออกบัตรนัดโดยเขียนแทน ', 'C', '02-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 23, 3, NULL, NULL, NULL, 'C', '2026-03-07', NULL, NULL, 'Y', NULL, '1900500041156', 'admin1', NULL, NULL, NULL, '82501-', 'OPD');
INSERT INTO `dc_report` VALUES (13008, 69, 2, 3, 44, 'ผู้ป่วย STF ไม่ทันเวลาให้ยา rtPA ', '2026-03-01', '18:33:00', '2026-03-01', '22:22:20', 'Clinic-Dx', '- Case STF on set เวลา 14.00น.ผู้ป่วยมาถึง ER เวลา 16.53น. E4V5M6 pupil 3 minRTLBE motor power rt gr 0 all ,lt gr V all พูดไม่ชัด ลิ้นคับปาก activate SFT ตั้งแต่แรกรับ tel consult รพ.สงขลา แจ้งแล้วว่าเครื่องชั่งน้ำเปลเสีย ยืนยันให้ CT ที่รพ.เทพาก่อน --->ส่งผล CT เข้าใน line SFT ให้ refer มาให้ rtPA ที่รพ.สงขลา รถออกจากรพ.เทพาเวลา 17.21น.(TL Time 28 นาที) ถึงจุด check point ผู้ป่วยอาการทรุดลง E3V2M6 tel แจ้งพ.รพ.สงขลารับทราบ ให้ pass too unit stroke แวะ CTA ก่อน ยังยืนยันให้ rtPA เหมือนเดิม ถึงรพ.สงขลาเวลา 18.20น. แวะ CTA ก่อนเข้าตึก \r\n- 18.33น.แพทย์รพ.สงขลาแจ้งว่า Case นี้ไม่ทัน STF ให้ rtPA ไม่ได้ ---->ข้อเสนอแนะจากรพ.สงขลา ให้มีเครื่องชั่งนน.เปล', '- ', 'G', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 112, 5, NULL, NULL, NULL, 'G', '2026-03-07', NULL, NULL, 'Y', NULL, '1900400008041', 'admin1', NULL, NULL, NULL, '34718-', 'OPD');
INSERT INTO `dc_report` VALUES (13009, 69, 2, 37, 3, 'ผู้ป่วยแพ้ยา แต่ซักประวัติ บันทึกไม่ได้แพ้ยา ', '2026-03-02', '22:32:00', '2026-03-02', '22:32:52', 'Clinic', 'HN 27236 มีบัตรเตือนแพ้ยา จากรพ.จิดเวช สงขลา แต่ ER ไม่ซักประวัติ และ ขีดตรงช่องไม่แพ้ยา ', 'เภสัชพิมพ์ประวัติแพ้ยาให้ และ โทรแจ้งให้ปั้มใบ Admit .', 'B', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 113, 5, NULL, NULL, NULL, 'B', '2026-03-07', NULL, NULL, 'Y', NULL, '3959900044394', 'admin1', NULL, NULL, NULL, '60440-', 'IPD');
INSERT INTO `dc_report` VALUES (13010, 69, 2, 6, 11, 'รถฉุกเฉินนำส่งผู้ป่วยเฉี่ยวชนกับรถเก๋งขณะนำส่งผู้ป่วย', '2026-03-03', '13:00:00', '2026-03-04', '08:51:32', 'Non_Clinic', 'วันที่ 3/3/2569 เวลา เวลา 11.40  น. รถ refer รพ.เทพา ทะเบียน งย 3734 นำส่งผู้ป่วยชายไทย  อายุ 39  ปี HN:000027326 AN:690001205 แพทย์วินิจฉัย Schizophrenia with Suicidal  attemp with Amphetamine use  นำส่งรพ.จิตเวชสงขลาราชนครินทร์  มีพยาบาลนำส่ง  2  คน พขร.1 คน ผู้ป่วย 1  คน และญาติอีก 1  คน ขณะรถนำส่งถึงที่เกิดเหตุ เวลา 12.29  น. ถึงแยกอ่างทอง จอดรถติดไฟแดงและไปทางตรงเพื่อเข้าสงขลา มีรถเก๋งยี่ห้อ Yaris สีแดง ทะเบียน 2ขอ 9883 กรุงเทพมหานคร  เบรคกระทันหัน จึงทำให้รถพยาบาลเบรคแล้วหักหลบไม่พ้น จึงทำให้ด้านซ้ายของรถพยาบาลเฉี่ยวชน จึงทำการหยุดรถ และลงไปดูรถ ดูผู้โดยสารซึ่งเป็นผู้ป่วย และญาติ รวมทั้งพยาบาลนำส่ง ไม่มีผู้ได้รับบาดเจ็บ ขณะเกิดเหตุมีรถ อบต.เทพาผ่านทาง (จะไปรับผู้ป่วยที่รพ.สงขลากลับบ้าน) มาถึงจุดเกิดเหตุ จึงแจ้งให้นำผู้ป่วยจิตเวช พร้อมพยาบาลนำส่งไปส่งผู้ป่วยที่รพ.จิตเวชสงขลาราชนครินทร์แทน จากนั้นได้ไปดูคู่กรณี และได้ประสานประกันรถยนต์ ', '1.ประเมินระดับความรู้สึกตัวของผู้ป่วยและญาติ รวมทั้งพยาบาลนำส่ง และลงไปประเมินคู่กรณี\r\n2.ประเมินสภาพรถฉุกเฉินและรถยนต์คู่กรณี \r\n3.พยาบาลนำส่งรายงานหัวหน้างานหอผู้ป่วยใน 1 --->หัวหน้างานหอผู้ป่วยใน1 รายงานผู้อำนวยการทราบ \r\n4.พนักงานขับรถฉุกเฉินรายงานหัวหน้างานยานพาหนะ และรายงานหัวหน้าบริหารทราบ \r\n5.โทรแจ้งตำรวจและประกันรถยนต์ฉุกเฉินทราบ ', '3', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'ENV', NULL, 38, 1, NULL, NULL, NULL, '3', '2026-03-07', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '68095-', 'IPD');
INSERT INTO `dc_report` VALUES (13011, 69, 2, 7, 25, 'สิทะิ์ผู้ป่วยไม่เป็นปัจจุบัน', '2026-02-27', '13:00:00', '2026-03-04', '14:03:44', 'Clinic', 'ผู้ป่วย HN 120104 Admit ห้องพิเศษ ตั้งแต่วันแรก 24/2/69  D/C 27/2/69 สิทธิ์ในการรักษา เป็นสิทะิ์ UC 0-12 ปี ตรวจเช็คจากโน๊ตจนท.งานประกับ ก้็เป็นสิทธิ์เดิมจนวันที่ผู้ป่วย D/Cพยาบาลลงค่ารักษา 1200 บาทตามสิทธ์  ญาติมาแจ้งพยาบาลก่อนไปรับยากลับบ้านว่า มารดาเป็น อสม. ในเขตอำเภอเทพา', '- แนะนำให้ติดต่อเอาหลักฐานยืนยัน ที่รพ.สต. แล้วส่งพบ จนท.ศูนย์สิทธิ์ ต้องรอเวลาหลายชม. +มี คนไข้้รายใหม่ที่รอเข้าห้องพิเศษต่อจากผู้ป่วยรายนี้ด้วย\r\n-แก้ไขรายการค่าห้อง ค่าอาหารใหม่ \r\n\r\nข้อเสนอแนะ ....จนท.ศูนย์สิทธิ์ควรมีการตรวจสอบสิทธิ์ผู้ป่วยให้เป็นปัจจุบันทุกวัน โดยเฉพาะคนไข้ที่นอนห้องพิเศษ เพื่อจะได้ไม่ต้องเพิ่มภาระงานในการแก้ไขค่ารักษาสำหรับพยาบาลค่ะ\r\n\r\n', 'C', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 24, 3, NULL, NULL, NULL, 'C', '2026-03-07', NULL, NULL, 'Y', NULL, '3900600258269', 'admin1', NULL, NULL, NULL, '71070-', 'IPD');
INSERT INTO `dc_report` VALUES (13012, 69, 2, 7, 7, 'pt หนีออกจากโรงพยาบาล', '2026-03-01', '18:30:00', '2026-03-04', '20:20:20', 'Clinic-Dx', 'หญิงไทย อายุ 40 ปี HN000063586  Admit 26/2/69 G8P5A2 GA 10+6  wk\r\ncase drug overdose with pregnancy admit รพ.เทพา 22-25 กุมภาพันธ์ 2569 ขณะ admit  24/2/2569\r\nประเมินสุขภาพจิต\r\n2Q= 2 คะแนน\r\n9Q= 19 คะแนน (มีภาวะซึมเศร้าระดับรุนแรง)\r\n8Q= 40 คะแนน (มีแยวโน้มการฆ่าตัวตายระดับรุนแรง)\r\nทีม OSCC และทีมครรภ์เสี่ยง ---ประเมินความพร้อมในการตั้งครรภ์และความพร้อมในการเลี้ยงดูร่วมกับผู้ป่วยและสามี ให้ข้อมูล สรุปคือ ไม่สมารถตั้งครรภ์ต่อได้และไม่พร้อมเลี้ยงดูบุตร ตัดสินใจจะยุติการตั้งครรภ์ \r\nได้ประสาน รพ.สงขลา คลีนิค นรีเวช เพื่อยุติการตั้งครรภ์ และสง่ต่อเมื่อวันที่ 25/2/2569 พ.ได้ให้กินยา MA 1 tab at 15.30 น. 25/2/2569 และให้ยาเหน็บช่องคลอด 4 เม็ด ให้มาเหน็บเองที่บ้าน\r\nRx.SKH\r\n-Medabon เหน็บช่องคลอด  1 tab ทุก 15 นาที จนครบ 4 เม็ด เริ่ม 26/2/2569 \r\n-Quetiapine 200 mg ครั้งละ ครึ่งเม็ด ก่อนนอน ถ้าง่วงเดิน ลดเหลือ 1/4 เม็ด\r\n-lorazepam 1 mg ครั้งละ 1 เม็ดก่อน เมื่อมีอาการนอนไม่หลับ\r\n- Fluoxetine 20 mg ครั้งละ ครึ่งเม็ด หลังอาหารเช้า 6 วัน หลังจากนั้น ครั้งละ 1 เม็ด\r\nทีมOSCC และะทีมครรภ์เสี่ยงโทรติดตามอาการผู้ป่วย แนะนำให้มานอนรพ.เพื่อ Obs.Bleed ติดตามอาการซึมเศร้า เฝ้าระวังการฆ่าตัวตาย\r\nวันที่ 2/3/69 มีนัดทำ TR ที่ รพ นาทวี 11.00น\r\nวันที่ 1/3/69 เวลาประมาณ 17.00 ทำการเดินรวนผู้ป่วยเเจ้งกับผู้ป่วยว่าพรุงนี้ ทำหมันที่ รพ นาทวี เวลา 11.00 น หลัง้ที่ยงคืนให้งดน้ำงดอาหาร และมาใส่น้ำเกลือให้ ผู้ป่วยพยักหน้ารับทราบ\r\nประมาณ 18.30 ญาตเตียงใกล้ๆแจ้งว่ายคนไข้ออกไปข้างนอกกับแฟน เปลี่ยนเสื้อผ้าและเก็บของใช้ส่วนตัว \r\nจึงติดต่อโทรศัพท์ไปหาคนไข้ ไม่ติด(คล้ายโทรศัพท์ปิดเครื่อง)โทรไปหาแฟนหนุ่มไม่รับสาย\r\nติดต่อสอบถาม รปภ >>แจ้งว่าไม่พบคนไข้เวลาดังกล่าว\r\nเดินไปสำรวจบริเวณเซเว่นใน รพ ไม่มี,ศาลาบริเซนหน้า รพ ก็ไม่พบคนไข้\r\nประสานติดต่อ ผอ รพสต ท่าไทร หมู่7และทีมผู้ใหญ่บ้าน <<แจ้งว่าคนไข้กับแฟนไม่ได้กลับไปที่บ้านท่าไทร\r\nโทรแจ้ง ผอ เดชา แซ่หลี รับทราบ\r\nโทรแจ้งหัวหน้สวอด 2 รับทราบให้ทำตาม line\r\nติดต่อประสานขอรถ+พขร ไปสถานีตำรวจเทพา>> ลงบันทึกประจำวันกับตำรวจเรียบร้อย\r\n', 'ดูแลจัด คนไข้ให้อยู่ใกล้ชิดกับเคารเตอร์พยาบาลมากที่สุด\r\n', 'D', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 114, 5, NULL, NULL, NULL, 'D', '2026-03-07', NULL, NULL, 'Y', NULL, '1900500095507', 'admin1', NULL, NULL, NULL, '73979-', 'IPD');
INSERT INTO `dc_report` VALUES (13013, 69, 1, 29, 41, 'ให้บริการล่าช้า', '2026-02-27', '13:20:00', '2026-03-05', '08:39:32', 'Non_Clinic', 'จากแบบฟอร์มแสดงความคิดเห็นการมารับบริการโรงพยาบาลเทพา เมื่อวันที่ 27/2/2569 ญาติผู้ป่วยได้ตอบแบบสอบถามแสดงความคิดเห็นว่า มีคนไข้เยอะ เจ้าหน้าที่ไม่เพียงพอ', 'แจ้งหน่วยงานที่เกี่ยวข้องรับทราบ', '1', '03-2026', 'P', 1, 0, 0, 0, 4, NULL, 'PCT', NULL, 116, 5, NULL, NULL, NULL, '1', '2026-03-15', NULL, NULL, 'Y', NULL, '1959900643089', 'admin1', NULL, NULL, NULL, '93210-แบบแสดงความคิดเห็น.pdf', 'OPD');
INSERT INTO `dc_report` VALUES (13014, 69, 2, 37, 38, 'สั่งและจ่ายยากลุ่ม CCB ซ้ำ', '2026-03-05', '13:29:00', '2026-03-05', '13:29:02', 'Clinic', 'ผป.มา admit 5/3/69 เมื่อทำ MR พบว่า D/C ครั้งก่อน (17/2/69) ได้รับ Amlodipine และ Manidipine กลับบ้าน เมื่อย้อนกลับไปดูโปรไฟล์ พบว่า ได้ซ้ำตั้งแต่นอนรพ. โดนตอนแรกรับได้แค่ Amlodipine หลังจากนั้น แพทย์สั่ง manidipine เพิ่ม วันที่13/2/69 จึงได้พร้อมกันตั้งแต่นั้นมา จนถึงวันนี้ (5/3/69)', 'ตอนนอนรพ.แพทย์ hold Amlodipine แล้ว เขียนโน้ตในโปรโฟล์ห้องยา ตอน D/C หากแพทย์สั่งซ้ำ ให้ consult', 'D', '03-2026', 'P', 1, 1, 0, 0, 1, 'U5', 'PTC', 'U5', 123, 6, 46, 172, 302, 'D', '2026-03-15', '2026-03-20', '', 'Y', 'PTC ', '1969900313984', 'PTC ', '', '', 'open', '43812-', 'IPD');
