INSERT INTO `dc_report` VALUES (13016, 69, 2, 7, 7, 'เสียชีวิตอย่างสงบ (NR)', '2026-03-05', '13:46:00', '2026-03-06', '08:17:32', 'Clinic-Dx', 'ผู้ป่วยหญิงไทย อายุ80 ปี HN 00002609 U/D: Severe AS/MR,HFeEF,HT,Thalassemia \r\nAdmit วันที่3/3/2569 ด้วย CHF มีปัญหาเรื่องเหนื่อย On O2 mask with bag +พ่นยา ผู้ป่วยและญาติ Full NR ขอรักษาแบบประคับประคอง วันที่5/03/2569 เวลา 13.46 น.มีปัญหาซึมลง กระสับกระส่าย วัดBP ไม่ได้ คลำPulse ไม่ได้ EKG: asystole ฟังHeart no sound ', 'รายงานแพทย์รับทราบ\r\nให้ข้อมูลญาติ ญาติ Accept \r\ncare dead', 'A', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 118, 5, NULL, NULL, NULL, 'I', '2026-03-15', NULL, NULL, 'Y', NULL, '1930200082787', 'admin1', NULL, NULL, NULL, '83046-', 'IPD');
INSERT INTO `dc_report` VALUES (13017, 69, 2, 37, 37, 'ผู้ป่วยจิตเวชห้องเบอร์ 17 กินยาน้ำบนรถยา IPD1 หน้าห้องยาผู้ป่วยใน', '2026-03-06', '08:20:00', '2026-03-06', '08:29:33', 'Clinic', 'ผู้ป่วยจิตเวชระหว่างนั่งรอหน้าห้องเบอร์ 17 และได้มากินยาน้ำบนรถยา IPD1 หน้าห้องยาผู้ป่วยใน แต่ไม่แน่ใจว่าเป็นยาน้ำอะไร คาดว่า GG syr หรือ Morphine Syr', 'ถามญาติผู้ป่วยว่ากินขวดไหน ญาติตอบว่ากิน GG syr ซึ่งเหลือ 10 cc แต่ Morphine Syr หมดแกล้ง', 'C', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 119, 5, NULL, NULL, NULL, 'C', '2026-03-15', NULL, NULL, 'Y', NULL, '1909801036711', 'admin1', NULL, NULL, NULL, '79131-49469.jpg', 'IPD');
INSERT INTO `dc_report` VALUES (13018, 69, 2, 24, 3, 'คีย์รายการเอกเรย์คอมพิวเตอร์แต่ไม่ได้ทำและเก็บค่ารักษาคนไข้', '2026-03-06', '13:15:00', '2026-03-06', '14:04:37', 'Clinic', 'คนไข้ HN 000180447 Mr.YAN NAING LIN  พม่า  Admit 2/3-69-5/3/69 และจำหน่ายออกจากโรงพยาบาล  สิทธิชำระเงินเอง ค่าใช้จ่ายตลอดการรักษา 22,720.50 บาท คนไข้ชำระเงินเองจนครบ ตั้งแต่วันที่ 5/3/69 จนกระทั่งวันที่ 6/3/69 ได้ให้ล่าม มาติดต่อสอบถามเรื่องค่าใช้จ่ายให้อธิบายชี้แจงยอดต่างๆ เนื่องจากมีราคาสูง ห้องบัตรจึงได้แนะนำในส่วนของรายการ ค่าตรวจวินิจฉัยและรักษาทางรังสีวิทยา 18,200 บ. แต่คนไข้แจ้งว่าก่อนทำเอกเรย์คอมพิวเตอร์ ได้จ่ายเงินแล้ว 8000 กว่าบาท แต่ทำไม ยอดเงินสูง ', 'ให้คนไข้นั่งรอสักครู่ ศูนย์สิทธิได้ตรวจสอบในระบบพบว่ามีรายการ CT Scan 2 รายการ จึงได้ตรวจสอบกับห้องเอกเรย์ พบว่ามีรายการ CT Scan เพียง 1 รายการ และได้ทำการประสานกับห้องการเงิน เพื่อคืนเงินคนไข้', 'C', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 25, 3, NULL, NULL, NULL, 'C', '2026-03-15', NULL, NULL, 'Y', NULL, '1900500108471', 'admin1', NULL, NULL, NULL, '43698-ค่ารักษา-เคส-พม่า-6-3-69.docx', 'IPD');
INSERT INTO `dc_report` VALUES (13019, 69, 2, 3, 44, 'ผู้ป่วยไม่พึงพอใจรอรับบริการนาน', '2026-03-08', '15:48:00', '2026-03-08', '15:48:04', 'Non_Clinic', 'HN.48993 case Acute left basal GG hemorrhage รักษาต่อเนื่องที่ รพ.สงขลา \r\nเข้ารับการรักษาคลินิกนายแพทย์ณัฐพันธุ์  ควบคู่ไปด้วย แพทย์ให้ฉีดยาต่อเนื่อง 14 วัน คือ ยา cerebrolysin  30 ml + NSS 100 ml IV drip OD * 14 วัน visit opd at 14.17น.แพทย์เวรตรวจ  opd ส่งมาฉีดยา ER \r\n- ยื่นบัตรเวลา at ER14.45น.ให้นั่งรอเรียกหน้า ER ขณะนั้น ER มี Case AOC plan on ETT ,Case bradycardia plan on Transcutaneous pacing ,Case UGIB plan refer ,Case อุบัติเหตุจราจร 2 case \r\n- at 15.35น.ผู้ป่วยและญาติมาติดต่อในห้องฉุกเฉิน ไม่พอใจที่รอรับบริการนาน ยังไม่เรียก  พูดเสียงดัง พยบ.ให้ข้อมูลว่ากำลังให้บริการ Case ฉุกเฉินอยู่ แต่ก็ยังไม่พอใจ ยังพูดเสียงดัง ', 'หัวหน้าเวรจึงให้พยบ.ในเวรฉีดยาให้ผู้ป่วยก่อน ', '3', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 120, 5, NULL, NULL, NULL, '3', '2026-03-15', NULL, NULL, 'Y', NULL, '1900400008041', 'admin1', NULL, NULL, NULL, '17287-', 'OPD');
INSERT INTO `dc_report` VALUES (13020, 69, 1, 24, 3, 'ไม่ลงค่ารถrefer ส่วนต่าง', '2026-03-08', '22:30:00', '2026-03-09', '08:28:59', 'Non_Clinic', 'วันที่8/3/69 คนไข้อุบัติเหตุจากรถ สิทธประกันสังคม โงพยาบาลหาดใหญ่ พยาบาลไม่ลงรถ refer ส่วนต่าง ที่คนไข้ต้องจ่ายก่อนที่จะส่งตัวไป โรงพยาบาลหาดใหญ่', 'ได้แจ้งพยาบาล ER ให้ลงค่ารถrefer ส่วนต่างแล้วเมื่อ 8/3/69 พยาบาลได้ เพิ่มค่ารถ 9/3/69 และพยาบาลได้โทรแจ้งญาติให้มาจ่ายค่ารถส่วนต่าง', '4', '03-2026', 'P', 1, 0, 0, 0, 4, NULL, 'IM', NULL, 26, 3, NULL, NULL, NULL, '2', '2026-03-15', NULL, NULL, 'Y', NULL, '1900500080798', 'admin1', NULL, NULL, NULL, '85393-', 'OPD');
INSERT INTO `dc_report` VALUES (13021, 69, 2, 3, 2, 'ประเมินความเร่งด่วนผู้ป่วยผิดพลาด', '2026-03-09', '13:57:00', '2026-03-11', '08:44:43', 'Clinic-Dx', '9/3/69 HN.159843 visit OPD 13.57 น. \r\nส่งมา er เวลา 15.15 น. ---> case AF c RVR HR 162 bpm.  จาก opd ส่งมาทำหัตถการ ยาฉีด amiodarone  drip + repeat EKG ให้ญาติเข็นผู้ป่วยมาเองกับรถเข็นนั่งพร้อมเบิกยาจากห้องยา  ไม่มีพยาบาลนำส่ง ถึง er ผู้ป่วยรู้สึกตัวดี ใจสั่น เหนื่อยๆ EKG HR 172 bpm. ---> AF c RVR --->พ. er ดูอาการ ---> off order ยาจาก opd ทั้งหมด  ---> แก้ไขอาการตาม algolithym  tachycardia ---> amiodarone drip + synz. cardiovertion ----> refer ', 'แก้ไขอาการตาม algolithym  tachycardia ---> amiodarone drip + synz. cardiovertion ----> refer ', 'F', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 121, 5, NULL, NULL, NULL, 'E', '2026-03-15', NULL, NULL, 'Y', NULL, '3900500052758', 'admin1', NULL, NULL, NULL, '53326-', 'OPD');
INSERT INTO `dc_report` VALUES (13022, 69, 1, 3, 42, 'ศูนย์ CT รันคิว ไม่มีเหมาะสม', '2026-03-11', '08:20:00', '2026-03-11', '08:43:14', 'Clinic', 'at 8.10 น. HN 61703 R/O appendic\r\nโทรประสานห้อง CT มีเคส Emer จาก ER ผู้ป่วยครบ NPO 9.00 น.  \r\nโทรประสาน CT เพื่อไป CT   บุคคลากร บอกว่าขอรันคิวเป็นเวลา 10.00 น. เนื่องจาก มีคิวจาก OPD มาตามนัด CT    ', ': โทรประสาน CT รันคิวใหม่อีกรอบ เนื่องจาก ER เป็นเคส ด่วนกว่า', 'B', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 122, 5, NULL, NULL, NULL, 'B', '2026-03-15', NULL, NULL, 'Y', NULL, '1900501136266', 'admin1', NULL, NULL, NULL, '17964-', 'OPD');
INSERT INTO `dc_report` VALUES (13023, 69, 2, 3, 2, 'ไม่แจ้งว่าผู้ป่วยเป็น case TB', '2026-03-11', '11:40:00', '2026-03-11', '11:44:53', 'Clinic', 'ผุ้ป่วย  HN 80044  ส่งมาจาก OPD  มาOn Iv + รอผล lab \r\nหลังจากนั้น ส่งญาติกลับไปฟังผล Lab แพทย์ order เพิิ่ม CXR plan admit\r\nซึ่งแพทย์ DX. TB    พยาบาลโทรประสานเป็น case admit รอเตียง แต่ไม่แจ้งว่าเป็น case TB\r\nซึ่งผู้ป่วยนอน Obs. อยู่ใน ER  โดยยังไม่เข้าห้องแยก ซึ่งเสี่ยงต่อผู้ป่วยท่านอื่น และบุคคลากรใน ER', ': ย้ายผู้ป่วยเข้าห้องแยกระหว่างรอเตียง\r\n: โทประสานพยาบาล OPD รับทราบ', 'D', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 123, 5, NULL, NULL, NULL, 'D', '2026-03-15', NULL, NULL, 'Y', NULL, '1900501136266', 'admin1', NULL, NULL, NULL, '97412-', 'OPD');
INSERT INTO `dc_report` VALUES (13024, 69, 2, 40, 51, 'ผู้ป่วย burn จากแผ่นร้อน', '2026-03-11', '13:30:00', '2026-03-11', '17:43:20', 'Clinic-Dx', 'ผู้ป่วย IPD เคส stroke มีอาการอ่อนแรงของใบหน้ข้างขวา มารักษาทำกายภาพเป็นครั้งที่ 2 โดยการวางแผ่นร้อนที่บริเวณใบหน้า 15 นาที และกระตุ้นไฟเพิ่มความแข็งแรงของกล้ามเนื้อใบหน้าอีก 15 นาที ซึ่งขณะวางแผ่นร้อนผู้ป่วยมีอาการร้อนแสบแต่ไม่ได้แจ้งเจ้าหน้าที่ หลังจากผู้ป่วยกลับไปพักฟื้นที่ ward เกิดแผลผุผองที่บริเวณใบหน้า ญาติจึงไปแจ้งพยาบาล พยาบาลจึงโทรมาแจ้งแผนกกายภาพ นักกายภาพจึงเจ้าไปประเมินอาการทันที ', '-ประเมินแผลผู้ป่วย พบว่ามีอาการแดงและแผลผุผองที่บริเวณใบหน้า จึงนำแผ่นประคบเย็นไปประคบบริเวณใบหน้าเพื่อลดอาการอีกเสบ และให้คำแนะนำแก่ผู้ป่วยและญาติ\r\n-ทบทวนแนวทางเพื่อป้องกันการเกิดเหตุการณ์ซ้ำ', 'E', '03-2026', 'P', 1, 0, 0, 0, 7, NULL, 'PCT', NULL, 124, 5, NULL, NULL, NULL, 'E', '2026-03-15', NULL, NULL, 'Y', NULL, '1950600208214', 'admin1', NULL, NULL, NULL, '11760-', 'IPD');
INSERT INTO `dc_report` VALUES (13025, 69, 2, 7, 40, 'ผู้ป่วยได้รับบาดเจ็บจากการทำหัตถการ hot pack', '2026-03-11', '14:58:00', '2026-03-12', '08:27:28', 'Clinic', 'ผู้ป่วยหญิง อายุ 60 ปี HN 27885 DX. dizziness c recent stroke NF \r\nส่งทำกายภาพ วันที่11/3/69 at 13.15 น. \r\nกลับจากกายภาพ at 14.58 น. pt good concious มีรอยburn แดง บ่นแสบร้อน บริเวณโหนกแก้มขวา pt และญาติไม่พอใจ \r\n', '- โทรประสานกายภาพรับทราบเคส ขึ้นมาประเมินPT\r\n- รายงานแพทย์รับทราบ มีRX : ทาเจลว่านหางจระเข้ บริเวณรอย burn PRN ', 'E', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 125, 5, NULL, NULL, NULL, 'E', '2026-03-15', NULL, NULL, 'Y', NULL, '1969900200098', 'admin1', NULL, NULL, NULL, '55692-พ1.jpg', 'IPD');
INSERT INTO `dc_report` VALUES (13026, 69, 2, 29, 3, 'การสื่อสารในการให้บริการกับผู้รับบริการ', '2026-02-28', '03:00:00', '2026-03-12', '09:21:35', 'Non_Clinic', 'จากแบบแสดงความคิดเห็น ระบุว่า \"เมื่อตอนตี3ของวันที่28 พาหลาน5ขวบซึ่งอาเจียน ตั้งแต่สี่ทุ่มจนถึงตีสาม และกลัวว่าเด็กจะมีอาการเพลีย\r\nเด็กอาเจียนตลอดไม่หยุดเลยจึงตัดสินใจไปโรงพยาบาลตอนตีสาม หมอก็จัดการฉีดยาแก้อาเจียนให้และให้กลับบ้านได้ ก่อนกลับต้องชำระ ก่อนกลับต้องชำระเงิน 100 บาทเงิน100บาท ทางเจ้าหน้าที่แจ้งว่าไม่ใช่เหตุฉุกเฉินที่ควรจะมาตอนนี้รอถึงตอนเช้าก็ได้ โดยส่วนตัวเงิน 100 บาทสามารถจ่ายได้แต่ไม่ชอบลักษณะการพูดที่บอกว่าไม่ฉุกเฉินมาตอนเช้าก็ได้ซึ่งเด็กเริ่มเพลียมากแล้วไม่ได้นอนและอาเจียนไม่หยุดตลอดเวลาทำให้รู้สึกเหมือนว่าทำไมเราไม่รอให้เช้าก่อนถึงจะมา ทั้งทั้งที่ตอนตัดสินใจมาก็รู้สึกว่าเด็กไม่ไหวแล้ว ไม่ได้นอนและอาเจียนตลอด จึงเห็นว่าไม่ควรจะต้องบอกว่านี่คือเรื่องไม่ฉุกเฉินแล้วมาเก็บเงินถ้าอยากจะเก็บก็เก็บไปเลยไม่ได้ว่าอะไร สุดท้ายก็ต้องไปรักษารพ.อื่นที่มีแพทย์เฉพาะทางซึ่งถ้าไม่ใช่ตอนตี3คงไม่ไปรพเทพาอยู่แล้ว\"', 'แจ้งผู้เกี่ยวข้องรับทราบและดำเนินการแก้ไขแล้ว', '1', '03-2026', 'P', 1, 0, 0, 0, 4, NULL, 'RM', NULL, 38, 8, NULL, NULL, NULL, '1', '2026-03-15', NULL, NULL, 'Y', NULL, '1959900643089', 'admin1', NULL, NULL, NULL, '79024-ภาพ.rar', 'OPD');
INSERT INTO `dc_report` VALUES (13027, 69, 1, 7, 2, 'ไม่ปั้มแพ้ยา ในใบ admit', '2026-03-05', '22:10:00', '2026-03-12', '15:10:01', 'Clinic', 'ผู้ป่วยหญิงอายุ 59 ปี admit จาก OPD DX : Osteomyelitis มีประวัติแพ้ยา dicloxa แต่ในชาร์ท ที่ admit ไม่ได้ปั้มแพ้ยา', 'พยาบาลที่วอร์ดจึงปั้มใน Order และ ใบ mar พร้อมติดป้ายแพ้ยาหน้าชาร์ท', 'B', '03-2026', 'P', 1, 1, 0, 0, 4, 'OPD', 'PTC', 'OPD', 124, 6, 114, 615, 598, 'B', '2026-03-15', '2026-03-20', '', 'Y', 'PTC ', '1910300006284', 'PTC ', '', '', '', '54763-', 'IPD');
INSERT INTO `dc_report` VALUES (13028, 69, 2, 7, 3, 'ให้สารน้ำด้านที่ผู้ป่วยอ่อนแรง', '2026-03-05', '13:20:00', '2026-03-12', '15:16:43', 'Clinic', 'ผู้ป่วยหญิงอายุ 82 ปี  HN 100147 DX : Stroke non fast มีอาการอ่อนแรงแขน+-ขา ซีกซ้าย แพทย์มีแผนการรักษาให้สารน้ำแก่ผู้ป่วย  ER ย้ายผู้ป่วยมาที่วอร์ด ให้สารน้ำผู้ป่วยบริเวณแขนด้านซ้าย เมื่ิอพยาบาลที่วอร์ดไปรับผู้ป่วยปรากฎว่า IV cloth แล้ว (on iv บริเวณหลังมือผู้ป่วย) ซึ่งพยาบาลที่วอร์ดประเมินแล้วสามารถเปิดเส้นให้สารน้ำบริเวณ Forarm ได้', '- off iv\r\n-เปิดเส้นให้สารน้ำใหม่บริเวณ Forarm แขนขวา', 'D', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 126, 5, NULL, NULL, NULL, 'D', '2026-03-15', NULL, NULL, 'Y', NULL, '1910300006284', 'admin1', NULL, NULL, NULL, '77972-', 'IPD');
