INSERT INTO `dc_report` VALUES (13030, 69, 2, 7, 3, 'ไม่ได้เปลี่ยนเสื้อให้ผู้ป่วยก่อนย้ายเข้าวอร์ด', '2026-03-13', '14:28:00', '2026-03-13', '14:26:34', 'Clinic', 'ผู้ป่วยหญิง อายุ 61 ปี HN 108207 DX: pneumonia  on o2 canular 3 LPM on iv+ATB  (2 เส้น ) ย้ายเข้าวอร์ดโดยไม่ได้เปลี่ยนเสื้อผ้า  พนักงานเปลที่ย้ายผู้ป่วยบอกที่ ER ไม่มีผู้ป่วยแล้ว', 'ช่วยผู้ป่วยเปลี่ยนเสื้อผ้าซึ่งค่อนข้างลำบากเนื่องจากมี IV 2 เส้น สุ่มเสี่ยที่ IV จะหลุดได้', 'B', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 128, 5, NULL, NULL, NULL, 'B', '2026-03-15', NULL, NULL, 'Y', NULL, '1910300006284', 'admin1', NULL, NULL, NULL, '76075-', 'IPD');
INSERT INTO `dc_report` VALUES (13031, 69, 2, 7, 3, 'ไม่เปลี่ยนชุด รพ.ก่อน on iv + ก่อนย้ายเข้าวอร์ด', '2026-03-12', '15:36:00', '2026-03-13', '14:34:31', 'Clinic', 'ผู้ป่วยหญิงอายุ 77 ปี HN 21591 DX: Brady  cardia ย้ายผู้ป่วยที่ on iv เข้าวอร์ดโดยไม่ได้เปลี่ยนเสื้อผ้าให้ผู้ป่วย', 'ช่วยผู้ป่วยเปลี่ยนเสื้อผ้า  สุ่มเสี่ยงที่ iv จะหลุดได้', 'B', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 129, 5, NULL, NULL, NULL, 'B', '2026-03-15', NULL, NULL, 'Y', NULL, '1910300006284', 'admin1', NULL, NULL, NULL, '43050-', 'IPD');
INSERT INTO `dc_report` VALUES (13032, 69, 2, 7, 7, 'ไม่สามารถเข้าระบบ HOS XP  ได้เนื่องจากไฟตก', '2026-03-13', '19:30:00', '2026-03-13', '20:13:08', 'Non_Clinic', 'วันที่ 13/03/2569 at 17.30 น  ไฟตก 2 รอบ \r\nไม่ได้เข้าไป test ระบบ  HOS XP ว่าใช้งานได้หรือไม่\r\nat 19.30 น. พยาบาลจะเข้ารบบ  HOS XP เพื่อเข้าไปคีย์รับเลือดให้ผู้ป่วย แต่ไม่สามารถเข้าระบบHOS XP ได้ (คอมพิวเตอร์ทุกตัวในตึกเข้าระบบ HOS XP ไม่ได้ )\r\nจึงโทรสอบถามหน่วยงานอื่นๆปรากฎว่าระบบ HOS XP ใช้ได้ ', '- โทรประสานเจ้าหน้าที่ IT รับทราบเพื่อหาแนวทางแก้ไข\r\n- โทรรายงานหัวหน้างานรับทราบ\r\n- มีเจ้าหน้าที่จากห้องบัตรมาช่วยแก้ไขระบบให้ \r\n- HOS XP กลับมาใช้งานได้ตามปกติ at 20.00 น.', '2', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 27, 3, NULL, NULL, NULL, '2', '2026-03-15', NULL, NULL, 'Y', NULL, '1969900200098', 'admin1', NULL, NULL, NULL, '69451-', 'IPD');
INSERT INTO `dc_report` VALUES (13033, 69, 2, 37, 53, 'หน่วยไต คัดลอกยาผิด ', '2026-03-15', '15:00:00', '2026-03-15', '17:35:37', 'Clinic-Dx', '000003987 แพทย์ Nephro สั่งยา Insulin Mixtard 50-0-50  แต่ใน คอม Hos XP พิมพ์ผิดเป็น \r\n48-0-48 ', ' แก้ไขให้ถูกต้อง ', 'B', '03-2026', 'P', 1, 1, 0, 0, 1, 'PTC', 'PTC', 'PTC', 125, 6, 46, 171, 312, 'B', '2026-03-17', '2026-03-20', '', 'Y', 'PTC ', '3959900044394', 'PTC ', '', '', '', '39354-', 'OPD');
INSERT INTO `dc_report` VALUES (13034, 69, 2, 37, 38, 'แพทย์สั่ง ASA ผิด ', '2026-03-15', '15:00:00', '2026-03-15', '17:38:13', 'Clinic', 'ผู้ป่วยใน Stroke แผนการรักษา เป็น ASA(300) 1*1 pc จนครบ 14 วัน ( ครบ 19/3/69)แต่วันนี้ 15.3.69 แพทย์ สั่งผิด เป็น ASA (81) 1*1 pc ', 'consult แพทย์ ปรับ  ASA ตามแผนการรักษา  ', 'B', '03-2026', 'P', 1, 1, 0, 0, 1, 'U5', 'PTC', 'U5', 126, 6, 46, 172, 296, 'B', '2026-03-17', '2026-03-20', '', 'Y', 'PTC ', '3959900044394', 'PTC ', '', '', 'open', '79314-', 'IPD');
INSERT INTO `dc_report` VALUES (13035, 69, 1, 3, 6, 'refer back  โทรจองเตียงแล้ว แต่ยังรอเตียง ', '2026-03-15', '17:30:00', '2026-03-15', '17:39:37', 'Non_Clinic', '17.30 น. โทร admit ผู้ป่วย stroke   refer back \r\n< เวรเช้าโทรจองเตียง ไว้แล้วตั้งแต่ 11.00 น. และได้บอกแล้วว่าขอเตียงลมด้วย >\r\n แต่พอโทร admit เวรบ่ายได้แจ้งให้เตียง แต่บอกว่ารอเตียงลม 30 นาที  + รอโทรไปรับ ', 'รายงาน ', '1', '03-2026', 'P', 1, 0, 0, 0, 4, NULL, 'PCT', NULL, 130, 5, NULL, NULL, NULL, 'C', '2026-03-17', NULL, NULL, 'Y', NULL, '1900500046271', 'admin1', NULL, NULL, NULL, '42464-', 'N');
INSERT INTO `dc_report` VALUES (13036, 69, 2, 37, 3, 'คัดลอกรายการผิด จาก lorazepam (0.5) เป็น Loratadine (10) ', '2026-03-16', '21:00:00', '2026-03-16', '00:03:45', 'Clinic', 'แพทย์ สั่ง lorapam (0.5) 1 *hs แต่ คัดลอกยาผิด เป็น loratadine (10) 1*hs\r\nตรวจสอบพบว่า จ่ายยาถูก ฉลากถูก ( ฉลากเขียนเองไม่ได้พิมพ์จากคอม)', 'แก้ไข ใน Hos ให้ถุกต้อง เป็น lorazepam (0.5) 1* hs \r\nLASA \r\n ( ตรวจสอบเวชระเบียน ER ) ', 'B', '03-2026', 'P', 1, 1, 0, 0, 6, 'ER', 'PTC', 'ER', 127, 6, 46, 171, 308, 'B', '2026-03-17', '2026-03-20', '', 'Y', 'PTC ', '3959900044394', 'PTC ', '', '', 'open', '49529-', 'OPD');
INSERT INTO `dc_report` VALUES (13037, 69, 1, 22, 40, 'คนไข้เกิดแผลที่หน้าจากการประคบความร้อน', '2026-03-11', '16:00:00', '2026-03-16', '08:34:00', 'Clinic-Dx', 'มื่อวันที่ 11 มีนาคม 2569 ที่ผ่านมา ทางช่องทางข้อความในเพจเฟซบุ๊กของโรงพยาบาลได้รับแจ้งเหตุร้องเรียนจากญาติผู้ป่วยรายหนึ่ง ซึ่งแสดงความไม่พอใจอย่างมากต่อการปฏิบัติงานของเจ้าหน้าที่กายภาพ โดยระบุว่าผู้ป่วยที่เข้ารับการรักษาในแผนกกายภาพบำบัดด้วยวิธีการประคบร้อน ได้เกิดแผลไหม้แดงบริเวณใบหน้าในระหว่างการรักษาเหตุการณ์ดังกล่าวทำให้ญาติเกิดความกังวลและรู้สึกถึงความไม่ปลอดภัยในการรับบริการ', 'ทันทีที่ได้รับทราบเรื่องในเวลา 16.30 น. ของวันเดียวกัน ทีมงานได้ดำเนินการแก้ไขปัญหาในเบื้องต้นอย่างเร่งด่วน โดยเริ่มจากการประสานงานไปยัง \"พี่อิ\" เพื่อให้เข้าไปตรวจสอบข้อเท็จจริงสถานการณ์ที่เกิดขึ้นในแผนกกายภาพบำบัดโดยทันที ในขณะเดียวกัน ทางแอดมินเพจได้ส่งข้อความตอบกลับไปยังญาติผู้ป่วยเพื่อพูดคุยและดูแลความรู้สึกเบื้องต้น ช่วยให้ทางญาติใจเย็นลงและมั่นใจว่าโรงพยาบาลไม่ได้นิ่งนอนใจ ', 'E', '03-2026', 'P', 1, 1, 0, 0, 7, 'U9', 'RM', 'U9', 39, 8, 63, 1090, 809, '3', '2026-03-17', '2026-03-17', '', 'Y', 'rm', '1900500073619', 'rm', '', '', '', '43891-', 'IPD');
INSERT INTO `dc_report` VALUES (13038, 69, 2, 40, 40, 'ผู้ป่วย  burn จากแผ่นประคบร้อน', '2026-03-11', '13:30:00', '2026-03-16', '08:36:31', 'Clinic', 'เวลา 13.00 น. ผู้ป่วย stroke อ่อนแรงกล้ามเนื้อใบหน้าขวา  admit หอผู้ป่วย 2 ลงมาทำกายภาพบำบัดที่แผนก  เริ่มต้นด้วยการ วางแผ่นประคบร้อนบริเวณใบหน้าข้างขวา เป็นเวลา 15 นาที ไม่ได้มีการให้อุปรณ์ป้องกันแก่ผู้ป่วย ผู้ป่วยเริ่มมีอาการแสบร้อนบริเวณใบหน้าทันที แต่ไม่ได้แจ้งเจ้าหน้าที่รับทราบ หลังจากทำกายภาพเสร็จผู้ป่วยมีอาการแดงบริเวณใบหน้าและมีตุ่มใสขึ้นในเวลาถัดมา และเริ่มมีอาการมากขึ้นเมื่อกลับไปยังหอผู้ป่วย    ', 'ทำการประคบเย็นและส่งปรึกษาแพทย์เพื่อเบิกยาทาให้กับผู้ป่วย ', 'E', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 131, 5, NULL, NULL, NULL, 'E', '2026-03-17', NULL, NULL, 'Y', NULL, '1901100113291', 'admin1', NULL, NULL, NULL, '21909-s__8609812.jpg', 'N');
INSERT INTO `dc_report` VALUES (13039, 69, 2, 3, 37, 'จ่ายยาผิด', '2026-03-16', '10:55:00', '2026-03-16', '10:54:59', 'Clinic', 'HN 19603 case เวียนศีรษะ จาก OPD ส่งมาฉีดยาที่ ER ระหว่างรอผล Lab\r\n ซึ่งแพทย์  order dimen 1 amp IV  ระหวา่งจะไปฉีดยาผู้ป่วย ได้ตรวจสอบยาก่อนฉีด  ซึ่งห้องยาจ่ายยา dexa 1 amp มาให้  ', ': โทรประสาน ห้องยาให้ตรวจสอบอีกครั้ง ', 'B', '03-2026', 'P', 1, 1, 0, 0, 1, 'U4', 'PTC', 'U4', 128, 6, 46, 176, 334, 'B', '2026-03-17', '2026-03-20', '', 'Y', 'PTC ', '1900501136266', 'PTC ', 'dexa inj', 'dimen  inj', 'open', '71816-s__7299074.jpg', 'OPD');
