INSERT INTO `dc_report` VALUES (13045, 69, 2, 2, 37, 'จ่ายน้ำตาลให้ผู้ป่วยไม่ถูกชื่อตามที่ระบุในสติ๊กเกอร์', '2026-03-16', '08:00:00', '2026-03-17', '10:35:25', 'Clinic', 'ผู้ป่วย HN 5939 และ HN 19534 แพทย์นัดมาคัดกรองเบาหวานต้องกินน้ำตาล 75 กรัม หลังเจาะเลือดครั้งที่ 1 พยาบาลได้สั่งน้ำตาลในระบบและให้ผู้ป่วยไปรับที่ห้องยา ซึ่งเป็นเวลาที่ไล่เลี่ยกัน แต่หลังจากได้น้ำตาลมาพบว่าผู้ป่วยได้รับน้ำตาลที่่มีสติ๊กเกอร์ชื่อสลับกัน ', '- ทบทวนออร์เดอร์ของผู้ป่วยแต่ละรายให้ตรงตามออร์เดอร์ ', 'C', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 132, 5, NULL, NULL, NULL, 'C', '2026-03-17', NULL, NULL, 'Y', NULL, '1900500049611', 'admin1', NULL, NULL, NULL, '81563-จ่ายน้ำตาลให้ไม่ถูกคน.docx', 'OPD');
