INSERT INTO `dc_report` VALUES (13047, 69, 1, 43, 47, 'ข้อเสนอแนะผู้รับบริการ', '2026-03-16', '13:00:00', '2026-03-17', '20:07:08', 'Non_Clinic', 'วันที่ 16 มีค.69 เวลาประมาณ 13.30 น.ได้รับแจ้งจากหัวหน้ากลุ่มงานประกันว่า มีผู้รับบริการเขียน ข้อเสนอแนะด้านความสะอาด รายละเอียด ดังนี้ \r\n\" ข้อเสนอแนะด้านความสะอาด\r\n1. ขอชื่นชมคณะแพทย์และพยาบาลดูแลผู้มารับบริการเป็นอย่างดี\r\n2. เก้าอี้ผู้พักคอยรอการตรวจน่าจะปรับปรุงใหม่ได้ ดูแล้วชำรุดมากไม่กล้านั่ง\r\n3. บริเวณที่พ่นยา (โซนห้องฉุกเฉิน) สกปรกมากน่าจะดีกว่านี้\r\n4. สิ่งแวดล้อมด้านนอกควรจะมีการปรับปรุงตามปฏิทินของแผนงาน/โครงการ\r\n5. ในอาคารห้องผุ้ป่วยรวมและห้องพิเศษมีฝุ่นละอองมาก\r\n** รายละเอียดดังไฟล์แนบ**', '- แจ้งผู้เกี่ยวข้องรับทราบ\r\n- รายงานความเสี่ยงในโปรแกรมรายงานความเสี่ยง\r\n', '1', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'ENV', NULL, 39, 1, NULL, NULL, NULL, '1', '2026-03-17', NULL, NULL, 'Y', NULL, '3909700096820', 'admin1', NULL, NULL, NULL, '63962-ir.jpg', 'N');
INSERT INTO `dc_report` VALUES (13048, 69, 2, 6, 3, 'ไม่ติดป้ายให้สารน้ำ และป้ายข้อมือผู้ป่วย ', '2026-03-18', '09:30:00', '2026-03-18', '11:30:25', 'Clinic', 'วันที่่ 18/3/2569  เวลา 09.30  น. รับย้ายผู้ป่วยเด็กชายไทย อายุ  1  ปี 2  เดือน HN:000178926 AN:690001447  Dx.Acute gastritis ไม่มีป้ายข้อมือระบุผู้ป่วย และไม่ได้ติดป้ายให้สารน้ำ ', '1.ตรวจสอบชื่อสกุล ผู้ป่วย วันเดือนปีเกิด ดู HN AN ใน chart ผู้ป่วยว่าตรงกันหรือไม่\r\n2.ติดป้ายข้อมือให้ผู้ป่วย ทวนสอบจากมารดาอีกครั้ง \r\n3.ดูคำสั่งแพทย์ ชนิดของสารน้ำ และจำนวน rate IV ที่แพทย์ order ', 'C', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 133, 5, NULL, NULL, NULL, 'C', '2026-03-29', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '81154-', 'IPD');
