INSERT INTO `dc_report` VALUES (13050, 69, 2, 7, 7, 'เสียชีวิตอย่างสงบ (NR)', '2026-03-20', '22:48:00', '2026-03-20', '13:54:02', 'Clinic', 'ผู้ป่วยชาย อายุ 91 ปี  HN 37343  u/d CA prostate (PC )  admit 18/3/69   Dx.  aspirate pneumonia c acute dyspnea  (์NR c palive care  )\r\n ขณะ admit มีอาการหอบเหนื่อย  on O2 mask c bag 10 LPM c MO (1:1 ) drip rate 1 ml/hr ผู้ป่วยและญาติ NR ขอรักษาแบบประคับประคอง \r\nวันที่ 20/03/2569 at 10.47 น. ผู้ป่วย E1V1M1  หน้าอกไม่กระเพื่อม   วัดสัญญาณชีพไม่ได้ คลำชีพจรไม่ได้ pupil fix . EKG show asystole\r\n\r\n', '- รายงานแพทย์เวรทราบ\r\n- แจ้งทีม paliative care\r\n- ให้ข้อมูลญาติ ญาติ accept\r\n- dead care ', 'I', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 134, 5, NULL, NULL, NULL, 'I', '2026-03-29', NULL, NULL, 'Y', NULL, '1969900200098', 'admin1', NULL, NULL, NULL, '94725-', 'IPD');
