INSERT INTO `dc_report` VALUES (13052, 69, 2, 7, 7, 'เสียชีวิตอย่างสงบ', '2026-03-21', '23:45:00', '2026-03-23', '09:12:38', 'Clinic-Dx', 'ผู้ป่วยเพศหญิง อายุ89ปี HN 8135 ผู้ป่วยAdmit วันที่ 19/03/69 ด้วยเรื่อง Pneumonia หายใจเหนื่อย on HFNC Flow 40 Fio2 0.6 ญาติปฏิเสธ ETT. ขอรักษาแบบประคับประคอง  ดูแลให้ยา Morphine 10mg.+Midazolam 5mg.+NSS up to22ml sc via syring driver 3mm/hr. ระหว่างAdmit ผู็ป่วยสงบไม่มีกระสับกระส่าย วันที่ 21/03/69 เวลา 23.30น. O2SAt เริ่ม drop O2SAt 76% on HFNC หายใจช้าลง  Adv.ญาติ รับทราบ เวลา 23.45น. ผู้ป่วยนอนพักบนเตียง คลำชีพจรไม่ได้ วัด V/S ไม่ได้ รายงานแพทย์ทราบ', '-รายงานแพทย์ทราบ\r\n-ให้ข้อมูลญาตฺิ ญาติ Accept\r\n-Care dead', 'A', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 135, 5, NULL, NULL, NULL, 'I', '2026-03-29', NULL, NULL, 'Y', NULL, '1960600168085', 'admin1', NULL, NULL, NULL, '28439-', 'IPD');
INSERT INTO `dc_report` VALUES (13053, 69, 2, 2, 2, 'ปฏิเสธ Admit ', '2026-03-24', '19:09:00', '2026-03-24', '19:09:15', 'Clinic', 'HN 93790 ประวัติมาด้วยไข้สูง ไม่ไอ ไม่มีน้ำมูก เจ็บคอ กลืนลำบาก กลืนแล้วเจ็บมากขึ้น ทานได้น้อยลง คลื่นไส้แต่ไม่อาเจียน เพลีย  CBC: wbc 14740 N 73 >> denied admit\r\nแพทย์จึง plan Cef-3 3 d + F/U', '- adv.อาการผิดปกติที่ต้องมาพบแพทย์\r\n-รายงานอุบัติการณ์\r\n', 'D', '03-2026', 'P', 1, 0, 0, 0, 10, NULL, 'PCT', NULL, 136, 5, NULL, NULL, NULL, 'D', '2026-03-29', NULL, NULL, 'Y', NULL, '1940300268548', 'admin1', NULL, NULL, NULL, '91255-', 'OPD');
INSERT INTO `dc_report` VALUES (13054, 69, 2, 6, 37, 'ยา admit ได้ไม่ครบ ', '2026-03-23', '17:00:00', '2026-03-25', '10:53:17', 'Clinic-Dx', 'วันที่ 23/3/2569  เวลา 17.00  น.  รับย้ายผู้ป่วยชาย อายุ 86  ปี  HN:000017437 AN:690001531 Dx.R/O COPD  ผล lab K=3 mmol/L  แพทย์ order KCL  elixer 30  ml O q  3 hr.*3 dose  ห้องยาไม่ได้จัดยาให้ก่อนเข้า ward ', '1.ทวนสอบ order แพทย์ \r\n2.โทรแจ้งห้องยาทราบ \r\n3. ดูแลให้ยา KCL  elixer ตามแพทย์สั่ง ', 'B', '03-2026', 'P', 1, 1, 0, 0, 1, 'U4', 'PTC', 'U4', 137, 6, 46, 176, 331, 'B', '2026-03-29', '2026-04-03', '', 'Y', 'PTC ', '1940200003259', 'PTC ', '', '', 'open', '44366-', 'IPD');
INSERT INTO `dc_report` VALUES (13055, 69, 1, 24, 20, 'ไข้โทรเข้ามาแจ้งการบริการของเจ้าที่ รักษาความปลอดภัย ', '2026-03-26', '17:00:00', '2026-03-26', '17:15:34', 'Non_Clinic', 'เวลาประมาณ 16.55 น. มีคนไข้โทรเข้ามาร้องเรียนการให้บริการ ของเจ้าที่รักษาความปลอดภัย ที่ป้อมยาม ว่าใช้คำพูดที่ไม่สุภาพ ทำให้คนไข้ไม่พึงพอใจการให้บริการ', 'ได้โทรไปแจ้งกับหัวหน้า(งานประกันฯ) ให้รับทราบแล้ว', '1', '03-2026', 'P', 1, 0, 0, 0, 4, NULL, 'HUM', NULL, 8, 4, NULL, NULL, NULL, '1', '2026-03-29', NULL, NULL, 'Y', NULL, '1900500080798', 'admin1', NULL, NULL, NULL, '88729-', 'N');
