INSERT INTO `dc_report` VALUES (13060, 69, 2, 7, 46, 'ผู้ป่วยเกิด Phlebitis Gr.4', '2026-03-26', '18:00:00', '2026-03-27', '19:13:26', 'Clinic', 'ขณะเดินตรวจดูผู้ป่วย ผู้ป่วยแจ้งว่ามีอาการปวด บวม มือขวาบริเวณที่ให้น้ำเกลือ จึงได้ตรวจสอบดูพบว่า มือขวามีอาการ บวมตึง แดง คลำอุ่น จึงoff IV   ขณะถอดเข็มออกมีหนองไหลตามรอยเข็มออกมาเล็กน้อย คลำได้เป็นไตแข็ง \r\n(  on IV 24/3/68 )', '- ประคบเย็น + วัด V/S\r\n- ให้ยาแก้ปวด\r\n- รายงานแพทย์ \r\n- รายงาน IC', 'E', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IC', NULL, 11, 7, NULL, NULL, NULL, 'E', '2026-03-29', NULL, NULL, 'Y', NULL, '1940500129860', 'admin1', NULL, NULL, NULL, '12009-', 'IPD');
INSERT INTO `dc_report` VALUES (13061, 69, 2, 7, 38, 'Pt.แพ้อาหารทะเล ทำ CTWA C CM ได้รับ Pre-med เป็น CPM 1 amp IV + Paracet(500) 1 tab PO ', '2026-03-25', '13:50:00', '2026-03-28', '13:45:52', 'Clinic', 'วันที่ 25/03/2569 เวลา 13.40 น. รับย้ายผู้ป่วย เพศ หญิง อายุ 39 ปี HN 6239 Dx. Lower Abdominal pain  U/D DLP Asthma หลังจากทำ CTWA c CM ( admit มาจาก OPD)  มีประวัติแพ้อาหารทะเล at ward ผู้ป่วยมีอาการไอเยอะ RR 22/min O2 sat 98%RA No chest retraction lung Mild wheeze BL มีคลื่นไส้ แต่ไม่อาเจียน ไม่มีผื่นขึ้นตามตัว ไม่มี Chest pain\r\n**ก่อนทำ CTWA มี Pre-Med เป็น CPM 1 amp IV + Paracet (500) 1 tab PO \r\nหากอ้างอิงตาม Guideline กรณี ทำ CT c CM ในผู้ป่วยที่มีประวัติเป็น Asthma , แพ้อาหารทะเล (แพ้สารทึบรังสี) : hydrocortisone 200 mg IV + CPM 0.25 mg/Kg IV 1 ชม. ก่อนฉีด Contrast   ', '- Notify แพทย์ที่ admit ทราบ at 13.50 มี order ให้ ฉีด Adrenaline (1:1000) 0.5 ml IM stat , Dexamethasone 8 mg IV stat then 4 mg IV q8hr  , CPM 1 amp IV stat then q8hr , Berodual (1:3) NB q15min * 3 dose then q4hr , obs. clinical anaphylaxis \r\n- รายงานหัวหน้าหอผู้ป่วยทราบ ', 'E', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 137, 5, NULL, NULL, NULL, 'E', '2026-03-29', NULL, NULL, 'Y', NULL, '1900501155244', 'admin1', NULL, NULL, NULL, '49752-s__8937477_0.jpg', 'IPD');
INSERT INTO `dc_report` VALUES (13062, 69, 2, 7, 7, 'ผู้ป่วยสะดุดล้มศีรษะกระแทกพื้น ', '2026-03-27', '04:53:00', '2026-03-29', '08:45:11', 'Clinic', '27/3/68 เวลา 4.53น. ผู้ป่วยหญิง อายุ 60 ปี HN29803 ผู้ป่วยลุกเข้าห้องน้ำ เดินสะดุดเสื่อนอนบริเวณปลายเตียง ทำให้ล้มลงศีรษะกระแทกพื้น จึงเข้าไปประเมินอาการผู้ป่วย แรกรับผู้ป่วยตื่นดี ไม่สลบ จำเหตุการณ์ได้  motor power full All สามารถลุกไปนั่งบยเตียงได้ มีศีรษะบวมโนข้างขวา 3 CM ไม่มีปวดศีรษะ ไม่มีN/V\r\nNotify แพทย์เวร', '- ประเมินอาการผู้ป่วย\r\n- ประคบเย็น\r\n- รายงานแพทย์\r\n', 'E', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 138, 5, NULL, NULL, NULL, 'E', '2026-03-29', NULL, NULL, 'Y', NULL, '1940500129860', 'admin1', NULL, NULL, NULL, '55870-', 'IPD');
INSERT INTO `dc_report` VALUES (13063, 69, 2, 43, 47, 'อุบัติเหตุรถจักรยานยนต์ชนแผงกั้นบนถนนหน้า รพ.', '2026-03-29', '20:30:00', '2026-03-29', '21:29:58', 'Non_Clinic', 'วันที่ 29 มีค 69 เวลาประมาณ 20.20 น.รถจักรยานยนต์ ชนแผงกั้นที่มีการก่อสร้างบริเวณตรงกลางถนนหน้า รพ.ทำให้มีผู้บาดเจ็บเป็นชาย 2 คน แจ้งว่ามองไม่เห็น เนื่องจากไม่มีสัญญาณไฟแจ้งเตือน', '1. รปภ.แจ้ง ER ออกรับผู้ป่วย\r\n2. รปภ.นำสัญญาณไฟบริเวณป้อมยามไปวางไว้แทนของเดิมที่ไฟสัญญาณเสีย', '3', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'ENV', NULL, 40, 1, NULL, NULL, NULL, '3', '2026-03-29', NULL, NULL, 'Y', NULL, '3909700096820', 'admin1', NULL, NULL, NULL, '65429-111.jpg', 'N');
INSERT INTO `dc_report` VALUES (13064, 69, 2, 6, 3, 'ไม่ติดป้าย IV และไม่เปลี่ยนเสื้อผ้าก่อน admit ', '2026-03-27', '23:50:00', '2026-03-30', '08:23:24', 'Clinic', 'วันที่ 27/03/2569  เวลา 23.50  น. รับย้ายจาก ER ผู้ป่วยผู้ชาย อายุ 17  ปี HN: 000183307 AN:690001622 Dx. Anaphylaxis แพทย์ order 0.9 Nss  1,000 ml V rate 80  cc/hr.  ขณะย้ายผู้ป่วยมา admit หอผู้ป่วยใน1 ไม่ติดป้าย  IV ก่อนย้ายผู้ป่วย และไม่เปลี่ยนเสื้อผ้าผู้ป่วย ', '1.ทวนสอบชื่อ-สกุลผู้ป่วย  วันเดือนปี เกิด \r\n2.ตรวจสอบ order แพทย์อีกครั้ง (order 0.9 Nss 1,000 ml V rate  80 cc /hr.)\r\n3. ติดป้าย IV ใหม่ \r\n4.ดูแลเปลี่ยนเสื้อผ้าผู้ป่วย ', 'C', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 139, 5, NULL, NULL, NULL, 'C', '2026-03-31', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '27967-', 'IPD');
