INSERT INTO `dc_report` VALUES (13067, 69, 2, 7, 7, 'เสียชีวิตอย่างสงบ (NR)', '2026-03-30', '14:25:00', '2026-03-30', '14:56:26', 'Clinic-Dx', 'ผู้ป่วยเพศหญิง อายุ93 ปี HN.63260 Admit วันที่ 20/03/069 ด้วยเรื่อง Pneumonia หายใจเหนื่อยหอบ adv. on ETT. ญาติปฏิเสธขอรักษาแบบประคับประคอง ดูแลให้on o2 HFNC support  วันที่21/03/69 ผู้ป่วยหายใจเหนื่อยเพิ่มมากขึ้น รายงานแพทย์ทราบ ดูแลให้ยาMO20mg.+buscopan80mg.+NSS up to 24ml iv rate 1ml/hr.  วันนี้ วันที่ 30/03/2569 ผู้ป่วยหายใจหอบลึก o2sat 56% RR. 16 bpm. รายงานแพทย์ทราบ ดูแลให้ยา MO30mg.+buscopan80mg.+NSS up to 22ml via syring driver  3 mm/hr  เวลา14.25น. ผู้ป่วยนอนพักบนเตียง ปลุกไม่ตื่น คลำชีพจรไม่ได้ วัดV/S ไม้ได้', 'รายงานแพทย์ทราบ\r\nAdv. ญาติทราบ ญาติ Accept\r\nCare death', 'A', '03-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 140, 5, NULL, NULL, NULL, 'I', '2026-03-31', NULL, NULL, 'Y', NULL, '1960600168085', 'admin1', NULL, NULL, NULL, '59075-', 'IPD');
