INSERT INTO `dc_report` VALUES (13082, 69, 2, 6, 2, 'ไม่ตรวจสอบการเจาะ lab ก่อนเข้า ward', '2026-03-27', '16:00:00', '2026-04-03', '14:07:41', 'Clinic', 'วันที่ 27/03/2569   เวลา 16.00 น. รับย้ายผู้ป่วยจาก OPD ผู้ป่วยเด็กผู้หญิง อายุ 1  ปี 4  เดือน HN:000178452  AN:690001686 Dx.AGE with poor oral intake ปฏิเสธโรคประจำตัว  แพทย์ order เจาะ Lab CBC ,Eletrolyte ,H/C*1 ขวด  OPD ทำเครื่องหมายถูก order CBC,Eletrolyte  ', '1.ทวนสอบ order แพทย์อีกครั้ง \r\n2.ทวนสอบพยาบาล OPD ผู้ที่แจ้งประวัติการ admit \r\n3.พยาบาล IPD 1โทรสอบถามห้อง lab ว่ามี lab ส่งตรวจหรือไม่ \r\n4.พยาบาล IPD เจาะเลือด Eletrolyte ใหม่\r\n( อยากให้พยาบาล OPD ตรวจสอบ order และดูผล lab เบื้องต้นในกรณีที่ผล lab ออกแล้วและทวนสอบ order ก่อน admit ทุกครั้ง)', 'B', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 141, 5, NULL, NULL, NULL, 'B', '2026-04-05', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '88491-', 'IPD');
INSERT INTO `dc_report` VALUES (13083, 69, 1, 35, 3, 'ไม่ติดสติ๊กเกอร์ที่กระปุกปัสสาวะ', '2026-04-05', '17:45:00', '2026-04-06', '08:01:00', 'Clinic', 'เวลา ประมาณ 17.30 น. ได้มีการมาส่ง LAB เป็นกระปุก แต่ไม่มีการติดสติกเกอร์ ดูหน้าจอมีแค่ IPD1 ที่คีย์ออเดอร์แล็ป จึงโทรไปสอบถาม IPD1 แจ้งว่า เค้ายังไม่ได้ดำเนินการส่ง จึงลองโทรไปสอบถาม ER ว่ามีส่งปัสสาวะไหม เพราะหน้าจอแล็ปไม่มีการคีย์แล็ปมา ER แจ้งว่ามี จึงได้แจ้งทาง ER ว่ายังไม่มีการติดสติกเกอร์นะคะ ทาง ER จึงได้นำสติกเกอร์มาติดพร้อมกับเขียนในแบบฟอร์มยืนยันใฃ้สิ่งส่งตรวจเดิม', 'โทรไปถามจุดบริการต่างๆ และแจ้งว่าไม่มีการติดสติกเกอร์ ทางจุดบริการ ER นำสติกเกอร์มาติดพร้อมกับเขียนในแบบฟอร์มยืนยันใฃ้สิ่งส่งตรวจเดิม', 'B', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 142, 5, NULL, NULL, NULL, 'B', '2026-04-06', NULL, NULL, 'Y', NULL, '1900501126082', 'admin1', NULL, NULL, NULL, '46646-ไม่ติดสติกเกอร์-5-4-69.jpg', 'OPD');
INSERT INTO `dc_report` VALUES (13084, 69, 1, 37, 38, 'สั่งจำนวนยาไม่ตรงวันนัด', '2026-04-08', '10:07:00', '2026-04-08', '10:07:07', 'Clinic', 'HN 21226 นัด 90 วัน ยาทุกตัวกิน 1x2 แพทย์ศิวกรสั่งยาแค่ 90 เม็ด ทำให้ต้องแก้รายการยาใหม่ทั้งหมดทำให้คนไข้ต้องรอยาอีกรอบเพื่อแก้ไขยาใหม่ทั้งหมด', 'แก้จำนวนยาใหม่ทั้งหมด', 'B', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PTC', NULL, 154, 6, NULL, NULL, NULL, 'B', '2026-04-12', NULL, NULL, 'Y', NULL, '1909800514627', 'admin1', NULL, NULL, NULL, '25681-', 'OPD');
INSERT INTO `dc_report` VALUES (13085, 69, 1, 37, 38, 'สั่งจำนวนยาไม่ตรงวันนัด', '2026-04-08', '10:19:00', '2026-04-08', '10:09:03', 'Clinic', 'HN5744 นัด 84 วัน แต่แพทย์ศิวกร สั่งยา 110 วัน\r\n(เนื่องจาก remed ไม่แก้จำนวนยา)', 'แก้ยาใหม่ทั้งหมด', 'B', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PTC', NULL, 155, 6, NULL, NULL, NULL, 'B', '2026-04-12', NULL, NULL, 'Y', NULL, '1909800514627', 'admin1', NULL, NULL, NULL, '46878-', 'OPD');
INSERT INTO `dc_report` VALUES (13086, 69, 2, 36, 24, 'visit คนไข้ผิดคน', '2026-04-08', '13:10:00', '2026-04-08', '13:39:27', 'Non_Clinic', 'เมื่อคนไข้นำใบนำทางจากห้องบัตรมาที่โตีะซักประวัติ พบว่าชื่อของผู้รับบริการที่ห้องบัตร visit มาไม่ตรงกัน ชื่อที่ visit มาเป็นผู้ชาย ส่วนผู้รับบริการเป็นผู้หญิง ชื่อไม่เหมือนกัน', 'ทวนซำ้กับผู้รับบริการ และโทรให้ห้องบัตรแก้ไขชื่อผู้รับบริการเป็นชื่อที่ถูกต้อง', '2', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 29, 3, NULL, NULL, NULL, '2', '2026-04-12', NULL, NULL, 'Y', NULL, '1900501138137', 'admin1', NULL, NULL, NULL, '90020-', 'OPD');
INSERT INTO `dc_report` VALUES (13087, 69, 2, 7, 3, 'เจาะเลือดผู้ป่วยแล้วส่ง lab ไม่ครบ', '2026-04-08', '23:00:00', '2026-04-08', '16:47:20', 'Clinic', 'ผู้ป่วยหญิง อายุ 73 ปี HN 58551 case pneumonia admit จาก ER วันที่ 7/4/69  แพทย์มีแผนการรักษาให้เจาะ LAB Trop I TFT CBC BUN CRE ELYTE  แต่พยาบาล ER ไม่ได้คีย์ lab CBC BUN CRE ELYTE  (ในใบ order ติ๊กด้วยปากกาแดงว่าทำแล้ว) มาถึงวอร์ดพยาบาลปริ้น ผล LAB แต่ไม่มี lab  CBC BUN CRE ELYTE โทรไปสอบถาม  อ้างว่ามองไม่เห็น lab ดังกล่าว  ฝากให้พยาบาลวอร์ดเจาะใหม่ให้ด้วย  เมื่อพยาบาลวอร์ดไปเจาะเลือด ผู้ป่วยไม่พึงพอใจ บอกว่าเจาะไปแล้ว 2 ครั้ง ยังต้องเจาะอีกเหรอ', '- แก้สถานการณ์โดยบอกว่าเลือดที่เจาะไปไม่พอจึงขอเจาะใหม่\r\n-อยากให้พยาบาล ER เพิ่มความละเอียดรอบคอบให้มากกว่านี้ เพราะเจอบ่อยครั้งที่เจาะ LAB หรือทำหัตรการไม่ครบแล้วอ้างว่าไม่เห็น ส่งผลให้ผู้ป่วยต้องเจ็บตัวหลายครั้ง หรือทำให้ได้รับการรักษาที่ล่าช้า ผู้ป่วยไม่พึงพอใจ', 'C', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 143, 5, NULL, NULL, NULL, 'C', '2026-04-12', NULL, NULL, 'Y', NULL, '1910300006284', 'admin1', NULL, NULL, NULL, '90622-', 'IPD');
INSERT INTO `dc_report` VALUES (13088, 69, 2, 7, 3, 'ลืมเจาะ LAB', '2026-04-08', '17:10:00', '2026-04-08', '17:09:33', 'Clinic', 'ผู้ป่วยหญิง อายุ 27 ปี Case UTI แพทย์มีคำสั่งให้เจาะ LAB CBC แต่พยาบาลไม่ได้เจาะ lab ดังกล่าว แต่ on iv มาให้', '- พยาบาลวอร์ดต้องเจาะ lab ใหม่อีกรอบ\r\n-อยากให้พยาบาล ER เพิ่มความละเอียดรอบคอบให้มากกว่านี้ เพราะเจอบ่อยครั้งที่เจาะ LAB หรือทำหัตรการไม่ครบแล้วอ้างว่าไม่เห็น ส่งผลให้ผู้ป่วยต้องเจ็บตัวหลายครั้ง หรือทำให้ได้รับการรักษาที่ล่าช้า ผู้ป่วยไม่พึงพอใจ', 'C', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 144, 5, NULL, NULL, NULL, 'C', '2026-04-12', NULL, NULL, 'Y', NULL, '1910300006284', 'admin1', NULL, NULL, NULL, '88727-', 'IPD');
INSERT INTO `dc_report` VALUES (13089, 69, 2, 7, 7, 'เสียชีวิตอย่างสงบ (NR CASE )', '2026-04-08', '18:28:00', '2026-04-08', '20:40:12', 'Clinic-Dx', 'ผู้ป่วย เพศหญิง อายุ 86 ปี HN32385  U/D DM, HT , old CVA. ปฎิเสธการ refer CPR NR Case  Admit วันที่ 23/3/69 ด้วย pneumonia status bedridden ขาดยา 7/68 มีอาการ  หายใจเหนื่อย On o2 On ATB  ญาติ NRขอรักษาเเบบประคับประคอง  Off ATB Drip Mophine syring driver  วันที่ 8//4/69 at 17:30 น.มีหายใจ Air hunger  RR 28 bpm chest retraction O2 sat 85 % On mask  PR 130 at 18:00 น. มีPR 40-80 bpm O2 sat 64 %On mask RR28 bpm at18:28 น. ญาติมาตามผู้ป่วยนอนนิ่ง ไม่หายใจ คลำ pluse ไม่ได้  วัด BP ไม่ได้  PR 0 bpm ปลายมือปลายเท้าเย็น ผู้ป่วยเสียชีวิตอย่างสงบ \r\n', 'รายงานเเพทย์เวรรับทราบ \r\nให้ข้อมูลญาติ Accept \r\ncare dead ', 'A', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 145, 5, NULL, NULL, NULL, 'I', '2026-04-12', NULL, NULL, 'Y', NULL, '1941001340990', 'admin1', NULL, NULL, NULL, '33890-', 'IPD');
INSERT INTO `dc_report` VALUES (13090, 69, 2, 3, 36, 'ผู้ป่วยจองคิวฟันในระบบไม่ได้ ', '2026-04-09', '06:06:00', '2026-04-09', '07:52:36', 'Clinic', 'เวลา 06.06 น ผู้ป่วยโทรเข้าห้องฉุกเฉินแจ้งว่า กดเข้าไปจองคิว 06.01 น  ขึ้นว่าให้จองวันถัดไป ผุ้ป่วยขอสายห้องฟัน ', 'ให้โทรในเวลาราชการ', 'A', '04-2026', 'P', 1, 0, 0, 0, 4, NULL, 'PCT', NULL, 146, 5, NULL, NULL, NULL, 'B', '2026-04-12', NULL, NULL, 'Y', NULL, '1940200154214', 'admin1', NULL, NULL, NULL, '27442-', 'OPD');
INSERT INTO `dc_report` VALUES (13091, 69, 1, 3, 36, 'ผู้สูงอายุจองทางระบบออนไลน์ไม่เป็น ', '2026-04-07', '04:30:00', '2026-04-09', '07:57:19', 'Clinic', '05.30 น ผู้สูงอายุ 2 คน มาติดต่อห้องฉุกเฉินจองคิวห้องฟันทำยังไร ทำไม่เป็น แนะนำให้ไปสแกนคิวอาร์โค้ด ผู้ป่วยบอกว่าทำไม่เป็น ', '-เจ้าหน้าที่ห้องฉุกเฉินมีเคสห้องฉุกเฉิน ไม่สามารถจองให้ได้ ', 'A', '04-2026', 'P', 1, 0, 0, 0, 4, NULL, 'PCT', NULL, 147, 5, NULL, NULL, NULL, 'B', '2026-04-12', NULL, NULL, 'Y', NULL, '1940200154214', 'admin1', NULL, NULL, NULL, '14490-', 'OPD');
INSERT INTO `dc_report` VALUES (13092, 69, 2, 6, 3, 'ไม่ได้ตรวจสอบไฟเช็คก่อน admit  ', '2026-04-03', '09:20:00', '2026-04-09', '09:08:10', 'Clinic', 'วันที่ 3/04/69   เวลา 21.20 น. Dx. Alcohol cirrhosis ,HypoMg 1.3 ,Hypo K 3  --->8 hr. ดื่มเหล้าเถื่อน 2-3 เป็ก ร่วมกับเพื่อน หลังจากนั้น มีอาการปวดท้องด้านขวา PS 5  คะแนน  มีอาการอ่อนเพลีย จึงมารพ. AWS 3 คะแนน  ขณะ admit ผู้ป่วยมีไฟเช็คติดตัว +ใบจาก+ยาสูบ', '1.ประเมินอาการและสัญญาณชีพผู้ป่วย\r\n2.ประเมิน AWS \r\n3. ตรวจสอบอาวุธ เช่น ของมีคม ไฟเช็ค \r\n4.แจ้งผู้ป่วยและญาติทราบ เรื่องไม่อนุญาตให้สูบบุหรี่ และไม่อนุญาตให้ผู้ป่วยนำไฟเช็คมาใช้ขณะ Admit (พยาบาลเก็บไฟเช็คและยาสูบให้ผู้ป่วย) ', 'A', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 148, 5, NULL, NULL, NULL, 'B', '2026-04-12', NULL, NULL, 'Y', NULL, '1940200003259', 'admin1', NULL, NULL, NULL, '46320-', 'IPD');
INSERT INTO `dc_report` VALUES (13093, 69, 1, 35, 24, 'วันเดือนปีเกิดคนไข้ไม่ถูกต้อง', '2026-04-07', '08:17:00', '2026-04-09', '09:21:39', 'Clinic', 'คนไข้มาเจาะเลือดเวลา 08.17 น. เจ้าหน้าที่ห้องแลปได้สอบถามชื่อนามสกุล และวันเดือนปีคนไข้ พร้อมกับเช็คข้อมูลในระบบ HOSxp ว่าตรงไหม ซึ่งคนไข้แจ้งว่าตัวเอง เกิดวันที่ 11 สิงหาคม 2516 แต่ในระบบ HOsxp เป็นวันที่ 11 ธันวาคม 2516 จึงขอบัตรประชาชนคนไข้เพื่อตรวจสอบข้อมูล ซึ่งข้อมูลในบัตรประชาชนกับใน HOSxp ไม่ตรงกัน จึงได้ทำการโทรแจ้งห้องบัตรเพื่อแก้ไข้ข้อมูลให้ถูกต้อง', 'เช็คข้อมูลในบัตรประชาชนกับ HosXpแล้วโทรแจ้งห้องบัตรแก้ไขข้อมูลให้ถูกต้อง พร้อมทั้งเขียนรายงานความเสี่ยง', 'A', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'IM', NULL, 30, 3, NULL, NULL, NULL, '2', '2026-04-12', NULL, NULL, 'Y', NULL, '1900501126082', 'admin1', NULL, NULL, NULL, '6362-วดป-ผิด.jpg', 'OPD');
INSERT INTO `dc_report` VALUES (13094, 69, 2, 7, 3, 'ตามรถ refer ล่าช้า', '2026-04-06', '22:20:00', '2026-04-09', '15:37:23', 'Clinic', 'ผู้ป่วยหญิง อายุ 74 HN 80541 case ADHF U/D old MI มีอาการเหนื่อย เหงื่ออกตัวชื้น กระสับกระส่าย แพทย์ใส่ tube เวลาประมาณ 8.45 น. ประสานพยาบาล ER เพื่อขอรถส่งต่อผู้ป่วยไป รพ.สงขลา เวลา 9.10 น. พขร.มารับผู้ป่วยเวลา 10.20 น. แพทย์ไม่พึงพอใจ ที่รถส่งต่อมาล่าช้า พยาบาลจึงสอบถาม พขร.ว่าทำไมถึงมาช้า พขร.บอกว่า เป็นมือที่ 3 มือที่ 1 ส่งต่อผู้ป่วยห้องคลอด มือที่ 2 ไป home ward แต่พยาบาล ER โทรตามพขร.เวลา 9.48 น.', '- รายงานอุบัติการณ์ในในระบบ', 'C', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'PCT', NULL, 149, 5, NULL, NULL, NULL, 'C', '2026-04-12', NULL, NULL, 'Y', NULL, '1910300006284', 'admin1', NULL, NULL, NULL, '53598-', 'IPD');
INSERT INTO `dc_report` VALUES (13095, 69, 1, 2, 2, 'ปฏิเสธ Admit ', '2026-04-10', '10:00:00', '2026-04-10', '15:30:42', 'Clinic', 'HN 131601 case Anaemia , Malaise and fatigue แพทย์ต้องการรับไว้รักษาในโรงพยาบาล แต่ผู้ป่วยไม่สะดวก เนื่องจากไม่มีคนเฝ้าไข้ ', '- Adv. การดูแลตัวเอง สังเกตอาการผิดปกติ ', 'D', '04-2026', 'P', 1, 0, 0, 0, 10, NULL, 'PCT', NULL, 150, 5, NULL, NULL, NULL, 'D', '2026-04-12', NULL, NULL, 'Y', NULL, '1900500049611', 'admin1', NULL, NULL, NULL, '32161-', 'OPD');
INSERT INTO `dc_report` VALUES (13096, 69, 2, 41, 32, 'งูกัดเจ้าหน้าที่', '2026-04-09', '12:30:00', '2026-04-10', '16:08:54', 'Non_Clinic', 'เจ้าหน้าที่เข้าห้องน้ำ คลินิกการแพทย์แผนไทย PCU 1 โดนงูเขียนกัดบริเวณแขน ทำให้เกิดบาดแผลบริเวณแขน ', 'ตีงู และแนะนำให้เจ้าหน้าที่ไปพบแพทย์โดยด่วน', '3', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'ENV', NULL, 42, 1, NULL, NULL, NULL, '3', '2026-04-12', NULL, NULL, 'Y', NULL, '1900501149694', 'admin1', NULL, NULL, NULL, '6558-s__69861393.jpg', 'OPD');
INSERT INTO `dc_report` VALUES (13097, 69, 2, 6, 47, 'กลิ่นควันเผาขยะในหอผู้ป่วยใน1', '2026-04-12', '19:30:00', '2026-04-12', '19:34:03', 'Non_Clinic', 'วันทึ่ 12/4/69 เวลา 19.30 น \r\nขณะเดินปฏิบัติหน้าที่ในห้องผู้ป่วยใน 1 ฝั่งชาย ได้กลิ่นควันเผาขยะ  เกิดอาการหายใจไม่ออก แสบจมูก  และญาติผู้ป่วยแจ้งว่าได้กลิ่นด้วย  แต่ยังไม่มีใครได้้รับผลกระทบ \r\nยังมีไม่มีอาการผู้ป่วยอาการหอบเพิ่ม\r\n', 'ประสานเจ้าหน้าที่รักษาความปลอดภัย ', '3', '04-2026', 'P', 1, 0, 0, 0, 1, NULL, 'ENV', NULL, 43, 1, NULL, NULL, NULL, '2', '2026-04-13', NULL, NULL, 'Y', NULL, '1900500021082', 'admin1', NULL, NULL, NULL, '44843-', 'IPD');
INSERT INTO `dc_report` VALUES (13098, 69, 1, 43, 47, 'มลภาวะทางกลิ่น', '2026-04-12', '19:57:00', '2026-04-12', '19:49:44', 'Non_Clinic', 'วันนี้เวลาประมาณ 19.30 น.ได้รับแจ้งจากน้องพยาบาลหอผู้ป่วยใน 1 ว่า ได้กลิ่นควันไฟลอยเข้ามาในตึก จนรู้สึกแสบจมูก จึงได้แจ้ง รปภ.รับทราบและมีการตรวจสอบพบว่ารอบๆ รพ.ไม่มีการเผาขยะใดๆ จึงคาดเดาว่าน่าจะเป็นควันไฟที่ลอยมาจากที่อื่น ซึ่งอาจส่งผลกระทบกับผู้ป่วยที่ admit ใน รพ.', '1. แจ้ง รปภ.ตรวจสอบพื้นที่\r\n2. แจ้ง ENV ทราบ\r\n3. รายงานความเสี่ยงในระบบ', '2', '04-2026', 'P', 1, 0, 0, 0, 4, NULL, 'ENV', NULL, 44, 1, NULL, NULL, NULL, '2', '2026-04-13', NULL, NULL, 'Y', NULL, '3909700096820', 'admin1', NULL, NULL, NULL, '79366-', 'IPD');
